import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { useResizeObserver } from '@/hooks/use-resize-observer';

export function useTemplaterBackdrop(
  containerRef: React.RefObject<HTMLDivElement | null>,
) {
  const backdropRef = useRef<HTMLDivElement>(null);
  const [field, setField] = useState<
    HTMLInputElement | HTMLTextAreaElement | null
  >(null);

  // Locate the underlying input/textarea once mounted so the resize observer
  // and listeners below can bind to the actual DOM node.
  useEffect(() => {
    const found = containerRef.current?.querySelector<
      HTMLInputElement | HTMLTextAreaElement
    >('textarea, input');
    setField(found ?? null);
  }, [containerRef]);

  // Copy font styles once — they don't change at runtime
  useEffect(() => {
    if (!field || !backdropRef.current) return;
    const backdrop = backdropRef.current;

    const computed = window.getComputedStyle(field);
    backdrop.style.fontSize = computed.fontSize;
    backdrop.style.fontFamily = computed.fontFamily;
    backdrop.style.fontWeight = computed.fontWeight;
    backdrop.style.lineHeight = computed.lineHeight;
    backdrop.style.letterSpacing = computed.letterSpacing;
    backdrop.style.wordSpacing = computed.wordSpacing;

    const isTextarea = field.tagName === 'TEXTAREA';
    backdrop.style.whiteSpace = isTextarea ? 'pre-wrap' : 'pre';
    backdrop.style.wordBreak = isTextarea ? 'break-word' : 'normal';
  }, [field]);

  const positionRaf = useRef(0);
  const syncPosition = useCallback(() => {
    const container = containerRef.current;
    const backdrop = backdropRef.current;
    if (!container || !field || !backdrop) return;

    cancelAnimationFrame(positionRaf.current);
    positionRaf.current = requestAnimationFrame(() => {
      const containerRect = container.getBoundingClientRect();
      const fieldRect = field.getBoundingClientRect();

      backdrop.style.top = `${fieldRect.top - containerRect.top}px`;
      backdrop.style.left = `${fieldRect.left - containerRect.left}px`;
      backdrop.style.width = `${fieldRect.width}px`;
      backdrop.style.height = `${fieldRect.height}px`;
      // Re-read padding — it can change when icons / states toggle
      backdrop.style.padding = window.getComputedStyle(field).padding;
    });
  }, [containerRef, field]);

  // Initial sync once the field is located; cancel any pending frame on unmount.
  useEffect(() => {
    syncPosition();
    return () => cancelAnimationFrame(positionRaf.current);
  }, [syncPosition]);

  const fieldRef = useMemo(() => ({ current: field }), [field]);

  useResizeObserver({ ref: fieldRef, onResize: syncPosition });

  // Keep the backdrop scrolled in lockstep with the field
  useEffect(() => {
    if (!field || !backdropRef.current) {
      return;
    }

    const backdrop = backdropRef.current;

    let scrollRaf = 0;

    const syncScroll = () => {
      cancelAnimationFrame(scrollRaf);
      scrollRaf = requestAnimationFrame(() => {
        backdrop.scrollTop = field.scrollTop;
        backdrop.scrollLeft = field.scrollLeft;
      });
    };

    field.addEventListener('scroll', syncScroll);

    return () => {
      cancelAnimationFrame(scrollRaf);
      field.removeEventListener('scroll', syncScroll);
    };
  }, [field]);

  return backdropRef;
}
