import { Mail01 } from '@untitledui/icons';
import { Input } from '@/components/atoms/Input/base/input';
import { WithDataId } from '@/types/withDataId';
import {
  FieldWrapper,
  FieldWrapperProps,
} from '@/components/molecules/FieldWrapper/FieldWrapper';

export type InputEmailFieldProps = Omit<
  React.ComponentPropsWithoutRef<typeof Input>,
  'icon' | 'required'
> &
  WithDataId &
  Omit<FieldWrapperProps, 'children'>;

export function InputEmailField({
  label,
  hint,
  isInvalid,
  isRequired,
  tooltip,
  description,
  id = '',
  fieldSize = 'md',
  labelPosition = 'left',
  ...props
}: InputEmailFieldProps) {
  return (
    <FieldWrapper
      id={id}
      label={label}
      hint={hint}
      isInvalid={isInvalid}
      isRequired={isRequired}
      tooltip={tooltip}
      description={description}
      fieldSize={fieldSize}
      labelPosition={labelPosition}
    >
      <Input
        {...props}
        isInvalid={isInvalid}
        type="email"
        icon={Mail01}
      />
    </FieldWrapper>
  );
}
