import { useEffect, useRef } from 'react';
import { SearchLg } from '@/icons';
import { InputField } from '@/components/atoms/Input';
import type { WithDataId } from '@/types/withDataId';

interface PopoverSearchInputProps extends WithDataId {
  value: string;
  onChange: (value: string) => void;
  placeholder?: string;
}

/**
 * Search input rendered at the top of a popover. Mirrors the
 * `ColumnsSelector` pattern (InputField + SearchLg icon, separator below).
 *
 * Focuses on mount via a deferred ref query — `autoFocus` races react-aria's
 * portal mount and Storybook's patched focus throws "Could not determine
 * window of node" if `ownerDocument.defaultView` is null at commit time.
 */
export function PopoverSearchInput({
  value,
  onChange,
  placeholder = 'Search',
  'data-id': dataId,
}: PopoverSearchInputProps) {
  const wrapperRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const id = requestAnimationFrame(() => {
      const node = wrapperRef.current?.querySelector('input');
      if (node?.ownerDocument?.defaultView) {
        node.focus();
      }
    });
    return () => cancelAnimationFrame(id);
  }, []);

  return (
    <div
      ref={wrapperRef}
      className="border-b border-secondary p-2"
      // Block only printable single-character keys from reaching the
      // surrounding AriaSelect's typeahead. Navigation keys (Escape,
      // Arrow*, Enter, Tab) must still bubble.
      onKeyDown={(e) => {
        if (e.key.length === 1) e.stopPropagation();
      }}
    >
      <InputField
        icon={SearchLg}
        value={value}
        onChange={onChange}
        placeholder={placeholder}
        className="text-sm"
        data-id={dataId}
      />
    </div>
  );
}
