import { useEffect, useMemo, useRef } from 'react';
import { Input } from '@/components/atoms/Input';
import { FieldWrapper } from '@/components/molecules/FieldWrapper';
import { InputBase, TextField } from '@/components/atoms/Input/base/input';
import { cx } from '@/utils/cx';
import { useTemplaterBackdrop } from './_hooks';
import { TemplaterMenu } from './TemplaterMenu';
import { formatTemplate, highlightTemplateVars } from './_utils';
import type { FieldTemplaterProps } from './_types';

type FieldInputTemplaterProps = Omit<
  FieldTemplaterProps<typeof Input>,
  'component' | 'menuTopPos' | 'menuRightPos'
>;

export function FieldInputTemplater({
  label,
  hint,
  isInvalid,
  isRequired,
  tooltip,
  description,
  id = '',
  fieldSize = 'md',
  labelPosition = 'left',
  templateItems,
  value = '',
  onChange,
  onBlur,
  className,
  isReadOnly,
  isDisabled,
  isFormatTemplateItems = true,
  placeholder,
  shortcut,
  'data-id': dataId,
  ...rest
}: FieldInputTemplaterProps) {
  const containerRef = useRef<HTMLDivElement>(null);
  const backdropRef = useTemplaterBackdrop(containerRef);
  const showTrigger = !isReadOnly && !isDisabled;

  const validKeywords = useMemo(
    () =>
      new Set(
        isFormatTemplateItems
          ? templateItems.map((item) => formatTemplate(item))
          : templateItems,
      ),
    [templateItems, isFormatTemplateItems],
  );

  useEffect(() => {
    if (!backdropRef.current) return;
    backdropRef.current.innerHTML = highlightTemplateVars(
      value ?? '',
      validKeywords,
    );
  }, [value, validKeywords, backdropRef]);

  const handleSelect = (item: string) => {
    const inserted = isFormatTemplateItems ? formatTemplate(item) : item;
    onChange?.(`${value ?? ''}${inserted}`);
  };

  return (
    <FieldWrapper
      id={id}
      label={label}
      hint={hint}
      isInvalid={isInvalid}
      isRequired={isRequired}
      tooltip={tooltip}
      description={description}
      fieldSize={fieldSize}
      labelPosition={labelPosition}
    >
      <div
        ref={containerRef}
        className={cx(
          'relative w-full',
          // Hide the underlying field's text so the backdrop's styled HTML
          // shows through. The caret stays visible.
          '[&_input]:!text-transparent [&_input]:caret-fg-brand-primary',
          className,
        )}
      >
        <TextField
          {...rest}
          value={value}
          onChange={onChange}
          onBlur={onBlur}
          isInvalid={isInvalid}
          isReadOnly={isReadOnly}
          isDisabled={isDisabled}
        >
          <div
            className={cx(
              // Unified rounded ring around InputBase + trigger, matching
              // InputGroup's select-mode look (input-group.tsx).
              'group relative flex h-max w-full flex-row items-stretch rounded-lg bg-primary shadow-xs ring-1 ring-primary ring-inset transition-shadow duration-100 ease-linear',
              'focus-within:ring-2 focus-within:ring-brand',
              isInvalid && 'ring-error_subtle focus-within:ring-error',
              isDisabled &&
                'cursor-not-allowed bg-disabled_subtle ring-disabled',
            )}
          >
            <InputBase
              placeholder={placeholder}
              shortcut={shortcut}
              isDisabled={isDisabled}
              wrapperClassName="!shadow-none !ring-0 !rounded-none bg-transparent group-focus-within:!ring-0"
              data-id={`${dataId}-input`}
            />

            <div className="flex shrink-0 items-center">
              <TemplaterMenu
                data-id={dataId}
                templateItems={templateItems}
                onSelect={handleSelect}
                isFormatTemplateItems={isFormatTemplateItems}
                isDisabled={!showTrigger}
                className="mr-1"
              />
            </div>
          </div>
        </TextField>

        <div
          ref={backdropRef}
          aria-hidden
          className="pointer-events-none absolute z-20 overflow-hidden text-md text-primary"
        />
      </div>
    </FieldWrapper>
  );
}
