import type { FC, ReactNode, Ref, RefAttributes } from 'react';
import React, { isValidElement, useState } from 'react';
import { ChevronDown } from '@/icons';
import { PopoverSearchInput } from './PopoverSearchInput';
import type { SelectProps as AriaSelectProps } from 'react-aria-components';
import {
  Button as AriaButton,
  ListBox as AriaListBox,
  Select as AriaSelect,
  SelectValue as AriaSelectValue,
} from 'react-aria-components';
import { Avatar } from '@/vendor/untitled-ui/base/avatar/avatar';
import { cx } from '@/utils/cx';
import { isReactComponent } from '@/utils/is-react-component';
import { ComboBox } from './BaseComboBox';
import { Popover } from './BasePopover';
import { SelectItem } from './BaseSelectItem';
import { ComponentPropsWithoutRef } from 'react';

import { type SelectItemType, type CommonProps } from './baseTypes';

export { type SelectItemType, type CommonProps };

export interface SelectProps
  extends
    Omit<AriaSelectProps<SelectItemType>, 'children' | 'items'>,
    RefAttributes<HTMLDivElement>,
    CommonProps {
  items?: SelectItemType[];
  /**
   * Fallback options for displaying selected values that may not be in `items`.
   * Useful when:
   * - Selected item is filtered out by search
   * - Options are paginated/lazy-loaded
   * - Async options haven't loaded yet
   *
   * These are NOT shown in the dropdown, only used for display.
   */
  preparedOptions?: SelectItemType[];
  popoverClassName?: string;
  placeholderIcon?: FC | ReactNode;
  children: ReactNode | ((item: SelectItemType) => ReactNode);
  /** Render a search input inside the popover and filter items as the user types. */
  searchable?: boolean;
  /**
   * UI text overrides. Single grouped object so the surface can grow without
   * adding sibling string props.
   */
  texts?: {
    /** Placeholder for the search input. Defaults to "Search". */
    searchPlaceholder?: string;
    /** Message shown when no item matches. Defaults to "No results". */
    searchNotFound?: string;
  };
  /** Remove all border, shadow, and ring styling from the select trigger. */
  noBorder?: boolean;
}

interface SelectValueProps {
  isOpen: boolean;
  isFocusVisible: boolean;
  isDisabled: boolean;
  placeholder?: string;
  ref?: Ref<HTMLButtonElement>;
  placeholderIcon?: FC | ReactNode;
  isInvalid?: boolean;
  /** Fallback selected item when filtering hides it from the collection */
  selectedItemFallback?: SelectItemType;
  /** Remove all border, shadow, and ring styling */
  noBorder?: boolean;
}

const SelectValue = ({
  isOpen,
  isFocusVisible,
  isDisabled,
  isInvalid,
  placeholder,
  placeholderIcon,
  selectedItemFallback,
  noBorder,
  ref,
}: SelectValueProps) => {
  return (
    <AriaButton
      ref={ref}
      className={cx(
        'relative flex w-full cursor-pointer items-center rounded-lg bg-primary outline-hidden transition duration-100 ease-linear',
        !noBorder && 'shadow-xs ring-1 ring-primary ring-inset',
        !noBorder && (isFocusVisible || isOpen) && 'ring-2 ring-brand',
        !noBorder && isInvalid && 'ring-error_subtle',
        isDisabled && 'cursor-not-allowed bg-disabled_subtle text-disabled',
        !placeholder && 'min-h-9',
      )}
    >
      <AriaSelectValue<SelectItemType>
        className={cx(
          'flex h-max w-full items-center justify-start gap-2 truncate text-left align-middle',
          !noBorder && 'py-2 px-3',
          // Icon styles
          '*:data-icon:size-4 *:data-icon:shrink-0 *:data-icon:text-fg-quaternary in-disabled:*:data-icon:text-fg-disabled',
        )}
      >
        {(state) => {
          // Use fallback when the selected item is filtered out of the collection
          const selectedItem = state.selectedItem ?? selectedItemFallback;
          const Icon = selectedItem?.icon || placeholderIcon;

          return (
            <>
              {selectedItem?.avatarUrl ? (
                <Avatar
                  size="xs"
                  src={selectedItem.avatarUrl}
                  alt={
                    typeof selectedItem.label === 'string'
                      ? selectedItem.label
                      : ''
                  }
                />
              ) : isReactComponent(Icon) ? (
                <Icon
                  data-icon
                  aria-hidden="true"
                />
              ) : isValidElement(Icon) ? (
                Icon
              ) : null}

              {selectedItem ? (
                <section className="flex w-full gap-2 truncate">
                  {selectedItem.renderLabel && selectedItem.renderLabel}
                  {!selectedItem.renderLabel && (
                    <>
                      <p className="truncate text-sm font-medium text-primary">
                        {selectedItem?.label}
                      </p>
                      {selectedItem?.supportingText && (
                        <p className="text-sm text-tertiary">
                          {selectedItem?.supportingText}
                        </p>
                      )}
                    </>
                  )}
                </section>
              ) : (
                <p
                  className={cx(
                    'text-sm text-placeholder',
                    isDisabled && 'text-disabled',
                  )}
                >
                  {placeholder}
                </p>
              )}

              <ChevronDown
                aria-hidden="true"
                className="ml-auto shrink-0 size-4 stroke-[2.5px] text-fg-quaternary"
              />
            </>
          );
        }}
      </AriaSelectValue>
    </AriaButton>
  );
};

function matchesSelectQuery(item: SelectItemType, query: string): boolean {
  if (!query) return true;
  const q = query.toLowerCase();
  const fields: string[] = [
    typeof item.label === 'string' ? item.label : '',
    String(item.id),
    ...(item.searchAliases ?? []).map(String),
  ];
  return fields.some((field) => field.toLowerCase().includes(q));
}

const Select = ({
  placeholder = 'Select',
  placeholderIcon,
  children,
  items,
  preparedOptions,
  label: _label,
  hint: _hint,
  tooltip: _tooltip,
  className,
  searchable,
  texts,
  value,
  noBorder,
  ...rest
}: SelectProps) => {
  const searchPlaceholder = texts?.searchPlaceholder ?? 'Search';
  const searchNotFoundLabel = texts?.searchNotFound ?? 'No results';
  const dataId = (rest as { 'data-id'?: string })['data-id'];
  const [query, setQuery] = useState('');

  // Get selected value from props (for finding fallback item)
  const selectedValue = value;

  // Find selected item from preparedOptions first, then items
  // This ensures we can display the selected value even when filtered out
  const selectedItemFallback =
    preparedOptions?.find((item) => item.id === selectedValue) ??
    items?.find((item) => item.id === selectedValue);

  const filteredItems =
    !searchable || !query.trim()
      ? items
      : (items ?? []).filter((item) => matchesSelectQuery(item, query.trim()));

  return (
    <AriaSelect
      {...rest}
      value={value}
      className={(state) =>
        cx(
          'flex flex-col gap-1.5',
          typeof className === 'function' ? className(state) : className,
        )
      }
      onOpenChange={(isOpen) => {
        if (!isOpen && query && !filteredItems?.length) {
          setQuery('');
        }
      }}
    >
      {(state) => (
        <>
          <SelectValue
            {...state}
            placeholder={placeholder}
            placeholderIcon={placeholderIcon}
            isInvalid={rest.isInvalid}
            selectedItemFallback={selectedItemFallback}
            noBorder={noBorder}
          />

          <Popover
            className={cx(
              // When searchable, override the popover's own scroll/padding
              // so the search input is a fixed header and only the listbox
              // scrolls. Mirrors the ColumnsSelector dropdown pattern.
              searchable && 'flex flex-col overflow-hidden! py-0!',
              rest.popoverClassName,
            )}
          >
            {searchable && (
              <PopoverSearchInput
                data-id={`${dataId ?? 'select'}-search`}
                value={query}
                onChange={setQuery}
                placeholder={searchPlaceholder}
              />
            )}

            <AriaListBox
              items={filteredItems}
              className={cx(
                'outline-hidden',
                searchable ? 'flex-1 overflow-y-auto' : 'size-full',
              )}
              renderEmptyState={
                searchable
                  ? () => (
                      <div
                        className="px-3 py-4 text-sm text-tertiary"
                        role="status"
                      >
                        {searchNotFoundLabel}
                      </div>
                    )
                  : undefined
              }
            >
              {children}
            </AriaListBox>
          </Popover>
        </>
      )}
    </AriaSelect>
  );
};

type ComboBoxProps = ComponentPropsWithoutRef<typeof ComboBox>;

const _Select = Select as typeof Select & {
  ComboBox: React.ComponentType<ComboBoxProps>;
  Item: typeof SelectItem;
};
_Select.ComboBox = ComboBox;
_Select.Item = SelectItem;

export { _Select as Select };
