import type { ComponentPropsWithRef } from 'react';
import { cx } from '@/utils/cx';
import { AvatarAddButton } from '@/components/atoms/Avatar';
import {
  ChannelAvatar,
  type ChannelAvatarItem,
} from '@/components/molecules/ChannelAvatar';
import { WithDataId } from '@/types/withDataId';

export interface ChannelAvatarGroupProps
  extends Omit<ComponentPropsWithRef<'div'>, 'onClick'>, WithDataId {
  /**
   * Channels to render, in order. Each item is a `ChannelAvatarItem` and may carry
   * its own `label`, `isActive`, and `onClick`.
   */
  channels: ChannelAvatarItem[];
  /**
   * Shared avatar size applied to every channel in the group.
   * @default 'md'
   */
  size?: 'xs' | 'sm' | 'md';
  /**
   * When `true`, avatars overlap (stacked, with a contrast outline).
   * When `false`, they sit in a row separated by a small gap.
   * @default false
   */
  stack?: boolean;
  /**
   * When `true`, renders an add button at the end of the group.
   * Requires `onAdd` to actually appear.
   * @default false
   */
  editable?: boolean;
  /** Callback fired when the add button is clicked. */
  onAdd?: () => void;
  /**
   * Tooltip label for the add button.
   * @default 'Add channel'
   */
  addButtonLabel?: string;
}

export function ChannelAvatarGroup({
  channels,
  size = 'md',
  stack = false,
  editable = false,
  onAdd,
  addButtonLabel,
  className,
  'data-id': dataId,
  ...props
}: ChannelAvatarGroupProps) {
  return (
    <div
      {...props}
      className={cx(
        'flex items-center',
        stack ? '-space-x-3' : 'gap-1 flex-wrap',
        className,
      )}
    >
      {channels.map(({ channel, tooltip, isActive, onClick }, index) => (
        <ChannelAvatar
          key={`${channel}-${index}`}
          size={size}
          channel={channel}
          tooltip={tooltip}
          isActive={isActive}
          onClick={onClick}
          data-id={`${dataId}-${channel}-${index}`}
        />
      ))}
      {editable && onAdd && (
        <AvatarAddButton
          className={stack ? 'ml-5' : undefined}
          size={size}
          title={addButtonLabel ?? 'Add channel'}
          onPress={onAdd}
          data-id={`${dataId}-add`}
        />
      )}
    </div>
  );
}
