import * as React from 'react';
import {
  Legend,
  PolarAngleAxis,
  PolarGrid,
  PolarRadiusAxis,
  Radar,
  RadarChart as RechartsRadarChart,
  ResponsiveContainer,
  Tooltip,
} from 'recharts';
import type { BaseTickContentProps, TooltipProps } from 'recharts';
import type {
  NameType,
  ValueType,
} from 'recharts/types/component/DefaultTooltipContent';
import { cx } from '@/utils/cx';
import type { Props as LegendProps } from 'recharts/types/component/Legend';
import type { Props as PolarAngleAxisProps } from 'recharts/types/polar/PolarAngleAxis';
import type { Props as PolarRadiusAxisProps } from 'recharts/types/polar/PolarRadiusAxis';
import type { Props as RadarProps } from 'recharts/types/polar/Radar';

/** Tooltip props with recharts generic types */
type ChartTooltipProps = TooltipProps<ValueType, NameType>;

/** Radar component props */
type ChartRadarProps = RadarProps;

/**
 * Fallback palette (utility-brand 700 → 100).
 * Classes for stroke/fill via currentColor.
 */
import {
  FALLBACK_PALETTE,
  FALLBACK_PALETTE_COLORS,
  RADAR_LABEL_OFFSET,
  RADAR_PILL_CHAR_WIDTH,
  RADAR_PILL_HEIGHT,
  RADAR_PILL_PADDING_X,
  RADAR_PILL_PADDING_Y,
  RADAR_RADIUS_AXIS_Z_INDEX,
} from '../../../../constants/charts.constants';

/**
 * Allowed legend positions.
 * Combines vertical (top/middle/bottom) and horizontal (left/center/right) alignment.
 */
export type LegendPosition =
  | 'top'
  | 'top-left'
  | 'top-right'
  | 'bottom'
  | 'bottom-left'
  | 'bottom-right'
  | 'left'
  | 'right';

const LEGEND_POSITION_MAP: Record<
  LegendPosition,
  {
    verticalAlign: 'top' | 'middle' | 'bottom';
    align: 'left' | 'center' | 'right';
    layout?: 'horizontal' | 'vertical';
  }
> = {
  top: { verticalAlign: 'top', align: 'center' },
  'top-left': { verticalAlign: 'top', align: 'left' },
  'top-right': { verticalAlign: 'top', align: 'right' },
  bottom: { verticalAlign: 'bottom', align: 'center' },
  'bottom-left': { verticalAlign: 'bottom', align: 'left' },
  'bottom-right': { verticalAlign: 'bottom', align: 'right' },
  left: { verticalAlign: 'middle', align: 'left', layout: 'vertical' },
  right: { verticalAlign: 'middle', align: 'right', layout: 'vertical' },
};

/**
 * Configuration for a single radar series.
 */
export type RadarSeriesConfig = {
  /** Data key mapping to a property in your data objects */
  key: string;
  /** Display name for legend and tooltip. Defaults to `key` */
  name?: string;
  /** Hex color for stroke and fill. Falls back to utility-brand palette */
  color?: string;
  /** Fill opacity for the radar area. @default 0.2 */
  fillOpacity?: number;
  /** Optional props passed directly to the Radar component */
  radarProps?: Partial<ChartRadarProps>;
};

/**
 * RadarChart props.
 */
export interface RadarChartProps<
  T extends Record<string, unknown> = Record<string, unknown>,
> {
  /** aria label used for targeting the element */
  'aria-label'?: string;

  /** Array of data objects to display in the chart */
  data: T[];

  /** Key from data objects to use for the polar angle axis (category labels) */
  dataKey: keyof T & string;

  /** Array of series configurations defining which data keys to plot */
  series: RadarSeriesConfig[];

  /** Chart height in pixels or percentage string. @default 300 */
  height?: number | `${number}%`;

  /** Outer radius of the radar chart. @default "80%" */
  outerRadius?: number | string;

  /** Display polar grid lines. @default true */
  showGrid?: boolean;

  /** Display legend below the chart. @default true */
  showLegend?: boolean;

  /** Legend placement. @default "bottom" */
  legendPosition?: LegendPosition;

  /** Display tooltip on hover. @default true */
  showTooltip?: boolean;

  /** Props passed directly to the Recharts PolarAngleAxis component */
  polarAngleAxisProps?: Partial<PolarAngleAxisProps>;

  /** Props passed directly to the Recharts PolarRadiusAxis component */
  polarRadiusAxisProps?: Partial<PolarRadiusAxisProps>;

  /** Props passed directly to the Recharts Tooltip component */
  tooltipProps?: Partial<ChartTooltipProps>;

  /** Props passed directly to the Recharts Legend component */
  legendProps?: Partial<LegendProps>;

  /** Custom tooltip content component replacing the default tooltip */
  tooltipContent?: React.FC<ChartTooltipProps> | React.ReactElement;

  /** Custom legend content component replacing the default legend */
  legendContent?: React.FC<LegendProps> | React.ReactElement;

  /** Additional CSS classes for the chart container */
  className?: string;
}

function RadarChartAngleTick(props: BaseTickContentProps) {
  const {
    x,
    y,
    cx: centerX,
    cy: centerY,
    textAnchor,
    payload,
  } = props as unknown as {
    x: number;
    y: number;
    cx: number;
    cy: number;
    textAnchor: 'start' | 'middle' | 'end';
    payload: { value: string | number };
  };
  const dx = x - centerX;
  const dy = y - centerY;
  const dist = Math.sqrt(dx * dx + dy * dy);
  const nudgedX = dist > 0 ? x + (RADAR_LABEL_OFFSET * dx) / dist : x;
  const nudgedY = dist > 0 ? y + (RADAR_LABEL_OFFSET * dy) / dist : y;

  return (
    <text
      x={nudgedX}
      y={nudgedY}
      textAnchor={textAnchor}
      dominantBaseline="central"
      className="fill-utility-gray-700 text-xs font-medium"
    >
      {payload.value}
    </text>
  );
}

/**
 * Custom tick renderer for the PolarRadiusAxis.
 * Draws a rounded pill (fill-utility-gray-50) with centered text
 * at each radial grid value. Rendered behind the radar areas
 * via RADAR_RADIUS_AXIS_Z_INDEX.
 */
function RadarChartLegendPill(props: BaseTickContentProps) {
  const { x, y, payload } = props as {
    x: number;
    y: number;
    payload: { value: string | number };
  };
  const text = String(payload.value);
  const rectWidth =
    text.length * RADAR_PILL_CHAR_WIDTH + RADAR_PILL_PADDING_X * 2;
  const rectHeight = RADAR_PILL_HEIGHT + RADAR_PILL_PADDING_Y;

  return (
    <g>
      <rect
        x={x - rectWidth / 2}
        y={y - rectHeight / 2}
        width={rectWidth}
        height={rectHeight}
        rx={rectHeight / 2}
        className="fill-utility-gray-50"
      />
      <text
        x={x}
        y={y}
        textAnchor="middle"
        dominantBaseline="central"
        className="fill-utility-gray-700 text-xs font-medium"
      >
        {payload.value}
      </text>
    </g>
  );
}

export function RadarChart<
  T extends Record<string, unknown> = Record<string, unknown>,
>({
  'aria-label': ariaLabel,
  data,
  dataKey,
  series,
  height = 300,
  outerRadius = '80%',
  showGrid = true,
  showLegend = true,
  legendPosition = 'bottom',
  showTooltip = true,
  polarAngleAxisProps,
  polarRadiusAxisProps,
  tooltipProps,
  legendProps,
  tooltipContent,
  legendContent,
  className,
}: RadarChartProps<T>) {
  const chartLabel = ariaLabel ?? 'Radar Chart';
  const seriesWithFallback = series.map((s, index) => {
    const paletteIndex = index % FALLBACK_PALETTE.length;
    const fallbackClassName = s.color
      ? undefined
      : FALLBACK_PALETTE[paletteIndex];
    const resolvedColor = s.color ?? FALLBACK_PALETTE_COLORS[paletteIndex];

    return {
      ...s,
      className: fallbackClassName,
      resolvedColor,
    };
  });

  return (
    <ResponsiveContainer
      height={height}
      className={cx('w-full', className)}
    >
      <RechartsRadarChart
        cx="50%"
        cy="50%"
        outerRadius={outerRadius}
        data={data}
        className="text-tertiary [&_.recharts-text]:font-body [&_.recharts-text]:font-regular [&_.recharts-text]:text-xs"
        role="img"
        aria-label={chartLabel}
      >
        {showGrid && (
          <PolarGrid
            stroke="currentColor"
            className="text-utility-gray-100"
          />
        )}

        {showLegend && (
          <Legend
            {...LEGEND_POSITION_MAP[legendPosition]}
            {...(legendContent && { content: legendContent })}
            {...legendProps}
          />
        )}

        <PolarAngleAxis
          dataKey={dataKey}
          tickLine={false}
          tick={RadarChartAngleTick}
          {...polarAngleAxisProps}
        />
        <PolarRadiusAxis
          zIndex={RADAR_RADIUS_AXIS_Z_INDEX}
          angle={90}
          axisLine={false}
          tick={RadarChartLegendPill}
          {...polarRadiusAxisProps}
        />

        {showTooltip && (
          <Tooltip
            {...(tooltipContent && { content: tooltipContent })}
            {...tooltipProps}
          />
        )}

        {seriesWithFallback.map((s) => (
          <Radar
            key={s.key}
            isAnimationActive={false}
            className={cx(s.className)}
            dataKey={s.key}
            name={s.name}
            stroke={s.resolvedColor}
            strokeWidth={2}
            strokeLinejoin="round"
            fill={s.resolvedColor}
            fillOpacity={s.fillOpacity ?? 0.2}
            {...s.radarProps}
          />
        ))}
      </RechartsRadarChart>
    </ResponsiveContainer>
  );
}
