import { useCallback, useState } from 'react';
import { TableRow, TableRowIdentifier } from '../_types';

function isValidRowId(value: unknown): value is TableRowIdentifier {
  return (
    (typeof value === 'string' && value.length > 0) ||
    (typeof value === 'number' && !Number.isNaN(value))
  );
}

function resolveRowId<TData extends TableRow>(
  row: TData,
  index: number,
  getRowId?: (row: TData, index: number) => TableRowIdentifier | undefined,
): TableRowIdentifier {
  const explicitId =
    typeof getRowId === 'function' ? getRowId(row, index) : undefined;
  if (isValidRowId(explicitId)) return explicitId;
  if (typeof row === 'object' && isValidRowId(row.id)) return row.id;
  if ((typeof row === 'number' || typeof row === 'string') && isValidRowId(row))
    return row;
  return index;
}

export interface TableItemMeta {
  isParent: boolean;
  isChild: boolean;
  isLastChild: boolean;
}

const DEFAULT_META: TableItemMeta = {
  isParent: false,
  isChild: false,
  isLastChild: false,
};

export function useTableItems<TData extends TableRow>(
  rowData: TData[],
  getRowId?: (row: TData, index: number) => TableRowIdentifier | undefined,
  getChildRows?: (row: TData) => TData[],
  collapsible?: boolean,
) {
  const [collapsedKeys, setCollapsedKeys] = useState<Set<TableRowIdentifier>>(
    () => new Set(),
  );

  const toggleExpanded = useCallback((key: TableRowIdentifier) => {
    setCollapsedKeys((prev) => {
      const next = new Set(prev);
      if (next.has(key)) next.delete(key);
      else next.add(key);
      return next;
    });
  }, []);

  if (!getChildRows) {
    return {
      items: rowData.map((row, index) => ({
        __row: row,
        __index: index,
        __meta: DEFAULT_META,
        id: resolveRowId(row, index, getRowId),
      })),
      hasChildRows: false,
      collapsedKeys: undefined as Set<TableRowIdentifier> | undefined,
      toggleExpanded: undefined as
        | ((key: TableRowIdentifier) => void)
        | undefined,
    };
  }

  let flatIndex = 0;
  let anyChildren = false;
  const items: {
    __row: TData;
    __index: number;
    __meta: TableItemMeta;
    id: TableRowIdentifier;
  }[] = [];

  rowData.forEach((row, sourceIndex) => {
    const id = resolveRowId(row, sourceIndex, getRowId);
    const children = getChildRows(row) ?? [];
    const isParent = children.length > 0;
    if (isParent) anyChildren = true;

    items.push({
      __row: row,
      __index: flatIndex++,
      __meta: { isParent, isChild: false, isLastChild: false },
      id,
    });

    const isExpanded = !collapsible || !collapsedKeys.has(id);

    if (isParent && isExpanded) {
      children.forEach((child, childIndex) => {
        items.push({
          __row: child,
          __index: flatIndex++,
          __meta: {
            isParent: false,
            isChild: true,
            isLastChild: childIndex === children.length - 1,
          },
          id: resolveRowId(child, childIndex, getRowId),
        });
      });
    }
  });

  return {
    items,
    hasChildRows: anyChildren,
    collapsedKeys: collapsible ? collapsedKeys : undefined,
    toggleExpanded: collapsible ? toggleExpanded : undefined,
  };
}
