import { MultiSelect as BaseMultiSelect } from './BaseMultiSelect';
import { type SelectItemType } from './BaseSelect';
import { SelectItem } from './BaseSelectItem';
import { ComponentPropsWithoutRef } from 'react';
import { WithDataId } from '@/types/withDataId';

type BaseMultiSelectProps = ComponentPropsWithoutRef<typeof BaseMultiSelect>;

export interface MultiSelectProps
  extends Omit<BaseMultiSelectProps, 'children' | 'isRequired'>, WithDataId {
  children?: React.ReactNode | ((item: SelectItemType) => React.ReactNode);
  required?: BaseMultiSelectProps['isRequired'];
}

/** @deprecated Use CreatableMultiSelect instead */
const MultiSelect = function MultiSelect({
  required,
  items,
  'data-id': dataId,
  ...props
}: MultiSelectProps) {
  return (
    <BaseMultiSelect
      isRequired={required}
      items={items}
      data-id={dataId}
      {...props}
    >
      {props.children ||
        ((item) => (
          <SelectItem
            data-id={`${dataId}-${item.id}`}
            key={item.id}
            {...item}
          />
        ))}
    </BaseMultiSelect>
  );
};

export { MultiSelect };
