import * as React from 'react';
import {
  Area,
  AreaChart,
  CartesianGrid,
  Legend,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from 'recharts';
import type { TooltipProps } from 'recharts';
import type {
  NameType,
  ValueType,
} from 'recharts/types/component/DefaultTooltipContent';
import { cx } from '@/utils/cx';
import { ChartTooltipContent } from '../ChartTooltipContent';
import { ChartLegendContent } from '../ChartLegendContent';
import type { CurveType } from 'recharts/types/shape/Curve';
import type { Props as LegendProps } from 'recharts/types/component/Legend';
import type { Props as XAxisProps } from 'recharts/types/cartesian/XAxis';
import type { Props as YAxisProps } from 'recharts/types/cartesian/YAxis';
import type { Props as AreaProps } from 'recharts/types/cartesian/Area';

/** Tooltip props with recharts generic types */
type ChartTooltipProps = TooltipProps<ValueType, NameType>;

/** Area component props */
type ChartAreaProps = AreaProps;

/**
 * Fallback palette (utility-brand 700 → 100).
 * Classes for stroke via currentColor.
 */
import {
  FALLBACK_PALETTE,
  FALLBACK_PALETTE_COLORS,
} from '../../../../constants/charts.constants';

/**
 * Configuration for a single data series.
 */
export type SeriesConfig = {
  /** Data key mapping to a property in your data objects */
  key: string;
  /** Display name for legend and tooltip. Defaults to `key` */
  name?: string;
  /** Hex color for stroke and gradient. Falls back to utility-brand palette */
  color?: string;
  /** Show gradient fill under the line. @default false */
  gradient?: boolean;
  /** Line interpolation type. @default "monotone" */
  type?: CurveType;
  /** Optional props passed directly to the Area component */
  seriesProps?: Partial<ChartAreaProps>;
};

/**
 * LineChart props.
 */
export interface LineChartProps<
  T extends Record<string, unknown> = Record<string, unknown>,
> {
  /** aria label used for targeting the element */
  'aria-label'?: string;

  /** Array of data objects to display in the chart */
  data: T[];

  /** Key from data objects to use for the X-axis */
  xKey: keyof T & string;

  /** Array of series configurations defining which data keys to plot */
  series: SeriesConfig[];

  /** Chart height in pixels or percentage string. @default 300 */
  height?: number | `${number}%`;

  /** Display horizontal grid lines. @default true */
  showGrid?: boolean;

  /** Display legend below the chart. @default true */
  showLegend?: boolean;

  /** Display tooltip on hover. @default true */
  showTooltip?: boolean;

  /** Props passed directly to the Recharts XAxis component */
  xAxisProps?: Partial<XAxisProps>;

  /** Props passed directly to the Recharts YAxis component */
  yAxisProps?: Partial<YAxisProps>;

  /** Props passed directly to the Recharts Tooltip component */
  tooltipProps?: Partial<ChartTooltipProps>;

  /** Props passed directly to the Recharts Legend component */
  legendProps?: Partial<LegendProps>;

  /** Custom tooltip content component replacing the default tooltip */
  tooltipContent?: React.FC<ChartTooltipProps> | React.ReactElement;

  /** Custom legend content component replacing the default legend */
  legendContent?: React.FC<LegendProps> | React.ReactElement;

  /** Additional CSS classes for the chart container */
  className?: string;
}

export function LineChart<
  T extends Record<string, unknown> = Record<string, unknown>,
>({
  'aria-label': ariaLabel,
  data,
  xKey,
  series,
  height = 300,
  showGrid = true,
  showLegend = true,
  showTooltip = true,
  xAxisProps,
  yAxisProps,
  tooltipProps,
  legendProps,
  tooltipContent,
  legendContent,
  className,
}: LineChartProps<T>) {
  const chartLabel = ariaLabel ?? 'Area Chart';
  const seriesWithFallback = series.map((s, index) => {
    const paletteIndex = index % FALLBACK_PALETTE.length;
    const fallbackClassName = s.color
      ? undefined
      : FALLBACK_PALETTE[paletteIndex];
    const resolvedColor = s.color ?? FALLBACK_PALETTE_COLORS[paletteIndex];

    return {
      ...s,
      className: fallbackClassName,
      resolvedColor,
    };
  });

  return (
    <ResponsiveContainer
      height={height}
      className={cx('w-full', className)}
    >
      <AreaChart
        data={data}
        className="text-tertiary [&_.recharts-text]:font-body [&_.recharts-text]:font-regular [&_.recharts-text]:text-xs"
        role="img"
        aria-label={chartLabel}
      >
        <defs>
          {seriesWithFallback
            .filter((s) => s.gradient)
            .map((s) => {
              const gradientColor = s.resolvedColor;
              return (
                <linearGradient
                  key={s.key}
                  id={`gradient-${s.key}`}
                  x1="0"
                  y1="0"
                  x2="0"
                  y2="1"
                >
                  <stop
                    offset="5%"
                    stopColor={gradientColor}
                    stopOpacity={0.4}
                  />
                  <stop
                    offset="95%"
                    stopColor={gradientColor}
                    stopOpacity={0}
                  />
                </linearGradient>
              );
            })}
        </defs>

        {showGrid && (
          <CartesianGrid
            vertical={false}
            stroke="currentColor"
            className="text-utility-gray-100"
          />
        )}

        {showLegend && (
          <Legend
            iconType="circle"
            content={legendContent ?? ChartLegendContent}
            {...legendProps}
          />
        )}

        <XAxis
          dataKey={xKey}
          {...xAxisProps}
        />
        <YAxis {...yAxisProps} />

        {showTooltip && (
          <Tooltip
            content={tooltipContent ?? ChartTooltipContent}
            {...tooltipProps}
          />
        )}

        {seriesWithFallback.map((s) => (
          <Area
            key={s.key}
            isAnimationActive={false}
            className={cx(s.className)}
            dataKey={s.key}
            name={s.name}
            type={s.type ?? 'monotone'}
            stroke={s.resolvedColor}
            strokeWidth={2}
            fill={s.gradient ? `url(#gradient-${s.key})` : 'none'}
            fillOpacity={1}
            {...s.seriesProps}
          />
        ))}
      </AreaChart>
    </ResponsiveContainer>
  );
}
