import { Tabs, Tab, TabList } from '@/components/molecules/Tabs';
import { WithDataId } from '@/types/withDataId';

export interface TabItem {
  label: string;
  to: string;
}

export interface PageLayoutProps extends WithDataId {
  children: React.ReactNode;
  title: string;
  tabs?: TabItem[];
  selectedTab?: TabItem['to'];
  onTabChange?: (tabTo: string) => void;
}

export function PageLayout({
  children,
  title: _title,
  tabs,
  selectedTab,
  onTabChange,
  'data-id': dataId,
}: PageLayoutProps) {
  const handleSelectionChange = (key: React.Key) => {
    const tabTo = key as string;
    onTabChange?.(tabTo);
  };

  return (
    <div className="flex flex-col gap-6 px-6 pb-4 w-full">
      <header className="flex sticky top-0 z-20 flex-row gap-6 items-center bg-background">
        {tabs && tabs.length > 0 && (
          <Tabs
            selectedKey={selectedTab}
            onSelectionChange={onTabChange ? handleSelectionChange : undefined}
            aria-label="page tabs"
          >
            <TabList type="button-minimal">
              {tabs.map((tab) => (
                <Tab
                  key={tab.to}
                  id={tab.to}
                  label={tab.label}
                  data-id={`${dataId}-${tab.label}`}
                >
                  {/* Tab content will be provided by children prop in parent component */}
                  <div>
                    {/* This tab panel content should be provided by the parent */}
                  </div>
                </Tab>
              ))}
            </TabList>
          </Tabs>
        )}
      </header>
      {children}
    </div>
  );
}
