import {
  useCallback,
  useEffect,
  useLayoutEffect,
  useRef,
  useState,
} from 'react';

export function useChipOverflow({
  containerRef,
  chipCount,
  chipOverflow,
  isExpanded,
}: {
  containerRef: React.RefObject<HTMLDivElement | null>;
  chipCount: number;
  chipOverflow: boolean;
  isExpanded: boolean;
}) {
  const [visibleCount, setVisibleCount] = useState(
    chipOverflow && !isExpanded ? 0 : chipCount,
  );
  const [clipWidth, setClipWidth] = useState<number | undefined>(undefined);
  const [measureTick, setMeasureTick] = useState(0);
  const prevExpandedRef = useRef(isExpanded);
  // Track the last two measured counts to detect oscillation (e.g. 3 → 2 → 3 → 2).
  // When the count alternates between two values at a boundary width, we settle on
  // the lower value to stop the infinite resize loop.
  const prevCountRef = useRef<number | null>(null);
  const prevPrevCountRef = useRef<number | null>(null);
  const prevChipCountRef = useRef(chipCount);

  if (prevChipCountRef.current !== chipCount) {
    prevChipCountRef.current = chipCount;
    prevCountRef.current = null;
    prevPrevCountRef.current = null;
  }

  const measure = useCallback(() => {
    const container = containerRef.current;
    if (!container || !chipOverflow || isExpanded) {
      prevCountRef.current = null;
      prevPrevCountRef.current = null;
      setVisibleCount(chipCount);
      setClipWidth(undefined);
      return;
    }

    const chipElements = Array.from(container.children) as HTMLElement[];
    if (chipElements.length === 0) {
      prevCountRef.current = null;
      prevPrevCountRef.current = null;
      setVisibleCount(chipCount);
      setClipWidth(undefined);
      return;
    }

    // Temporarily remove clip constraint so we measure against the full available width
    const prevMaxWidth = container.style.maxWidth;
    container.style.maxWidth = 'none';

    const containerRect = container.getBoundingClientRect();
    let count = 0;
    for (const chip of chipElements) {
      if (chip.getBoundingClientRect().right <= containerRect.right) {
        count++;
      } else {
        break;
      }
    }

    // Detect oscillation: if the count is bouncing between two values,
    // settle on the lower one to break the loop.
    if (
      prevPrevCountRef.current !== null &&
      count === prevPrevCountRef.current &&
      count !== prevCountRef.current
    ) {
      count = Math.min(count, prevCountRef.current!);
    }
    prevPrevCountRef.current = prevCountRef.current;
    prevCountRef.current = count;

    // Compute a maxWidth that ends exactly at the last visible chip
    const newClipWidth =
      count > 0 && count < chipElements.length
        ? chipElements[count - 1].getBoundingClientRect().right -
          containerRect.left
        : undefined;

    // Restore before React re-renders
    container.style.maxWidth = prevMaxWidth;

    setVisibleCount(count);
    setClipWidth(newClipWidth);
  }, [containerRef, chipCount, chipOverflow, isExpanded]);

  useLayoutEffect(() => {
    // When transitioning from isExpanded → collapsed, reset visibleCount to 0
    // so the "+X more" button renders and takes space during measurement.
    // Then bump measureTick to trigger a second pass that actually measures.
    if (prevExpandedRef.current && !isExpanded && chipOverflow) {
      prevExpandedRef.current = isExpanded;
      setVisibleCount(0);
      setClipWidth(undefined);
      setMeasureTick((t) => t + 1);
      return;
    }
    prevExpandedRef.current = isExpanded;
    measure();
  }, [measure, isExpanded, chipOverflow, measureTick]);

  useEffect(() => {
    const container = containerRef.current;
    if (!container || !chipOverflow) return;

    let rafId: number;
    const observer = new ResizeObserver(() => {
      cancelAnimationFrame(rafId);
      rafId = requestAnimationFrame(() => {
        measure();
      });
    });
    observer.observe(container);
    return () => {
      cancelAnimationFrame(rafId);
      observer.disconnect();
    };
  }, [containerRef, chipOverflow, measure]);

  const hiddenCount =
    chipOverflow && !isExpanded ? Math.max(0, chipCount - visibleCount) : 0;
  return { visibleCount, hiddenCount, clipWidth };
}
