// Country data with phone codes
export interface Country {
  id: string; // ISO 3166-1 alpha-2 (lowercase)
  label: string; // Country name
  code: string; // Calling code, e.g. +1
  flag?: string;
  /**
   * Optional national-number formatting mask. `.` is a digit slot; any other
   * character is a literal (typically a space). Example: `.. .... .........`.
   */
  mask?: string;
  /**
   * Extra strings to match against when the picker is `searchable` (e.g.
   * localized country names). Search is case-insensitive substring.
   */
  searchAliases?: string[];
}

// Helper: country id to emoji flag
function isoToFlag(id: string): string {
  const code = aliasCountryId(id);
  if (code.length !== 2) return '';
  const A = 127397; // regional indicator base
  const chars = code
    .split('')
    .map((c) => String.fromCodePoint(A + c.charCodeAt(0)));
  return chars.join('');
}

