export type CountryLabelMode = 'flagName' | 'name' | 'iso';

export interface PhoneNumberInputProps
  extends
    Omit<FieldWrapperProps, 'children'>,
    WithDataId,
    Omit<React.HTMLAttributes<HTMLElement>, 'onChange'> {
  placeholder?: string;
  isDisabled?: boolean;
  size?: 'md';
  className?: string;
  // Full phone value including country code, e.g. '+1 555 000 0000'
  value?: string;
  defaultValue?: string;
  onChange?: (value: string) => void;
  selectedCountry?: Country;
  defaultSelectedCountry?: Country;
  onCountryChange?: (country: Country) => void;
  countries?: Country[];
  countryLabelMode?: CountryLabelMode; // how the dropdown labels render
  /**
   * Visual variant. `flag` renders only a circular country flag (clickable
   * picker) inside the field; `default` keeps the labelled NativeSelect.
   */
  variant?: 'default' | 'flag';
  /**
   * Make the country picker searchable. In the default variant this swaps the
   * native select for a custom popover trigger; in the flag variant the
   * existing popover gains a search input. Default false.
   */
  searchable?: boolean;
  /**
   * UI text overrides. Single grouped object so the surface can grow without
   * adding sibling string props.
   */
  texts?: {
    /** Placeholder shown in the search input. Defaults to "Search". */
    searchPlaceholder?: string;
    /** Message shown when no country matches. Defaults to "No countries found". */
    searchNotFound?: string;
  };
  ref?: Ref<HTMLInputElement>;
}

// Match the longest country code at the start of a value like '+351 ...'
function matchCountryByValue(
  all: Country[],
  fullValue: string | undefined,
): Country | undefined {
  if (!fullValue) return undefined;
  const v = fullValue.trim();
  if (!v.startsWith('+')) return undefined;
  // Sort codes by length desc to avoid partial matches like +3 before +351
  const sorted = [...all].sort((a, b) => b.code.length - a.code.length);
  return sorted.find((c) => v.startsWith(c.code));
}

// Match a country against a search query. Numeric queries match the dial code;
// text queries match label, ISO id, and any searchAliases.
function matchesCountrySearch(country: Country, query: string): boolean {
  const trimmed = query.trim().toLowerCase().replace(/^\+/, '');
  if (!trimmed) return true;
  if (/^\d+$/.test(trimmed)) {
    return country.code.replace(/\+/g, '').includes(trimmed);
  }
  return [country.label, country.id, ...(country.searchAliases ?? [])].some(
    (field) => field.toLowerCase().includes(trimmed),
  );
}

// Format raw digits according to a country mask (`.` = digit slot, other chars are literals).
function applyMask(digits: string, mask: string): string {
  let out = '';
  let di = 0;
  for (let mi = 0; mi < mask.length && di < digits.length; mi++) {
    if (mask[mi] === '.') {
      out += digits[di++];
    } else {
      out += mask[mi];
    }
  }
  // Append any digits beyond the mask length unchanged.
  if (di < digits.length) out += digits.slice(di);
  return out;
}

// Ensure value starts with '+' and allow only '+', digits, spaces, dashes, parentheses
function normalizeValue(raw: string, fallbackDial: string): string {
  let v = raw.replace(/[^\d+\s\-()]/g, '');
  // Keep only the first '+' and ensure it exists
  v = v.replace(/\+/g, '');
  v = `+${v}`;
  // If user typed nothing after '+', seed with selected code
  if (v === '+') return fallbackDial + ' ';
  return v;
}

export const PhoneNumberInput: FC<PhoneNumberInputProps> = ({
  label,
  hint,
  placeholder,
  isRequired,
  isDisabled,
  isInvalid,
  isWarning,
  tooltip,
  description,
  id,
  fieldSize = 'md',
  labelPosition = 'left',
  alignLabel,
  size = 'sm',
  className,
  value,
  defaultValue,
  onChange,
  selectedCountry,
  defaultSelectedCountry = countries[0],
  onCountryChange,
  countries: customCountries = countries,
  countryLabelMode = 'flagName',
  variant = 'default',
  searchable = false,
  texts,
  ref,
  'data-id': dataId,
  ...rest
}) => {
  const searchPlaceholder = texts?.searchPlaceholder ?? 'Search';
  const searchNotFoundLabel = texts?.searchNotFound ?? 'No countries found';
  const [searchQuery, setSearchQuery] = useState('');

  // Clear the search query when the consumer swaps the country list (e.g.
  // region change). Compared by id-list stringification so inline-array refs
  // from a parent re-render do not spuriously clear the query.
  const countriesKey = customCountries.map((c) => c.id).join('|');
  useEffect(() => {
    setSearchQuery('');
  }, [countriesKey]);

  const filteredCountries = useMemo(() => {
    if (!searchable || !searchQuery.trim()) return customCountries;
    return customCountries.filter((c) => matchesCountrySearch(c, searchQuery));
  }, [customCountries, searchQuery, searchable]);
  // Country selection (controlled/uncontrolled)
  const [country, setCountry] = useControlledState(
    selectedCountry,
    defaultSelectedCountry,
    (c) => {
      onCountryChange?.(c);
    },
  );

  // Full phone value including the '+' and dial code
  const [fullValue, setFullValue] = useControlledState(
    value,
    defaultValue || country.code + ' ',
    (val) => {
      onChange?.(val);
    },
  );

  // Reconcile country with externally-driven value changes ONLY when the
  // consumer controls `value` but leaves `selectedCountry` uncontrolled. In all
  // other paths, `handleInputChange` and `handleCountrySelect` already keep
  // them in sync — running the effect there risks repeated `onCountryChange`
  // calls (controlled-country case) and stale-dep re-runs (inline countries).
  const shouldReconcileCountry =
    value !== undefined && selectedCountry === undefined;
  useEffect(() => {
    if (!shouldReconcileCountry) return;
    const matched = matchCountryByValue(customCountries, fullValue);
    if (matched && matched.id !== country.id) {
      setCountry(matched);
    }
  }, [
    shouldReconcileCountry,
    fullValue,
    customCountries,
    country.id,
    setCountry,
  ]);

  const selectOptions = customCountries.map((c) => {
    const iso = c.id.toUpperCase();
    const optionLabel =
      countryLabelMode === 'iso'
        ? iso
        : countryLabelMode === 'name'
          ? c.label
          : `${c.flag ?? ''} ${c.label}`.trim();
    return { label: optionLabel, value: c.id };
  });

  const effectivePlaceholder =
    placeholder ?? `${country?.code ?? '+'} (555) 000-0000`;

  const handleInputChange = (val: string) => {
    let normalized = normalizeValue(val, country.code);
    // Auto-switch country (and flag) when the typed prefix matches a known code.
    const matched = matchCountryByValue(customCountries, normalized);
    if (matched) {
      if (matched.id !== country.id) setCountry(matched);
      const rest = normalized.slice(matched.code.length);
      const digits = rest.replace(/\D/g, '');
      if (matched.mask && digits) {
        normalized = `${matched.code} ${applyMask(digits, matched.mask)}`;
      } else if (rest && !rest.startsWith(' ')) {
        // Insert a space between the dial code and the national number.
        normalized = `${matched.code} ${rest}`;
      }
    }
    setFullValue(normalized);
  };

  const handleCountrySelect = (iso: string) => {
    const next =
      customCountries.find((c) => c.id === iso) || customCountries[0];
    if (next.id === country.id) return;

    // Extract national digits from the existing value (drop the previous dial code).
    const currentMatch = matchCountryByValue(customCountries, fullValue);
    const remainder = currentMatch
      ? fullValue.slice(currentMatch.code.length)
      : fullValue;
    const digits = remainder.replace(/\D/g, '');

    const formatted = digits
      ? next.mask
        ? `${next.code} ${applyMask(digits, next.mask)}`
        : `${next.code} ${digits}`
      : `${next.code} `;

    setCountry(next);
    setFullValue(formatted);
  };

  const countryPopoverContents = (
    <AriaPopover
      placement="bottom start"
      offset={4}
      className={cx(
        'flex max-h-64 w-72 flex-col overflow-hidden rounded-lg bg-primary shadow-lg ring-1 ring-secondary_alt outline-hidden',
        searchable ? 'py-0' : 'py-1',
      )}
    >
      {searchable && (
        <PopoverSearchInput
          data-id={`${dataId}-search`}
          value={searchQuery}
          onChange={setSearchQuery}
          placeholder={searchPlaceholder}
        />
      )}
      {searchable && filteredCountries.length === 0 ? (
        <div
          className="px-3 py-4 text-sm text-tertiary"
          role="status"
        >
          {searchNotFoundLabel}
        </div>
      ) : (
        <AriaListBox
          items={filteredCountries}
          className="flex-1 overflow-y-auto outline-hidden"
        >
          {(c) => (
            <AriaListBoxItem
              id={c.id}
              textValue={`${c.label} ${c.code}`}
              className={cx(
                'flex cursor-pointer items-center gap-2 px-3 py-2 text-md text-primary outline-hidden',
                'data-[focused]:bg-primary_hover data-[selected]:bg-active',
              )}
            >
              <FlagIcon flag={c.id} />
              <span className="flex-1 truncate">{c.label}</span>
              <span className="text-tertiary">{c.code}</span>
            </AriaListBoxItem>
          )}
        </AriaListBox>
      )}
    </AriaPopover>
  );

  const content =
    variant === 'flag' ? (
      <div
        className={cx(
          'flex w-full items-center rounded-lg bg-primary shadow-xs ring-1 ring-primary ring-inset transition duration-100 ease-linear',
          'focus-within:ring-2 focus-within:ring-brand',
          isDisabled && 'cursor-not-allowed bg-disabled_subtle',
          isInvalid && 'ring-error_subtle focus-within:ring-error',
          className,
        )}
      >
        <AriaSelect
          aria-label="Country"
          selectedKey={country?.id}
          onSelectionChange={(k) => handleCountrySelect(String(k))}
          isDisabled={isDisabled}
        >
          <AriaButton
            className={cx(
              'flex h-full items-center gap-1 outline-hidden cursor-pointer rounded-l-lg',
              size === 'sm' ? 'pl-3 pr-2 py-2' : 'pl-3.5 pr-2 py-2.5',
              'data-[focus-visible]:ring-2 data-[focus-visible]:ring-brand data-[focus-visible]:ring-inset',
              isDisabled && 'cursor-not-allowed',
            )}
            data-id={`${dataId}-country`}
          >
            <FlagIcon flag={country.id} />
            <ChevronDown
              aria-hidden="true"
              className="size-4 stroke-[2.5px] text-fg-quaternary"
            />
          </AriaButton>
          {countryPopoverContents}
        </AriaSelect>
        <input
          {...rest}
          id={id}
          ref={ref}
          type="tel"
          inputMode="tel"
          disabled={isDisabled}
          aria-invalid={isInvalid || undefined}
          required={isRequired}
          placeholder={effectivePlaceholder}
          value={fullValue}
          onChange={(e) => handleInputChange(e.target.value)}
          data-id={`${dataId}-input`}
          className={cx(
            'flex-1 bg-transparent text-md text-primary outline-hidden placeholder:text-placeholder px-2 py-2.5',
            isDisabled && 'cursor-not-allowed text-disabled',
          )}
        />
      </div>
    ) : (
      <InputGroup
        data-id={dataId}
        isDisabled={isDisabled}
        isInvalid={isInvalid}
        className={className}
        value={fullValue}
        onChange={handleInputChange}
        leadingAddon={
          searchable ? (
            <AriaSelect
              aria-label="Country"
              selectedKey={country?.id}
              onSelectionChange={(k) => handleCountrySelect(String(k))}
              isDisabled={isDisabled}
            >
              <AriaButton
                className={cx(
                  'flex h-full items-center gap-1 outline-hidden cursor-pointer rounded-l-lg',
                  size === 'sm' ? 'pl-3 pr-2 py-2' : 'pl-3.5 pr-2 py-2.5',
                  'data-[focus-visible]:ring-2 data-[focus-visible]:ring-brand data-[focus-visible]:ring-inset',
                  isDisabled && 'cursor-not-allowed',
                )}
                data-id={`${dataId}-country`}
              >
                <span className="truncate text-md text-primary">
                  {selectOptions.find((o) => o.value === country?.id)?.label ??
                    country?.label}
                </span>
                <ChevronDown
                  aria-hidden="true"
                  className="size-4 stroke-[2.5px] text-fg-quaternary"
                />
              </AriaButton>
              {countryPopoverContents}
            </AriaSelect>
          ) : (
            <NativeSelect
              aria-label="Country"
              options={selectOptions}
              value={country?.id}
              onChange={(e) => handleCountrySelect(e.target.value)}
            />
          )
        }
      >
        <InputBase
          {...(rest as React.ComponentProps<typeof InputBase>)}
          id={id}
          ref={ref}
          isDisabled={isDisabled}
          isInvalid={isInvalid}
          placeholder={effectivePlaceholder}
          inputMode="tel"
          type="tel"
          data-id={`${dataId}-input`}
        />
      </InputGroup>
    );

  return (
    <FieldWrapper
      id={id}
      label={label}
      hint={hint}
      isInvalid={isInvalid}
      isRequired={isRequired}
      isWarning={isWarning}
      tooltip={tooltip}
      description={description}
      fieldSize={fieldSize}
      labelPosition={labelPosition}
      alignLabel={alignLabel}
    >
      {content}
    </FieldWrapper>
  );
};
