import { WithDataId } from '@/types/withDataId';
import {
  FileListItemProps,
  FileUpload as FileUploadBase,
  FileUploadDropZone,
} from './FileUploadBase';

type BaseFileUploadDropZoneProps = React.ComponentProps<
  typeof FileUploadDropZone
>;

type DropZoneProps = Omit<BaseFileUploadDropZoneProps, 'className'>;

export type FileUploadProgressBarProps = {
  files: Array<
    Omit<FileListItemProps, 'onDelete' | 'onRetry'> & { id: string | number }
  >;
  onDeleteFile?: (id: string | number) => void;
  onRetryFile?: (id: string | number) => void;
  withProgressBar?: boolean;
  errorMessage?: string;
} & DropZoneProps &
  WithDataId;

export const FileUploadProgressBar = ({
  files,
  hint,
  accept,
  allowsMultiple,
  maxSize,
  onDropFiles,
  onDropUnacceptedFiles,
  onSizeLimitExceed,
  onDeleteFile,
  onRetryFile,
  isDisabled = false,
  withProgressBar = true,
  errorMessage,
  'data-id': dataId,
}: FileUploadProgressBarProps) => {
  const FileComponent = withProgressBar
    ? FileUploadBase.ListItemProgressBar
    : FileUploadBase.ListItemProgressFill;
  return (
    <FileUploadBase.Root data-id={dataId}>
      {(allowsMultiple || files.length === 0) && (
        <FileUploadBase.DropZone
          isDisabled={isDisabled}
          onDropFiles={onDropFiles}
          onDropUnacceptedFiles={onDropUnacceptedFiles}
          onSizeLimitExceed={onSizeLimitExceed}
          accept={accept}
          allowsMultiple={allowsMultiple}
          maxSize={maxSize}
          hint={hint}
        />
      )}

      {files.length > 0 && (
        <FileUploadBase.List className="mt-2.5">
          {files.map((file) => (
            <FileComponent
              key={file.id}
              {...file}
              onDelete={() => onDeleteFile?.(file.id)}
              onRetry={() => onRetryFile?.(file.id)}
            />
          ))}
        </FileUploadBase.List>
      )}
      {errorMessage && (
        <span
          role="alert"
          className="text-sm text-error-primary"
        >
          {errorMessage}
        </span>
      )}
    </FileUploadBase.Root>
  );
};
