import { ComboBox as BaseComboBox } from './BaseComboBox';
import { SelectItem } from './BaseSelectItem';
import { ComponentPropsWithoutRef } from 'react';
import { WithDataId } from '@/types/withDataId';

type BaseComboBoxProps = ComponentPropsWithoutRef<typeof BaseComboBox>;

export interface ComboBoxProps
  extends Omit<BaseComboBoxProps, 'isRequired'>, WithDataId {
  required?: BaseComboBoxProps['isRequired'];
}

const ComboBox = function ComboBox({
  required,
  items,
  'data-id': dataId,
  ...props
}: ComboBoxProps) {
  return (
    <BaseComboBox
      items={items}
      isRequired={required}
      data-id={dataId}
      {...props}
    >
      {(item) => (
        <SelectItem
          key={item.id}
          data-id={`${dataId}-${item.id}`}
          {...item}
        />
      )}
    </BaseComboBox>
  );
};

export { ComboBox };
