import { Extension } from '@tiptap/core';
import { Plugin, PluginKey } from '@tiptap/pm/state';
import { Decoration, DecorationSet } from '@tiptap/pm/view';
import { TEMPLATE_VAR_HIGHLIGHT_CLASS } from '../_utils';
import type { Node as ProseMirrorNode } from '@tiptap/pm/model';

const TEMPLATE_VAR_REGEX = /\{\{([^{}]*)\}\}/g;

interface TemplateVarsHighlightOptions {
  validKeywords: Set<string>;
}

function buildDecorations(doc: ProseMirrorNode, validKeywords: Set<string>) {
  if (validKeywords.size === 0) {
    return DecorationSet.empty;
  }

  const decorations: Decoration[] = [];

  doc.descendants((node, pos) => {
    if (!node.isText || !node.text) return;

    const text = node.text;
    let match: RegExpExecArray | null;
    TEMPLATE_VAR_REGEX.lastIndex = 0;

    while ((match = TEMPLATE_VAR_REGEX.exec(text)) !== null) {
      const full = match[0];
      if (!validKeywords.has(full)) continue;

      const start = pos + match.index;
      const end = start + full.length;

      // ProseMirror inline decorations split the range at every overlapping
      // decoration boundary, so nesting an outer "highlight" with inner
      // "brace" decorations produces three separate spans — each carrying
      // the rounded outline class. Emit a single decoration so the whole
      // `{{var}}` renders as one continuous border.
      decorations.push(
        Decoration.inline(start, end, { class: TEMPLATE_VAR_HIGHLIGHT_CLASS }),
      );
    }
  });

  return DecorationSet.create(doc, decorations);
}

export const TemplateVarsHighlight =
  Extension.create<TemplateVarsHighlightOptions>({
    name: 'templateVarsHighlight',

    addOptions() {
      return {
        validKeywords: new Set<string>(),
      };
    },

    addProseMirrorPlugins() {
      const extension = this;
      const pluginKey = new PluginKey('templateVarsHighlight');

      return [
        new Plugin({
          key: pluginKey,
          state: {
            init: (_, state) =>
              buildDecorations(state.doc, extension.options.validKeywords),
            apply: (tr, oldSet) => {
              if (!tr.docChanged) return oldSet;
              return buildDecorations(tr.doc, extension.options.validKeywords);
            },
          },
          props: {
            decorations(state) {
              return pluginKey.getState(state);
            },
          },
        }),
      ];
    },
  });
