import { TextAreaBase } from '@/components/atoms/TextArea';
import { FieldWrapper } from '@/components/molecules/FieldWrapper';
import { Templater } from './Templater';
import type { FieldTemplaterProps } from './_types';

type FieldTextAreaTemplaterProps = Omit<
  FieldTemplaterProps<typeof TextAreaBase>,
  'component'
>;

export function FieldTextAreaTemplater({
  label,
  hint,
  isInvalid,
  isRequired,
  tooltip,
  description,
  id = '',
  fieldSize = 'md',
  labelPosition = 'left',
  ...props
}: FieldTextAreaTemplaterProps) {
  return (
    <FieldWrapper
      id={id}
      label={label}
      hint={hint}
      isInvalid={isInvalid}
      isRequired={isRequired}
      tooltip={tooltip}
      description={description}
      fieldSize={fieldSize}
      labelPosition={labelPosition}
    >
      <Templater
        {...props}
        isInvalid={isInvalid}
        component={TextAreaBase}
        menuTopPos="top-[5px]"
        menuRightPos="right-[15px]"
      />
    </FieldWrapper>
  );
}
