import * as React from 'react';
import {
  Legend,
  Pie,
  PieChart as RechartsPieChart,
  ResponsiveContainer,
  Sector,
  Tooltip,
} from 'recharts';
import type { TooltipProps } from 'recharts';
import type {
  NameType,
  ValueType,
} from 'recharts/types/component/DefaultTooltipContent';
import { cx } from '@/utils/cx';
import { ChartTooltipContent } from '../ChartTooltipContent';
import { ChartLegendContent } from '../ChartLegendContent';
import {
  useTooltipPosition,
  pieChartPositionCalculator,
  getPieElement,
} from '../hooks/useTooltipPosition';
import type { Props as LegendProps } from 'recharts/types/component/Legend';
import type {
  Props as PieProps,
  PieSectorShapeProps,
} from 'recharts/types/polar/Pie';

/** Tooltip props with recharts generic types */
type ChartTooltipProps = TooltipProps<ValueType, NameType>;

/** Pie component props */
type ChartPieProps = PieProps;

/**
 * Fallback palette (utility-brand 700 → 100).
 * Classes for fill via currentColor.
 */
import {
  FALLBACK_PALETTE,
  FALLBACK_PALETTE_COLORS,
} from '../../../../constants/charts.constants';

/**
 * A single data entry for the PieChart.
 */
export type PieChartDataEntry = {
  /** Display name for legend and tooltip */
  name: string;
  /** Numeric value determining slice size */
  value: number;
  /** Hex color for fill. Falls back to utility-brand palette */
  color?: string;
  /** Tailwind class for fill via currentColor. Falls back to utility-brand palette */
  className?: string;
};

/**
 * PieChart props.
 */
export interface PieChartProps {
  /** aria label used for targeting the element */
  'aria-label'?: string;

  /** Array of data entries to display in the chart */
  data: PieChartDataEntry[];

  /** Chart height in pixels or percentage string. @default 300 */
  height?: number | `${number}%`;

  /** Inner radius in pixels for donut style. @default 0 */
  innerRadius?: number;

  /** Outer radius in pixels. @default 80 */
  outerRadius?: number;

  /** Start angle in degrees. @default -270 */
  startAngle?: number;

  /** End angle in degrees. @default -630 */
  endAngle?: number;

  /** Display legend. @default true */
  showLegend?: boolean;

  /** Display tooltip on hover. @default true */
  showTooltip?: boolean;

  /** Props passed directly to the Recharts Tooltip component */
  tooltipProps?: Partial<ChartTooltipProps>;

  /** Props passed directly to the Recharts Legend component */
  legendProps?: Partial<LegendProps>;

  /** Props passed directly to the Recharts Pie component */
  pieProps?: Partial<ChartPieProps>;

  /** Custom tooltip content component replacing the default tooltip */
  tooltipContent?: React.FC<ChartTooltipProps> | React.ReactElement;

  /** Custom legend content component replacing the default legend */
  legendContent?: React.FC<LegendProps> | React.ReactElement;

  /** Additional CSS classes for the chart container */
  className?: string;

  activeShapeIndex?: number;
  /** Display tooltip on legend hover. @default false */
  showTooltipOnLegendHover?: boolean;
}

const renderActiveShape = (
  props: PieSectorShapeProps & { activeShapeIndex?: number },
) => {
  const { isActive, activeShapeIndex, ...rest } = props;
  const isActiveShape = isActive || activeShapeIndex === rest.index;

  return (
    <Sector
      {...rest}
      outerRadius={isActiveShape ? rest.outerRadius + 6 : rest.outerRadius}
    />
  );
};

export function PieChart({
  'aria-label': ariaLabel,
  data,
  height = 300,
  innerRadius = 0,
  outerRadius = 80,
  startAngle = -270,
  endAngle = -630,
  showLegend = true,
  showTooltip = true,
  tooltipProps,
  legendProps,
  pieProps,
  tooltipContent,
  legendContent,
  className,
  activeShapeIndex,
  showTooltipOnLegendHover = false,
}: PieChartProps) {
  const chartLabel = ariaLabel ?? 'Pie Chart';
  const dataWithFallback = data.map((entry, index) => {
    const paletteIndex = index % FALLBACK_PALETTE.length;
    const fallbackClassName = entry.color
      ? undefined
      : FALLBACK_PALETTE[paletteIndex];
    const fill = entry.color ?? FALLBACK_PALETTE_COLORS[paletteIndex];

    return {
      ...entry,
      className: entry.className ?? fallbackClassName,
      fill,
    };
  });

  const { ref, tooltipPos } = useTooltipPosition({
    activeShapeIndex,
    showTooltipOnLegendHover,
    getActiveShapeElement: getPieElement,
    calculatePosition: pieChartPositionCalculator,
  });

  return (
    <ResponsiveContainer
      height={height}
      className={cx('w-full', className)}
      ref={ref}
    >
      <RechartsPieChart
        role="img"
        aria-label={chartLabel}
      >
        {showLegend && (
          <Legend
            iconType="circle"
            content={legendContent ?? ChartLegendContent}
            {...legendProps}
          />
        )}

        {showTooltip && (
          <Tooltip
            content={tooltipContent ?? ChartTooltipContent}
            {...tooltipProps}
            {...(activeShapeIndex !== undefined && showTooltipOnLegendHover
              ? {
                  wrapperStyle: {
                    visibility: 'visible',
                    transition: 'transform 400ms ease',
                    transform: `translate(${tooltipPos.x}px, ${tooltipPos.y}px)`,
                  },
                }
              : {})}
          />
        )}

        <Pie
          isAnimationActive={false}
          startAngle={startAngle}
          endAngle={endAngle}
          stroke="none"
          data={dataWithFallback}
          dataKey="value"
          nameKey="name"
          fill="currentColor"
          innerRadius={innerRadius}
          outerRadius={outerRadius}
          shape={(props) => {
            return renderActiveShape({ ...props, activeShapeIndex });
          }}
          {...pieProps}
        />
      </RechartsPieChart>
    </ResponsiveContainer>
  );
}
