import type { ReactNode, Ref } from 'react';
import React, { useCallback, useLayoutEffect, useRef } from 'react';
import type {
  InputRenderProps,
  TextAreaProps as AriaTextAreaProps,
  TextFieldProps as AriaTextFieldProps,
} from 'react-aria-components';
import { TextArea as AriaTextArea } from 'react-aria-components';
import { TextField } from '@/components/atoms/Input/base/input';
import { cx } from '@/utils/cx';
import { ROW_HEIGHT_PX } from '@/utils/rowHeight';
import { WithDataId } from '@/types/withDataId';
import { FieldWrapper } from '@/components/molecules/FieldWrapper';
import { FieldWrapperProps } from '@/components/molecules/FieldWrapper/FieldWrapper';

// Creates a data URL for an SVG resize handle with a given color.
const getResizeHandleBg = (color: string) => {
  return `url(data:image/svg+xml;base64,${btoa(`<svg width="18" height="18" viewBox="0 0 18 18" fill="none" xmlns="http://www.w3.org/2000/svg"><path d="M10 2L2 10" stroke="${color}" stroke-linecap="round"/><path d="M11 7L7 11" stroke="${color}" stroke-linecap="round"/></svg>`)})`;
};

const resizeHandleStyle = {
  '--resize-handle-bg': getResizeHandleBg('#D5D7DA'),
  '--resize-handle-bg-dark': getResizeHandleBg('#373A41'),
} as React.CSSProperties;

interface AutoGrowProps {
  /**
   * When true, disables the textarea resize handle so the height is fixed.
   */
  disableResize?: boolean;
  /**
   * When true, the textarea auto-resizes to fit its content (via CSS
   * `field-sizing: content`). Defaults to `false` — height is fixed at the
   * native `rows` value (or `min-h-32` in framed mode) and the user must
   * drag the resize handle to grow.
   *
   * Starts at one row; pass `rows` for a larger initial / minimum height.
   * (Unlike `TextEditor`, no separate `minRows` prop is needed because the
   * underlying `<textarea>` already exposes `rows` as the minimum.)
   */
  autoGrow?: boolean;
  /**
   * When combined with `autoGrow`, caps the textarea height at `maxRows`
   * worth of text. Content beyond that scrolls within the textarea.
   * No-op when `autoGrow` is false.
   */
  maxRows?: number;
}

interface TextAreaBaseProps
  extends
    AriaTextAreaProps,
    Omit<FieldWrapperProps, 'children'>,
    AutoGrowProps {
  ref?: Ref<HTMLTextAreaElement>;
}

// 24px covers the textarea's `py-3` vertical padding (12 + 12).
const TEXTAREA_PADDING_PX = 24;

/**
 * Exported for the colocated spec to assert against the same formula.
 * Not part of the public package API — not re-exported from `index.ts`.
 */
export const textAreaRowsToPx = (rows: number) =>
  rows * ROW_HEIGHT_PX + TEXTAREA_PADDING_PX;

// Detect browsers without native CSS `field-sizing: content` support. Modern
// Chrome/Safari and Firefox 134+ handle auto-grow purely via CSS; older Firefox
// needs a JS fallback to resize the textarea as the user types.
const supportsFieldSizing = () =>
  typeof CSS !== 'undefined' &&
  typeof CSS.supports === 'function' &&
  CSS.supports('field-sizing', 'content');

export const TextAreaBase = ({
  isInvalid,
  className,
  disableResize,
  autoGrow,
  maxRows,
  rows,
  ref,
  ...props
}: TextAreaBaseProps) => {
  const internalRef = useRef<HTMLTextAreaElement | null>(null) as {
    current: HTMLTextAreaElement | null;
  };

  const setRef = useCallback(
    (el: HTMLTextAreaElement | null) => {
      internalRef.current = el;
      if (typeof ref === 'function') {
        ref(el);
      } else if (ref) {
        (ref as { current: HTMLTextAreaElement | null }).current = el;
      }
    },
    [ref],
  );

  const resize = useCallback(() => {
    if (!autoGrow || supportsFieldSizing()) return;
    const el = internalRef.current;
    if (!el) return;
    const maxHeight =
      maxRows !== undefined ? textAreaRowsToPx(maxRows) : Infinity;
    el.style.height = 'auto';
    el.style.height = `${Math.min(el.scrollHeight, maxHeight)}px`;
  }, [autoGrow, maxRows]);

  useLayoutEffect(() => {
    if (!autoGrow || supportsFieldSizing()) return;
    const el = internalRef.current;
    if (!el) return;
    el.addEventListener('input', resize);
    return () => el.removeEventListener('input', resize);
  }, [autoGrow, resize]);

  // Re-run on every commit so programmatic `value`/`defaultValue` changes
  // resize the textarea — the `input` listener only fires for user edits.
  // Deps deliberately omitted: when used inside `TextField`, value flows via
  // React-Aria context (not as a prop on `TextAreaBase`), so we can't gate on
  // a specific value/defaultValue dep — re-running on every commit is the
  // simplest way to stay correct in both standalone and TextField use.
  useLayoutEffect(() => {
    resize();
  });

  // Inline `max-height` (rather than a CSS variable as in `TextEditor`)
  // because the textarea is itself the resizable surface — no intermediate
  // contenteditable to hand the value to.
  const maxHeightStyle =
    autoGrow && maxRows !== undefined
      ? { maxHeight: `${textAreaRowsToPx(maxRows)}px` }
      : undefined;

  return (
    <AriaTextArea
      {...props}
      ref={setRef}
      rows={autoGrow ? (rows ?? 1) : rows}
      style={{ ...resizeHandleStyle, ...maxHeightStyle }}
      className={(state) =>
        cx(
          'w-full scroll-py-3 rounded-lg bg-primary px-3.5 py-3 text-md text-primary shadow-xs ring-1 ring-primary transition duration-100 ease-linear ring-inset placeholder:text-placeholder autofill:rounded-lg autofill:text-primary focus:outline-hidden',

          // Auto-grow: textarea sizes to its content (rows acts as a minimum).
          // Falls back to native fixed-row behavior in browsers without
          // CSS `field-sizing` support (Firefox).
          autoGrow && 'field-sizing-content',

          // Resize handle
          '[&::-webkit-resizer]:bg-(image:--resize-handle-bg) [&::-webkit-resizer]:bg-contain dark:[&::-webkit-resizer]:bg-(image:--resize-handle-bg-dark)',

          state.isFocused && !state.isDisabled && 'ring-2 ring-brand',
          state.isDisabled &&
            'cursor-not-allowed bg-disabled_subtle text-disabled ring-disabled',
          isInvalid && 'ring-error_subtle',
          isInvalid && state.isFocused && 'ring-2 ring-error',
          disableResize && 'resize-none',

          typeof className === 'function' ? className(state) : className,
        )
      }
    />
  );
};

TextAreaBase.displayName = 'TextAreaBase';

interface TextFieldProps
  extends
    AriaTextAreaProps,
    WithDataId,
    Omit<FieldWrapperProps, 'children'>,
    AutoGrowProps {
  ref?: Ref<HTMLDivElement>;
  isDisabled?: AriaTextFieldProps['isDisabled'];
  isReadOnly?: AriaTextFieldProps['isReadOnly'];
  wrapperClassName?: AriaTextFieldProps['className'];
  /**
   * Custom content rendered above the textarea inside a shared bordered frame.
   * Note: when slots are present, the textarea fills the frame via flex layout
   * and the `rows` attribute is ignored — drag the resize handle to grow.
   */
  headerSlot?: ReactNode;
  /**
   * Custom content rendered below the textarea inside a shared bordered frame.
   * Note: when slots are present, the textarea fills the frame via flex layout
   * and the `rows` attribute is ignored — drag the resize handle to grow.
   */
  footerSlot?: ReactNode;
}

export const TextArea = ({
  label,
  hint,
  wrapperClassName,
  isDisabled,
  isInvalid,
  isRequired,
  isReadOnly,
  tooltip,
  value,
  defaultValue,
  ref,
  labelPosition,
  alignLabel,
  fieldSize,
  description,
  headerSlot,
  footerSlot,
  disableResize,
  autoGrow = false,
  maxRows,
  ...textAreaProps
}: TextFieldProps) => {
  const { 'aria-label': ariaLabel, ...restTextAreaProps } = textAreaProps;
  const isFramed = !!(headerSlot || footerSlot);
  const userClassName = restTextAreaProps.className;

  return (
    <FieldWrapper
      label={label}
      isRequired={isRequired}
      tooltip={tooltip}
      isInvalid={isInvalid}
      hint={hint}
      labelPosition={labelPosition}
      alignLabel={alignLabel}
      fieldSize={fieldSize}
      description={description}
    >
      <TextField
        {...{
          ref,
          isDisabled,
          isInvalid,
          isReadOnly,
          isRequired,
          className: wrapperClassName,
          'aria-label': ariaLabel,
        }}
        value={value as string}
        defaultValue={defaultValue as string}
      >
        {({ isInvalid: fieldIsInvalid }) => {
          if (!isFramed) {
            return (
              <TextAreaBase
                isInvalid={fieldIsInvalid}
                disableResize={disableResize}
                autoGrow={autoGrow}
                maxRows={maxRows}
                {...restTextAreaProps}
              />
            );
          }

          const framedAreaClassName = (
            state: InputRenderProps & {
              defaultClassName: string | undefined;
            },
          ) =>
            cx(
              autoGrow ? '' : 'min-h-0 flex-1',
              'resize-none rounded-none border-0 shadow-none ring-0 focus:ring-0',
              typeof userClassName === 'function'
                ? userClassName(state)
                : userClassName,
            );

          return (
            <div
              style={autoGrow ? undefined : resizeHandleStyle}
              className={cx(
                'flex w-full flex-col overflow-hidden rounded-lg border border-primary bg-primary shadow-xs',
                'focus-within:border-brand focus-within:ring-1 focus-within:ring-brand',
                fieldIsInvalid &&
                  'border-error_subtle focus-within:border-error focus-within:ring-error',
                isDisabled &&
                  'cursor-not-allowed border-disabled bg-disabled_subtle',
                !autoGrow && [
                  'min-h-32',
                  'resize-y',
                  '[&::-webkit-resizer]:bg-(image:--resize-handle-bg) [&::-webkit-resizer]:bg-contain dark:[&::-webkit-resizer]:bg-(image:--resize-handle-bg-dark)',
                  isDisabled && 'resize-none',
                  disableResize && 'resize-none',
                ],
              )}
            >
              {headerSlot && (
                <div className="flex items-center px-3.5 pt-3">
                  {headerSlot}
                </div>
              )}
              <TextAreaBase
                isInvalid={fieldIsInvalid}
                autoGrow={autoGrow}
                maxRows={maxRows}
                {...restTextAreaProps}
                className={framedAreaClassName}
              />
              {footerSlot && (
                <div className="flex items-center px-3.5 pb-3">
                  {footerSlot}
                </div>
              )}
            </div>
          );
        }}
      </TextField>
    </FieldWrapper>
  );
};

TextArea.displayName = 'TextArea';
