import { useCallback, useEffect, useLayoutEffect, useState } from 'react';
import type { RefObject } from 'react';

export function useOverflowCount(
  containerRef: RefObject<HTMLDivElement | null>,
  itemCount: number,
  gap = 6,
) {
  const [visibleCount, setVisibleCount] = useState(itemCount);

  const measure = useCallback(() => {
    const container = containerRef.current;
    if (!container) {
      setVisibleCount(0);
      return;
    }

    const allChildren = Array.from(container.children) as HTMLElement[];
    // Only measure item (badge) children — the container may also hold the
    // overflow "+N" indicator as a trailing child, which shouldn't be counted.
    const children = allChildren.slice(0, itemCount);
    if (children.length === 0) {
      setVisibleCount(0);
      return;
    }

    const totalWidth = container.clientWidth;

    const badgeWidth = 36;

    // First pass: do all items fit without a badge?
    let usedWidth = 0;
    let allFit = true;
    for (let i = 0; i < children.length; i++) {
      usedWidth += children[i].scrollWidth + (i > 0 ? gap : 0);
      if (usedWidth > totalWidth) {
        allFit = false;
        break;
      }
    }

    if (allFit) {
      setVisibleCount(children.length);
      return;
    }

    // Second pass: reserve badge space and count how many fit
    const availableForItems = totalWidth - badgeWidth - gap;
    usedWidth = 0;
    let count = 0;
    for (let i = 0; i < children.length; i++) {
      const nextUsed = usedWidth + children[i].scrollWidth + (i > 0 ? gap : 0);
      if (nextUsed <= availableForItems + 1) {
        count++;
        usedWidth = nextUsed;
      } else {
        break;
      }
    }

    setVisibleCount(Math.max(1, count));
  }, [containerRef, gap, itemCount]);

  useLayoutEffect(() => {
    measure();
  }, [measure, itemCount]);

  useEffect(() => {
    const parent = containerRef.current?.parentElement;
    if (!parent) return;

    const observer = new ResizeObserver(measure);
    observer.observe(parent);
    return () => observer.disconnect();
  }, [containerRef, measure]);

  const hiddenCount = Math.max(0, itemCount - visibleCount);
  return { visibleCount, hiddenCount };
}
