import { cx } from './cx';

type ClassValue =
  | string
  | number
  | boolean
  | undefined
  | null
  | ClassValue[]
  | Record<string, boolean | string | number | undefined | null>;

function classNames(...args: ClassValue[]): string {
  const classes: string[] = [];

  for (let i = 0; i < args.length; i += 1) {
    const arg = args[i];
    if (!arg) continue;

    const argType = typeof arg;

    // TODO: class names cannot begin with numbers
    if (argType === 'string' || argType === 'number') {
      classes.push(String(arg));
    } else if (Array.isArray(arg) && arg.length) {
      const inner = classNames.call(null, ...arg);
      if (inner) {
        classes.push(inner);
      }
    } else if (argType === 'object') {
      Object.entries(arg).forEach((c) => {
        const [key, value] = c;
        if (value) {
          classes.push(key);
        }
      });
    }
  }

  // Use tailwind-merge to resolve conflicts in the final class string
  return cx(classes.join(' '));
}

export { classNames };
export type { ClassValue };
