import { isValidElement, ReactNode } from 'react';
import { Check } from '@/icons';
import type {
  ListBoxItemProps as AriaListBoxItemProps,
  ListBoxItemRenderProps,
} from 'react-aria-components';
import {
  ListBoxItem as AriaListBoxItem,
  Text as AriaText,
} from 'react-aria-components';
import { Avatar } from '@/vendor/untitled-ui/base/avatar/avatar';
import { cx } from '@/utils/cx';
import { isReactComponent } from '@/utils/is-react-component';
import type { SelectItemType } from './baseTypes';

export interface SelectItemProps
  extends Omit<AriaListBoxItemProps<SelectItemType>, 'id'>, SelectItemType {
  action?: React.ReactNode;
  selectedClassName?: string;
  renderItem?: (values: ListBoxItemRenderProps) => ReactNode;
}

export const SelectItem = ({
  label,
  id,
  value,
  avatarUrl,
  supportingText,
  isDisabled,
  icon: Icon,
  className,
  children,
  action,
  selectedClassName,
  renderItem = undefined,
  ...props
}: SelectItemProps) => {
  const labelOrChildren =
    (typeof label === 'string' ? label : '') ||
    (typeof children === 'string' ? children : '');
  const textValue = supportingText
    ? labelOrChildren + ' ' + supportingText
    : labelOrChildren;

  return (
    <AriaListBoxItem
      id={id}
      value={
        value ?? {
          id,
          label: labelOrChildren,
          avatarUrl,
          supportingText,
          isDisabled,
          icon: Icon,
        }
      }
      textValue={textValue}
      isDisabled={isDisabled}
      {...props}
      className={(state) =>
        cx(
          'w-full px-1.5 py-px outline-hidden',
          typeof className === 'function' ? className(state) : className,
        )
      }
    >
      {(state) => (
        <div
          className={cx(
            'flex cursor-pointer items-center gap-2 rounded-md outline-hidden select-none p-2 pr-2.5',
            state.isSelected && (selectedClassName || 'bg-active'),
            state.isDisabled && 'cursor-not-allowed',
            state.isFocusVisible &&
              'bg-primary_hover ring-2 ring-focus-ring ring-inset',

            // Icon styles
            '*:data-icon:size-4 *:data-icon:shrink-0 *:data-icon:text-fg-quaternary',
            state.isDisabled && '*:data-icon:text-fg-disabled',
          )}
        >
          {renderItem && renderItem(state)}
          {!renderItem && (
            <>
              {avatarUrl ? (
                <Avatar
                  aria-hidden="true"
                  size="xs"
                  src={avatarUrl}
                  alt={typeof label === 'string' ? label : ''}
                />
              ) : isReactComponent(Icon) ? (
                <Icon
                  data-icon
                  aria-hidden="true"
                />
              ) : isValidElement(Icon) ? (
                Icon
              ) : null}

              <div className="flex w-full min-w-0 flex-1 flex-wrap gap-x-2">
                <AriaText
                  slot="label"
                  className={cx(
                    'truncate text-sm font-medium whitespace-nowrap text-primary',
                    state.isDisabled && 'text-disabled',
                  )}
                >
                  {label ||
                    (typeof children === 'function'
                      ? children(state)
                      : children)}
                </AriaText>

                {supportingText && (
                  <AriaText
                    slot="description"
                    className={cx(
                      'text-sm whitespace-nowrap text-tertiary',
                      state.isDisabled && 'text-disabled',
                    )}
                  >
                    {supportingText}
                  </AriaText>
                )}
              </div>

              {action ??
                (state.isSelected && (
                  <Check
                    aria-hidden="true"
                    className={cx(
                      'ml-auto size-4 stroke-[2.5px] text-fg-brand-primary',
                      state.isDisabled && 'text-fg-disabled',
                    )}
                  />
                ))}
            </>
          )}
        </div>
      )}
    </AriaListBoxItem>
  );
};
