import { useEffect, useMemo, useRef } from 'react';
import { Input } from '@/components/atoms/Input';
import { cx } from '@/utils/cx';
import { useTemplaterBackdrop } from './_hooks';
import { formatTemplate, highlightTemplateVars } from './_utils';
import { TemplaterMenu } from './TemplaterMenu';
import type { ChangeEvent, ElementType } from 'react';
import type { TemplaterProps } from './_types';

export function Templater<C extends ElementType = typeof Input>({
  component,
  templateItems,
  value = '',
  onChange,
  onBlur,
  className,
  isReadOnly,
  isDisabled,
  isInvalid,
  triggerClassName,
  menuTopPos = 'top-1',
  menuRightPos = 'right-1',
  isFormatTemplateItems = true,
  'data-id': dataId,
  ...rest
}: TemplaterProps<C>) {
  const InputComponent = (component ?? Input) as ElementType;
  const showTrigger = !isReadOnly && !isDisabled;

  const containerRef = useRef<HTMLDivElement>(null);
  const backdropRef = useTemplaterBackdrop(containerRef);

  // Highlight whatever string actually gets inserted: when isFormatTemplateItems
  // is true items are wrapped as {{item}}, otherwise they're already pre-wrapped
  // (e.g. callers pass `{{name}}` directly), so we use them as-is for matching.
  const validKeywords = useMemo(
    () =>
      new Set(
        isFormatTemplateItems
          ? templateItems.map((item) => formatTemplate(item))
          : templateItems,
      ),
    [templateItems, isFormatTemplateItems],
  );

  // Update backdrop HTML directly — bypasses React diffing for snappy paint
  useEffect(() => {
    if (!backdropRef.current) return;
    backdropRef.current.innerHTML = highlightTemplateVars(
      value ?? '',
      validKeywords,
    );
  }, [value, validKeywords, backdropRef]);

  // Normalize: react-aria's TextField onChange yields a string, while a raw
  // textarea/input onChange yields a ChangeEvent.
  // Support both so the component works with Input and TextArea (and similar) without adapters.
  const handleInputChange = (
    next: string | ChangeEvent<HTMLInputElement | HTMLTextAreaElement>,
  ) => {
    if (typeof next === 'string') {
      onChange?.(next);
      return;
    }

    if (next && typeof next === 'object' && 'target' in next) {
      onChange?.((next.target as HTMLInputElement | HTMLTextAreaElement).value);
    }
  };

  const handleSelect = (item: string) => {
    const inserted = isFormatTemplateItems ? formatTemplate(item) : item;
    onChange?.(`${value ?? ''}${inserted}`);
  };

  return (
    <div
      ref={containerRef}
      className={cx(
        'relative w-full',
        // Hide the underlying field's text so the backdrop's styled HTML shows
        // through. The caret stays visible.
        '[&_input]:!text-transparent [&_textarea]:!text-transparent',
        '[&_input]:caret-fg-brand-primary [&_textarea]:caret-fg-brand-primary',
        className,
      )}
    >
      <InputComponent
        {...rest}
        isReadOnly={isReadOnly}
        isDisabled={isDisabled}
        isInvalid={isInvalid}
        value={value}
        onChange={handleInputChange}
        onBlur={onBlur}
        data-id={`${dataId}-input`}
      />

      {/* Rendered AFTER the input so it paints on top in document order.
       * The Input wrapper uses position:relative (z-auto), which sits in the
       * same painting layer as a z-0 backdrop — without this ordering it
       * would obscure the backdrop. */}
      <div
        ref={backdropRef}
        aria-hidden
        className="pointer-events-none absolute z-0 overflow-hidden text-md text-primary"
      />

      {showTrigger && (
        <div className={cx('absolute z-10', menuTopPos, menuRightPos)}>
          <TemplaterMenu
            data-id={dataId}
            templateItems={templateItems}
            onSelect={handleSelect}
            className={triggerClassName}
            isFormatTemplateItems={isFormatTemplateItems}
          />
        </div>
      )}
    </div>
  );
}
