import { useCallback, useMemo, useRef, useState } from 'react';
import { ParagraphSpacing } from '@untitledui/icons/ParagraphSpacing';
import { Lock01 } from '@untitledui/icons/Lock01';
import { Pin01 } from '@untitledui/icons/Pin01';
import { cx } from '@/utils/cx';

import { TableRow, ColDef } from './_types';

export type ColumnId = string | number;

function sortByOrder<TData extends TableRow>(
  cols: ColDef<TData>[],
  columnOrder?: Record<ColumnId, number>,
): ColDef<TData>[] {
  if (!columnOrder || Object.keys(columnOrder).length === 0) return cols;
  return [...cols].sort((a, b) => {
    const aOrder =
      a.id != null && a.id in columnOrder ? columnOrder[a.id] : Infinity;
    const bOrder =
      b.id != null && b.id in columnOrder ? columnOrder[b.id] : Infinity;
    return aOrder - bOrder;
  });
}

function buildOrderMap(ids: ColumnId[]): Record<ColumnId, number> {
  const map: Record<ColumnId, number> = {};
  ids.forEach((id, i) => {
    map[id] = i;
  });
  return map;
}

function SelectedColumnItem<TData extends TableRow>({
  column,
  isPinned,
  onDragStart,
  onDragOver,
  onDrop,
  onDragEnd,
  onKeyDown,
  isDragOver,
  dropSide,
  isDragging,
  dataId,
}: {
  column: ColDef<TData>;
  isPinned: boolean;
  onDragStart: (e: React.DragEvent) => void;
  onDragOver: (e: React.DragEvent) => void;
  onDrop: (e: React.DragEvent) => void;
  onDragEnd: (e: React.DragEvent) => void;
  onKeyDown?: (e: React.KeyboardEvent) => void;
  isDragOver: boolean;
  dropSide: 'top' | 'bottom' | null;
  isDragging: boolean;
  dataId: string | undefined;
}) {
  return (
    <div
      tabIndex={isPinned ? undefined : 0}
      role={isPinned ? undefined : 'option'}
      aria-label={column.label}
      aria-roledescription={isPinned ? undefined : 'sortable'}
      className={cx(
        'relative flex items-center gap-1.5 rounded-md px-1.5 py-1 text-sm text-secondary outline-none',
        isPinned
          ? 'text-quaternary'
          : 'cursor-grab focus-visible:ring-2 focus-visible:ring-brand-solid',
        isDragging && 'opacity-40',
      )}
      draggable={!isPinned}
      onDragStart={onDragStart}
      onDragOver={onDragOver}
      onDrop={onDrop}
      onDragEnd={onDragEnd}
      onKeyDown={onKeyDown}
      data-id={`${dataId}-${isPinned ? 'pinned' : 'reorderable'}-${column.id}`}
      {...(!isPinned ? { 'data-reorderable': '' } : {})}
    >
      {isDragOver && dropSide === 'top' && (
        <div className="absolute top-0 right-1 left-1 h-0.5 -translate-y-1/2 rounded-full bg-brand-solid" />
      )}
      {isPinned ? (
        <Lock01 className="size-4 shrink-0 text-fg-quaternary" />
      ) : (
        <ParagraphSpacing className="size-4 shrink-0 text-fg-quaternary" />
      )}
      <span className="flex-1 truncate">{column.label}</span>
      {isPinned && <Pin01 className="size-4 shrink-0 text-fg-quaternary" />}
      {isDragOver && dropSide === 'bottom' && (
        <div className="absolute bottom-0 right-1 left-1 h-0.5 translate-y-1/2 rounded-full bg-brand-solid" />
      )}
    </div>
  );
}

export function SelectedColumnsPanel<TData extends TableRow>({
  columns,
  columnOrder,
  onColumnOrderChange,
  texts,
  dataId,
}: {
  columns: ColDef<TData>[];
  columnOrder?: Record<ColumnId, number>;
  onColumnOrderChange?: (newOrder: Record<ColumnId, number>) => void;
  texts: { columnsSelector: Record<string, string> };
  dataId: string | undefined;
}) {
  const [draggedId, setDraggedId] = useState<ColumnId | null>(null);
  const [dragOverId, setDragOverId] = useState<ColumnId | null>(null);
  const [dropSide, setDropSide] = useState<'top' | 'bottom' | null>(null);

  const ordered = useMemo(
    () => sortByOrder(columns, columnOrder),
    [columns, columnOrder],
  );

  const pinnedLeft = ordered.filter((c) => c.pinned === 'left');
  const pinnedRight = ordered.filter((c) => c.pinned === 'right');
  const reorderable = ordered.filter((c) => !c.pinned);

  const handleDragStart = useCallback(
    (columnId: ColumnId) => (e: React.DragEvent) => {
      e.dataTransfer.effectAllowed = 'move';
      e.dataTransfer.setData('text/plain', String(columnId));
      setDraggedId(columnId);
    },
    [],
  );

  const handleDragOver = useCallback(
    (columnId: ColumnId) => (e: React.DragEvent) => {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';

      const rect = e.currentTarget.getBoundingClientRect();
      const midpoint = rect.top + rect.height / 2;
      setDropSide(e.clientY < midpoint ? 'top' : 'bottom');
      setDragOverId(columnId);
    },
    [],
  );

  const handleDrop = useCallback(
    (targetId: ColumnId) => (e: React.DragEvent) => {
      e.preventDefault();

      if (draggedId == null || draggedId === targetId) {
        setDraggedId(null);
        setDragOverId(null);
        setDropSide(null);
        return;
      }

      const ids = reorderable
        .map((c) => c.id)
        .filter((id): id is ColumnId => id != null);
      const withoutDragged = ids.filter((id) => id !== draggedId);
      const targetIndex = withoutDragged.indexOf(targetId);
      if (targetIndex === -1) {
        setDraggedId(null);
        setDragOverId(null);
        setDropSide(null);
        return;
      }

      const rect = e.currentTarget.getBoundingClientRect();
      const midpoint = rect.top + rect.height / 2;
      const insertAfter = e.clientY >= midpoint;
      const insertIndex = insertAfter ? targetIndex + 1 : targetIndex;
      withoutDragged.splice(insertIndex, 0, draggedId);

      onColumnOrderChange?.(buildOrderMap(withoutDragged));
      setDraggedId(null);
      setDragOverId(null);
      setDropSide(null);
    },
    [draggedId, reorderable, onColumnOrderChange],
  );

  const handleDragEnd = useCallback(() => {
    setDraggedId(null);
    setDragOverId(null);
    setDropSide(null);
  }, []);

  const noopDrag = useCallback((e: React.DragEvent) => {
    e.preventDefault();
  }, []);

  const listRef = useRef<HTMLDivElement>(null);

  const handleKeyboardReorder = useCallback(
    (columnId: ColumnId, e: React.KeyboardEvent) => {
      if (e.key !== 'ArrowUp' && e.key !== 'ArrowDown') return;
      e.preventDefault();

      const ids = reorderable
        .map((c) => c.id)
        .filter((id): id is ColumnId => id != null);
      const currentIndex = ids.indexOf(columnId);
      if (currentIndex === -1) return;

      const swapIndex =
        e.key === 'ArrowUp' ? currentIndex - 1 : currentIndex + 1;
      if (swapIndex < 0 || swapIndex >= ids.length) return;

      const newIds = [...ids];
      [newIds[currentIndex], newIds[swapIndex]] = [
        newIds[swapIndex],
        newIds[currentIndex],
      ];
      onColumnOrderChange?.(buildOrderMap(newIds));

      // Restore focus to the moved item after React re-renders
      requestAnimationFrame(() => {
        const items =
          listRef.current?.querySelectorAll<HTMLElement>('[data-reorderable]');
        items?.[swapIndex]?.focus();
      });
    },
    [reorderable, onColumnOrderChange],
  );

  return (
    <div className="flex flex-col">
      <div className="px-3 py-2 text-xs font-semibold text-quaternary">
        {texts.columnsSelector.selectedColumnsLabel}
      </div>
      <div
        ref={listRef}
        className="flex-1 overflow-y-auto px-1.5 pb-2"
      >
        {pinnedLeft.map((col) =>
          col.id != null ? (
            <SelectedColumnItem
              key={col.id}
              column={col}
              isPinned
              onDragStart={noopDrag}
              onDragOver={noopDrag}
              onDrop={noopDrag}
              onDragEnd={handleDragEnd}
              isDragOver={false}
              dropSide={null}
              isDragging={false}
              dataId={`${dataId}-pinnedLeft`}
            />
          ) : null,
        )}
        {reorderable.map((col) =>
          col.id != null ? (
            <SelectedColumnItem
              key={col.id}
              column={col}
              isPinned={false}
              onDragStart={handleDragStart(col.id)}
              onDragOver={handleDragOver(col.id)}
              onDrop={handleDrop(col.id)}
              onDragEnd={handleDragEnd}
              onKeyDown={(e) => handleKeyboardReorder(col.id!, e)}
              isDragOver={dragOverId === col.id && draggedId !== col.id}
              dropSide={dragOverId === col.id ? dropSide : null}
              isDragging={draggedId === col.id}
              dataId={`${dataId}-reorderable`}
            />
          ) : null,
        )}
        {pinnedRight.map((col) =>
          col.id != null ? (
            <SelectedColumnItem
              key={col.id}
              column={col}
              isPinned
              onDragStart={noopDrag}
              onDragOver={noopDrag}
              onDrop={noopDrag}
              onDragEnd={handleDragEnd}
              isDragOver={false}
              dropSide={null}
              isDragging={false}
              dataId={`${dataId}-pinnedRight`}
            />
          ) : null,
        )}
      </div>
    </div>
  );
}
