import { InputBase } from '@/components/atoms/Input/base/input';
import { InputGroup } from '@/components/atoms/Input/base/input-group';
import { WithDataId } from '@/types/withDataId';

export type InputGroupFieldProps = Omit<
  React.ComponentPropsWithoutRef<typeof InputBase>,
  'className'
> & {
  prefix?: string;
  leadingAddon?: React.ReactNode;
  trailingAddon?: React.ReactNode;
  className?: string;
} & WithDataId;

export function InputGroupField({
  type,
  icon,
  placeholder,
  tooltip,
  shortcut,
  wrapperClassName,
  tooltipClassName,
  inputClassName,
  iconClassName,
  ...restProps
}: InputGroupFieldProps) {
  return (
    <InputGroup {...restProps}>
      <InputBase
        wrapperClassName={wrapperClassName}
        tooltipClassName={tooltipClassName}
        inputClassName={inputClassName}
        iconClassName={iconClassName}
        type={type}
        icon={icon}
        placeholder={placeholder}
        tooltip={tooltip}
        shortcut={shortcut}
      />
    </InputGroup>
  );
}
