import {
  Tooltip as BaseTooltip,
  TooltipTrigger as BaseTooltipTrigger,
} from '@/components/atoms/Tooltip/base/tooltip';
import { HelpCircle } from '@untitledui/icons';
import { ComponentPropsWithoutRef, ReactNode } from 'react';
import { WithDataId } from '@/types/withDataId';

type TooltipBaseProps = Omit<
  ComponentPropsWithoutRef<typeof BaseTooltip>,
  'children'
> & {
  triggerProps?: ComponentPropsWithoutRef<typeof BaseTooltipTrigger>;
};

type TooltipWithHelpIcon = TooltipBaseProps & {
  isHelpIconTrigger: true;
  children?: ReactNode;
} & WithDataId;

type TooltipWithChildren = TooltipBaseProps & {
  isHelpIconTrigger?: false;
  children: ReactNode;
} & WithDataId;

export type TooltipProps = TooltipWithHelpIcon | TooltipWithChildren;
export const Tooltip = ({
  children,
  isHelpIconTrigger,
  isDisabled,
  triggerProps,
  'data-id': dataId,
  ...props
}: TooltipProps) => {
  return (
    <BaseTooltip
      {...props}
      isDisabled={isDisabled || (!props.title && !props.description)}
    >
      <BaseTooltipTrigger
        {...triggerProps}
        className={
          isHelpIconTrigger
            ? 'cursor-pointer text-fg-quaternary transition duration-100 ease-linear hover:text-fg-quaternary_hover focus:text-fg-quaternary_hover'
            : (triggerProps?.className ?? '')
        }
        data-id={dataId}
      >
        {isHelpIconTrigger ? <HelpCircle size={16} /> : children}
      </BaseTooltipTrigger>
    </BaseTooltip>
  );
};

export const TooltipBase = ({
  isDisabled,
  ...props
}: ComponentPropsWithoutRef<typeof BaseTooltip>) => {
  return (
    <BaseTooltip
      {...props}
      isDisabled={isDisabled || (!props.title && !props.description)}
    />
  );
};
