import * as React from 'react';

type TooltipPosition = { x: number; y: number };

type PositionCalculator = (
  shapeRect: DOMRect,
  chartRect: DOMRect,
  tooltipRect: DOMRect,
) => TooltipPosition;

type UseTooltipPositionOptions = {
  /** Index of the active shape */
  activeShapeIndex?: number;
  /** Whether to show tooltip on legend hover */
  showTooltipOnLegendHover: boolean;
  /** Function to find the active shape element within the container */
  getActiveShapeElement: (
    container: HTMLDivElement,
    index: number,
  ) => Element | null;
  /** Function to calculate tooltip position from element rects */
  calculatePosition: PositionCalculator;
};

/**
 * Hook to calculate tooltip position for chart legend hover interactions.
 * Returns a ref to attach to the chart container and the calculated tooltip position.
 */
export function useTooltipPosition({
  activeShapeIndex,
  showTooltipOnLegendHover,
  getActiveShapeElement,
  calculatePosition,
}: UseTooltipPositionOptions) {
  const ref = React.useRef<HTMLDivElement>(null);
  const [tooltipPos, setTooltipPos] = React.useState<TooltipPosition>({
    x: 0,
    y: 0,
  });

  React.useLayoutEffect(() => {
    if (
      activeShapeIndex !== undefined &&
      showTooltipOnLegendHover &&
      ref.current
    ) {
      const activeShapeEl = getActiveShapeElement(
        ref.current,
        activeShapeIndex,
      );
      const chartRect = ref.current.getBoundingClientRect();
      const activeShapeRect = activeShapeEl?.getBoundingClientRect();
      const tooltipRect = ref.current
        .querySelector('.recharts-tooltip-wrapper')
        ?.getBoundingClientRect();

      if (activeShapeRect && chartRect && tooltipRect) {
        setTooltipPos(
          calculatePosition(activeShapeRect, chartRect, tooltipRect),
        );
      }
    }
  }, [
    activeShapeIndex,
    showTooltipOnLegendHover,
    getActiveShapeElement,
    calculatePosition,
  ]);

  return { ref, tooltipPos };
}

/** Position calculator for bar charts - positions at the bar's top-left corner */
export const barChartPositionCalculator: PositionCalculator = (
  shapeRect,
  chartRect,
  tooltipRect,
) => {
  const deltaX = shapeRect.x + tooltipRect.width - chartRect.right;
  const offsetX = shapeRect.x - chartRect.x;
  const adjustedOffsetX = deltaX > 0 ? offsetX - deltaX : offsetX;

  return {
    x: adjustedOffsetX,
    y: shapeRect.y - chartRect.y,
  };
};

/** Position calculator for pie charts - positions at the slice's center */
export const pieChartPositionCalculator: PositionCalculator = (
  shapeRect,
  chartRect,
  tooltipRect,
) => {
  const middleX = shapeRect.x + Math.floor(shapeRect.width / 2);
  const deltaX = middleX + tooltipRect.width - chartRect.right;
  const offsetX = middleX - chartRect.x;
  const adjustedX = deltaX > 0 ? offsetX - deltaX : offsetX;

  return {
    x: adjustedX,
    y: shapeRect.y + Math.floor(shapeRect.height / 2) - chartRect.y,
  };
};

/** Gets bar element by index using recharts-rectangle class */
export const getBarElement = (container: HTMLDivElement, index: number) =>
  container.querySelectorAll('.recharts-rectangle')[index] ?? null;

/** Gets pie slice element by index using data attribute */
export const getPieElement = (container: HTMLDivElement, index: number) =>
  container.querySelector(`[data-recharts-item-index="${index}"]`);
