import { ContentDivider } from '@/components/atoms/ContentDivider';
import {
  type Message,
  MessageItem as BaseMessageItem,
} from '@/vendor/untitled-ui/application/messaging/messaging';
import { MessageActionButton } from './MessageActionButton';
import { ComponentPropsWithRef } from 'react';

export type MessageItem = Message;

export type MessageItemProps = Omit<
  ComponentPropsWithRef<typeof BaseMessageItem>,
  'msg'
>;

export type MessagesListProps = {
  todaysMessages?: MessageItem[];
  olderMessages?: MessageItem[];
  todaysMessagesDividerLabel: string;
} & MessageItemProps;

export const MessagesList = ({
  todaysMessages,
  olderMessages,
  todaysMessagesDividerLabel,
  ...messageItemProps
}: MessagesListProps) => {
  return (
    <ol className="flex h-full flex-col gap-4 overflow-y-auto px-4 py-6 md:px-6 [&::-webkit-scrollbar]:w-2 [&::-webkit-scrollbar-track]:rounded-full [&::-webkit-scrollbar-track]:bg-primary">
      {olderMessages &&
        olderMessages.map((msg) => (
          <BaseMessageItem
            key={msg.id}
            msg={msg}
            {...messageItemProps}
          />
        ))}
      {todaysMessages && (
        <>
          <ContentDivider
            data-id="messaging-today-divider"
            className="my-4"
          >
            {todaysMessagesDividerLabel}
          </ContentDivider>

          {todaysMessages.map((msg) => (
            <BaseMessageItem
              key={msg.id}
              msg={msg}
              {...messageItemProps}
            />
          ))}
        </>
      )}
    </ol>
  );
};

MessagesList.MessageButton = MessageActionButton;
