import { type ReactNode } from 'react';
import { cx } from '@/utils/cx';

export interface ContentDividerProps extends React.ComponentProps<'div'> {
  children?: ReactNode;
  className?: string;
}

export function ContentDivider({
  children,
  className,
  ...rest
}: ContentDividerProps) {
  if (!children) {
    return (
      <div
        className={cx('h-px w-full bg-border-secondary', className)}
        {...rest}
      />
    );
  }

  return (
    <div
      className={cx('flex w-full shrink-0 items-center gap-x-2', className)}
      {...rest}
    >
      <div className="h-px flex-1 bg-border-secondary" />
      <span className="text-sm text-tertiary">{children}</span>
      <div className="h-px flex-1 bg-border-secondary" />
    </div>
  );
}
