import { forwardRef } from 'react';
import { SearchLg } from '@untitledui/icons';
import { Input } from '@/components/atoms/Input/base/input';
import { type InputFieldProps } from './InputField';

export type InputSearchFieldProps = Omit<InputFieldProps, 'icon'>;

export const InputSearchField = forwardRef<
  HTMLInputElement,
  InputSearchFieldProps
>((props, ref) => {
  return (
    <Input
      {...props}
      icon={SearchLg}
      ref={ref}
    />
  );
});

InputSearchField.displayName = 'InputSearchField';
