import { InputBase } from '@/components/atoms/Input/base/input';
import { InputGroup } from '@/components/atoms/Input/base/input-group';
import { WithDataId } from '@/types/withDataId';
import { FieldWrapper } from '@/components/molecules/FieldWrapper';
import { FieldWrapperProps } from '@/components/molecules/FieldWrapper/FieldWrapper';

export type InputWebsiteFieldProps = Omit<
  React.ComponentPropsWithoutRef<typeof InputBase>,
  'className'
> &
  WithDataId &
  Omit<FieldWrapperProps, 'children'>;

export function InputWebsiteField({
  placeholder,
  shortcut,
  label,
  hint,
  isInvalid,
  isRequired,
  tooltip,
  description,
  id = '',
  labelPosition = 'left',
  ...restProps
}: InputWebsiteFieldProps) {
  return (
    <FieldWrapper
      id={id}
      label={label}
      hint={hint}
      isInvalid={isInvalid}
      isRequired={isRequired}
      tooltip={tooltip}
      description={description}
      labelPosition={labelPosition}
    >
      <InputGroup
        leadingAddon={<InputGroup.Prefix>https://</InputGroup.Prefix>}
        {...restProps}
      >
        <InputBase
          type="url"
          placeholder={placeholder}
          shortcut={shortcut}
          isInvalid={isInvalid}
        />
      </InputGroup>
    </FieldWrapper>
  );
}
