export function isEmptyObject(value: object): boolean {
  if (Array.isArray(value)) return value.length === 0;
  const keys = Object.keys(value);
  if (keys.length === 0) return true;
  return keys.every((k) => {
    const v = (value as Record<string, unknown>)[k];
    if (Array.isArray(v)) {
      return v.length === 0;
    }

    return !v;
  });
}
