import { cx } from '@/utils/cx';
import { WithDataId } from '@/types/withDataId';
import { ButtonUtility } from '@/components/atoms/ButtonUtility';
import {
  Dropdown,
  type DropdownProps,
  type DropdownSectionItem,
} from '@/components/atoms/Dropdown';
import { DotsHorizontal, XClose } from '@/icons';
import { Button } from '@/components/atoms/Button';
import { TooltipBase } from '@/components/atoms/Tooltip';

const DEFAULT_MAX_VISIBLE_ACTIONS = 3;

export type BulkActionItem = DropdownSectionItem &
  WithDataId & {
    isLoading?: boolean;
  };

export type BulkActionSection = {
  items: BulkActionItem[];
};

export interface BulkActionMenuLabels {
  /** Label for the selected count, e.g. "6 selected" */
  selected: string;
  /** Tooltip text for the close button */
  clearAll: string;
}

export interface BulkActionMenuProps
  extends WithDataId, React.ComponentProps<'div'> {
  /** Action sections matching Dropdown's sections type, extended with isLoading */
  actions: BulkActionSection[];
  /** Translatable labels */
  labels: BulkActionMenuLabels;
  /** Maximum number of visible action buttons before overflow (default: 3) */
  maxVisibleActions?: number;
  /** data-id for the overflow menu trigger */
  overflowDataId: string;
  /** data-id for the close button */
  closeDataId: string;
  /** Called when the close button is clicked */
  onClose?: () => void;
  /** Additional CSS classes */
  className?: string;
}

export function BulkActionMenu({
  actions,
  labels,
  maxVisibleActions = DEFAULT_MAX_VISIBLE_ACTIONS,
  overflowDataId,
  closeDataId,
  onClose,
  className,
  'data-id': dataId,
  ...rest
}: BulkActionMenuProps) {
  const allItems = actions.flatMap((section) => section.items);
  const visibleItems = allItems.slice(0, maxVisibleActions);
  const visibleSet = new Set(visibleItems);

  // Preserve sections structure, excluding visible items
  const overflowSections: DropdownProps['sections'] = actions
    .map((section) => ({
      items: section.items.filter((item) => !visibleSet.has(item)),
    }))
    .filter((section) => section.items.length > 0);

  const hasOverflow = overflowSections.length > 0;

  return (
    <div
      className={cx(
        'inline-flex items-center rounded-xl bg-primary-solid shadow-lg',
        className,
      )}
      role="toolbar"
      aria-label={labels.selected}
      data-id={dataId}
      {...rest}
    >
      <span className="whitespace-nowrap px-4 py-2.5 text-sm font-semibold text-white">
        {labels.selected}
      </span>

      <Divider />

      {visibleItems.map((item) => (
        <ActionButton
          key={item.label}
          item={item}
          data-id={`${dataId}-action-button-${item['data-id']}`}
        />
      ))}

      {hasOverflow && (
        <div className="flex items-center px-1 [&_button]:bg-transparent [&_button]:text-button-primary-icon [&_button]:hover:bg-white/10">
          <Dropdown
            data-id={overflowDataId}
            type="icon"
            icon={DotsHorizontal}
            placement="top"
            sections={overflowSections}
          />
        </div>
      )}

      <Divider />

      <div className="flex items-center px-1 [&_button]:bg-transparent [&_button]:text-button-primary-icon [&_button]:hover:bg-white/10">
        <ButtonUtility
          data-id={closeDataId}
          icon={XClose}
          tooltip={labels.clearAll}
          color="tertiary"
          onClick={onClose}
        />
      </div>
    </div>
  );
}

function Divider() {
  return (
    <div
      className="h-5 w-px bg-white/20"
      aria-hidden="true"
    />
  );
}

function ActionButton({
  item,
  'data-id': dataId,
}: {
  item: BulkActionItem;
  'data-id': string;
}) {
  const {
    label,
    icon: Icon,
    onAction,
    isDisabled = false,
    isLoading = false,
    tooltip,
  } = item;

  return (
    <TooltipBase title={tooltip}>
      <Button
        data-id={dataId}
        aria-disabled={isDisabled}
        color="tertiary"
        className={cx(
          'flex cursor-pointer items-center gap-2 whitespace-nowrap px-4 py-2.5 text-sm font-medium !text-white transition hover:bg-white/10 data-[loading]:!bg-transparent',
          isDisabled && 'cursor-not-allowed !text-disabled',
        )}
        onClick={() => {
          if (isDisabled) return;
          onAction?.();
        }}
        iconLeading={
          Icon && typeof Icon === 'function' ? (
            <Icon
              className={cx(
                'size-5 text-button-primary-icon',
                isDisabled && 'text-disabled',
              )}
            />
          ) : undefined
        }
        isLoading={isLoading}
        loadingLabel={label}
      >
        {label}
      </Button>
    </TooltipBase>
  );
}
