import { useMemo, useState } from 'react';
import {
  endOfMonth,
  endOfWeek,
  getLocalTimeZone,
  startOfMonth,
  startOfWeek,
  today,
} from '@internationalized/date';
import { useControlledState } from '@react-stately/utils';
import { Calendar as CalendarIcon } from '@untitledui/icons';
import { useDateFormatter } from 'react-aria';
import type {
  DateRangePickerProps as AriaDateRangePickerProps,
  DateValue,
} from 'react-aria-components';
import {
  DateRangePicker as AriaDateRangePicker,
  Dialog as AriaDialog,
  Group as AriaGroup,
  Popover as AriaPopover,
  useLocale,
} from 'react-aria-components';
import { Button } from '@/components/atoms/Button';
import { cx } from '@/utils/cx';
import { DateInput } from '@/vendor/untitled-ui/application/date-picker/date-input';
import { RangeCalendar } from '@/vendor/untitled-ui/application/date-picker/range-calendar';
import { RangePresetButton } from '@/vendor/untitled-ui/application/date-picker/range-preset';
import { WithDataId } from '@/types/withDataId';
import { DEFAULT_TEXTS } from './defaultTexts';
import { FieldWrapper } from '@/components/molecules/FieldWrapper';
import { FieldWrapperProps } from '@/components/molecules/FieldWrapper/FieldWrapper';

export type DateRangePickerTexts = typeof DEFAULT_TEXTS;

export interface DateRangePickerProps
  extends
    AriaDateRangePickerProps<DateValue>,
    WithDataId,
    Omit<FieldWrapperProps, 'children'> {
  /** Custom formatter for displaying selected dates in the trigger button. */
  formatDate?: (date: Date) => string;
  /** The function to call when the apply button is clicked. */
  onApply?: () => void;
  /** The function to call when the cancel button is clicked. */
  onCancel?: () => void;
  /** Override default UI texts for i18n. */
  t?: DateRangePickerTexts;
  /** Override the default local timezone. */
  timeZone?: string;
}

export const DateRangePicker = ({
  value: valueProp,
  defaultValue,
  onChange,
  onApply,
  onCancel,
  formatDate,
  t: textsProp,
  timeZone,
  'data-id': dataId,
  isInvalid,
  isRequired,
  label,
  hint,
  labelPosition = 'left',
  tooltip,
  description,
  id,
  ...props
}: DateRangePickerProps) => {
  const texts = {
    ...(textsProp ?? DEFAULT_TEXTS),
  };
  const tz = timeZone ?? getLocalTimeZone();
  const { locale } = useLocale();
  const formatter = useDateFormatter({
    month: 'short',
    day: 'numeric',
    year: 'numeric',
  });
  const [value, setValue] = useControlledState(
    valueProp,
    defaultValue || null,
    onChange,
  );
  const [focusedValue, setFocusedValue] = useState<DateValue | null>(null);

  const now = useMemo(() => today(tz), [tz]);
  const highlightedDates = useMemo(() => [today(tz)], [tz]);

  const formatDisplayDate = (date: DateValue) => {
    const jsDate = date.toDate(tz);
    return formatDate ? formatDate(jsDate) : formatter.format(jsDate);
  };

  const formattedStartDate = value?.start
    ? formatDisplayDate(value.start)
    : texts.placeholder;
  const formattedEndDate = value?.end
    ? formatDisplayDate(value.end)
    : texts.placeholder;

  const presets = useMemo(
    () => ({
      today: { label: texts.presets.today, value: { start: now, end: now } },
      yesterday: {
        label: texts.presets.yesterday,
        value: {
          start: now.subtract({ days: 1 }),
          end: now.subtract({ days: 1 }),
        },
      },
      thisWeek: {
        label: texts.presets.thisWeek,
        value: { start: startOfWeek(now, locale), end: endOfWeek(now, locale) },
      },
      lastWeek: {
        label: texts.presets.lastWeek,
        value: {
          start: startOfWeek(now, locale).subtract({ weeks: 1 }),
          end: endOfWeek(now, locale).subtract({ weeks: 1 }),
        },
      },
      thisMonth: {
        label: texts.presets.thisMonth,
        value: { start: startOfMonth(now), end: endOfMonth(now) },
      },
      lastMonth: {
        label: texts.presets.lastMonth,
        value: {
          start: startOfMonth(now).subtract({ months: 1 }),
          end: endOfMonth(now).subtract({ months: 1 }),
        },
      },
      thisYear: {
        label: texts.presets.thisYear,
        value: {
          start: startOfMonth(now.set({ month: 1 })),
          end: endOfMonth(now.set({ month: 12 })),
        },
      },
      lastYear: {
        label: texts.presets.lastYear,
        value: {
          start: startOfMonth(now.set({ month: 1 }).subtract({ years: 1 })),
          end: endOfMonth(now.set({ month: 12 }).subtract({ years: 1 })),
        },
      },
      allTime: {
        label: texts.presets.allTime,
        value: {
          start: now.set({ year: 2000, month: 1, day: 1 }),
          end: now,
        },
      },
    }),
    [locale, now, texts.presets],
  );

  return (
    <FieldWrapper
      isRequired={isRequired}
      label={label}
      hint={hint}
      isInvalid={isInvalid}
      labelPosition={labelPosition}
      tooltip={tooltip}
      description={description}
      id={id}
    >
      <AriaDateRangePicker
        aria-label="Date range picker"
        shouldCloseOnSelect={false}
        {...props}
        value={value}
        onChange={setValue}
      >
        <AriaGroup>
          <Button
            size="sm"
            color="secondary"
            iconLeading={CalendarIcon}
            className={cx(isInvalid && 'ring-error_subtle')}
            data-id={`${dataId}-calendar-icon-button`}
          >
            {!value ? (
              <span className="text-placeholder">{texts.placeholderRange}</span>
            ) : (
              `${formattedStartDate} – ${formattedEndDate}`
            )}
          </Button>
        </AriaGroup>
        <AriaPopover
          placement="bottom right"
          offset={8}
          className={({ isEntering, isExiting }) =>
            cx(
              'will-change-transform',
              isEntering &&
                'duration-150 ease-out animate-in fade-in placement-right:origin-left placement-right:slide-in-from-left-0.5 placement-top:origin-bottom placement-top:slide-in-from-bottom-0.5 placement-bottom:origin-top placement-bottom:slide-in-from-top-0.5',
              isExiting &&
                'duration-100 ease-in animate-out fade-out placement-right:origin-left placement-right:slide-out-to-left-0.5 placement-top:origin-bottom placement-top:slide-out-to-bottom-0.5 placement-bottom:origin-top placement-bottom:slide-out-to-top-0.5',
            )
          }
        >
          <AriaDialog className="flex rounded-2xl bg-primary shadow-xl ring ring-secondary_alt focus:outline-hidden">
            {({ close }) => (
              <>
                <div className="hidden w-38 flex-col gap-0.5 border-r border-solid border-secondary p-3 lg:flex">
                  {Object.values(presets).map((preset) => (
                    <RangePresetButton
                      key={preset.label}
                      value={preset.value}
                      onClick={() => {
                        setValue(preset.value);
                        setFocusedValue(preset.value.start);
                      }}
                      data-id={`${dataId}-range-preset-button`}
                    >
                      {preset.label}
                    </RangePresetButton>
                  ))}
                </div>
                <div className="flex flex-col">
                  <RangeCalendar
                    focusedValue={focusedValue}
                    onFocusChange={setFocusedValue}
                    highlightedDates={highlightedDates}
                    presets={{
                      lastWeek: presets.lastWeek,
                      lastMonth: presets.lastMonth,
                      lastYear: presets.lastYear,
                    }}
                    data-id={`${dataId}-range-calendar`}
                  />
                  <div className="flex justify-between gap-3 border-t border-secondary p-4">
                    <div className="hidden items-center gap-3 md:flex">
                      <DateInput
                        slot="start"
                        className="w-36"
                        data-id={`${dataId}-date-start-input`}
                      />
                      <div className="text-md text-quaternary">–</div>
                      <DateInput
                        slot="end"
                        className="w-36"
                        data-id={`${dataId}-date-end-input`}
                      />
                    </div>
                    <div className="grid w-full grid-cols-2 gap-3 md:flex md:w-auto">
                      <Button
                        size="sm"
                        color="secondary"
                        onClick={() => {
                          onCancel?.();
                          close();
                        }}
                        data-id={`${dataId}-cancel-button`}
                      >
                        {texts.cancelBtn}
                      </Button>
                      <Button
                        size="sm"
                        color="primary"
                        onClick={() => {
                          onApply?.();
                          close();
                        }}
                        data-id={`${dataId}-apply-button`}
                      >
                        {texts.applyBtn}
                      </Button>
                    </div>
                  </div>
                </div>
              </>
            )}
          </AriaDialog>
        </AriaPopover>
      </AriaDateRangePicker>
    </FieldWrapper>
  );
};
