import { TableRow, ColDef } from '../_types';

export function isColumnSelected<TData extends TableRow>(
  column: ColDef<TData>,
  columnsSelection?: Record<string, boolean>,
) {
  if (column.alwaysVisible) {
    return true;
  }

  if (column.isSelected !== undefined) {
    return column.isSelected;
  }

  if (
    columnsSelection !== undefined &&
    columnsSelection[String(column.id)] !== undefined
  ) {
    return columnsSelection[String(column.id)];
  }

  return column.defaultVisibility === undefined || column.defaultVisibility;
}
