import { Node, mergeAttributes } from '@tiptap/core';
import { ReactNodeViewRenderer } from '@tiptap/react';
import { HtmlEmbedNodeView } from './HtmlEmbedNodeView';

export interface HtmlEmbedAttrs {
  html: string;
}

export interface HtmlEmbedOptions {
  /**
   * Extra HTML attributes merged onto the rendered `<div data-html-embed>` wrapper.
   */
  HTMLAttributes?: Record<string, unknown>;
}

declare module '@tiptap/core' {
  interface Commands<ReturnType> {
    htmlEmbed: {
      /**
       * Insert a new htmlEmbed block at the current selection.
       */
      insertHtmlEmbed: (html: string) => ReturnType;
      /**
       * Update the html attribute of the currently-selected htmlEmbed node.
       */
      updateHtmlEmbed: (html: string) => ReturnType;
    };
  }
}

/**
 * `htmlEmbed` — TipTap node for inline raw-HTML blocks (iframes, scripts,
 * styles, custom widgets, marketing snippets). Designed as a drop-in
 * replacement for CKEditor's `htmlEmbed` plugin.
 *
 * The node is an atom (no inner editing) and serializes to
 * `<div data-html-embed>{{ html }}</div>` so existing CKEditor content
 * round-trips cleanly.
 *
 * **Security**: embedded HTML is rendered as-is — no sanitization. This
 * extension is intentionally a privileged feature; only enable it on
 * screens where authors are trusted (admins/owners). Consumers are
 * responsible for any sanitization they need at their own boundaries.
 */
export const HtmlEmbedExtension = Node.create<HtmlEmbedOptions>({
  name: 'htmlEmbed',
  group: 'block',
  atom: true,
  selectable: true,
  draggable: true,

  addOptions() {
    return {
      HTMLAttributes: {},
    };
  },

  addAttributes() {
    return {
      html: {
        default: '',
        parseHTML: (element) => {
          // Recover raw inner HTML so existing CKEditor output round-trips.
          return element.innerHTML.trim();
        },
        renderHTML: () => ({}),
      },
    };
  },

  parseHTML() {
    return [{ tag: 'div[data-html-embed]' }];
  },

  renderHTML({ HTMLAttributes, node }) {
    const html = (node.attrs.html ?? '') as string;
    const attrs = mergeAttributes(
      this.options.HTMLAttributes ?? {},
      HTMLAttributes,
      { 'data-html-embed': '' },
    );
    // TipTap's renderHTML cannot emit raw HTML strings as children, so we
    // serialize the embed via DOM nodes that carry the markup verbatim.
    const dom = document.createElement('div');
    Object.entries(attrs).forEach(([key, value]) => {
      if (value === undefined || value === null) return;
      dom.setAttribute(key, String(value));
    });
    dom.innerHTML = html;
    return dom;
  },

  addNodeView() {
    return ReactNodeViewRenderer(HtmlEmbedNodeView);
  },

  addCommands() {
    return {
      insertHtmlEmbed:
        (html) =>
        ({ chain }) =>
          chain()
            .insertContent({
              type: this.name,
              attrs: { html },
            })
            .run(),
      updateHtmlEmbed:
        (html) =>
        ({ commands, state }) => {
          if (state.selection.empty) return false;
          const node = state.doc.nodeAt(state.selection.from);
          if (!node || node.type.name !== this.name) return false;
          return commands.updateAttributes(this.name, { html });
        },
    };
  },
});
