import { WithDataId } from '@/types/withDataId';
import { FieldWrapper } from '@/components/molecules/FieldWrapper';
import { FieldWrapperProps } from '@/components/molecules/FieldWrapper/FieldWrapper';
import { Input } from './Input';

export type InputFieldProps = React.ComponentProps<typeof Input> &
  WithDataId &
  Omit<FieldWrapperProps, 'children'>;

export function InputField({
  label,
  hint,
  isInvalid,
  isRequired,
  tooltip,
  description,
  id = '',
  fieldSize = 'md',
  labelPosition = 'left',
  ...props
}: InputFieldProps) {
  return (
    <FieldWrapper
      id={id}
      label={label}
      hint={hint}
      isInvalid={isInvalid}
      isRequired={isRequired}
      tooltip={tooltip}
      description={description}
      fieldSize={fieldSize}
      labelPosition={labelPosition}
    >
      <Input
        isInvalid={isInvalid}
        {...props}
      />
    </FieldWrapper>
  );
}
