import type { ComponentProps } from 'react';
import { useId, useRef } from 'react';
import { Button } from '@/components/atoms/Button';
import { Upload01 } from '@/icons';

export interface FileUploadButtonProps {
  /** The class name of the button. */
  className?: string;
  /**
   * Disables the button.
   */
  isDisabled?: boolean;
  /**
   * Specifies the types of files that the server accepts.
   * Examples: "image/*", ".pdf,image/*", "image/*,video/mpeg,application/pdf"
   */
  accept?: string;
  /**
   * Allows multiple file uploads.
   */
  allowsMultiple?: boolean;
  /**
   * Maximum file size in bytes.
   */
  maxSize?: number;
  /**
   * Callback function that is called with the list of selected files.
   */
  onSelectFiles?: (files: FileList) => void;
  /**
   * Callback function that is called with the list of unaccepted files.
   */
  onSelectUnacceptedFiles?: (files: FileList) => void;
  /**
   * Callback function that is called with the list of files that exceed
   * the size limit.
   */
  onSizeLimitExceed?: (files: FileList) => void;
  /**
   * Button label text.
   */
  children?: React.ReactNode;
  /**
   * Button color variant.
   */
  color?: ComponentProps<typeof Button>['color'];
  /**
   * Button size variant.
   */
  size?: ComponentProps<typeof Button>['size'];
  /**
   * Data ID for testing.
   */
  'data-id'?: string;
}

export const FileUploadButton = ({
  className,
  isDisabled,
  accept,
  allowsMultiple = false,
  maxSize,
  onSelectFiles,
  onSelectUnacceptedFiles,
  onSizeLimitExceed,
  children = 'Upload file',
  color = 'secondary',
  size = 'sm',
  'data-id': dataId = 'file-upload-button',
}: FileUploadButtonProps) => {
  const id = useId();
  const inputRef = useRef<HTMLInputElement>(null);

  const isFileTypeAccepted = (file: File): boolean => {
    if (!accept) return true;

    const acceptedTypes = accept.split(',').map((type) => type.trim());

    return acceptedTypes.some((acceptedType) => {
      if (acceptedType.startsWith('.')) {
        const extension = `.${file.name.split('.').pop()?.toLowerCase()}`;
        return extension === acceptedType.toLowerCase();
      }

      if (acceptedType.endsWith('/*')) {
        const typePrefix = acceptedType.split('/')[0];
        return file.type.startsWith(`${typePrefix}/`);
      }

      return file.type === acceptedType;
    });
  };

  const processFiles = (files: File[]): void => {
    const acceptedFiles: File[] = [];
    const unacceptedFiles: File[] = [];
    const oversizedFiles: File[] = [];

    const filesToProcess = allowsMultiple ? files : files.slice(0, 1);

    filesToProcess.forEach((file) => {
      if (maxSize && file.size > maxSize) {
        oversizedFiles.push(file);
        return;
      }

      if (isFileTypeAccepted(file)) {
        acceptedFiles.push(file);
      } else {
        unacceptedFiles.push(file);
      }
    });

    if (oversizedFiles.length > 0 && typeof onSizeLimitExceed === 'function') {
      const dataTransfer = new DataTransfer();
      oversizedFiles.forEach((file) => dataTransfer.items.add(file));
      onSizeLimitExceed(dataTransfer.files);
    }

    if (acceptedFiles.length > 0 && typeof onSelectFiles === 'function') {
      const dataTransfer = new DataTransfer();
      acceptedFiles.forEach((file) => dataTransfer.items.add(file));
      onSelectFiles(dataTransfer.files);
    }

    if (
      unacceptedFiles.length > 0 &&
      typeof onSelectUnacceptedFiles === 'function'
    ) {
      const unacceptedDataTransfer = new DataTransfer();
      unacceptedFiles.forEach((file) => unacceptedDataTransfer.items.add(file));
      onSelectUnacceptedFiles(unacceptedDataTransfer.files);
    }

    if (inputRef.current) {
      inputRef.current.value = '';
    }
  };

  const handleInputFileChange = (
    event: React.ChangeEvent<HTMLInputElement>,
  ) => {
    processFiles(Array.from(event.target.files || []));
  };

  return (
    <>
      <input
        ref={inputRef}
        id={id}
        type="file"
        className="sr-only"
        disabled={isDisabled}
        accept={accept}
        multiple={allowsMultiple}
        onChange={handleInputFileChange}
      />
      <Button
        data-id={dataId}
        color={color}
        size={size}
        isDisabled={isDisabled}
        iconLeading={Upload01}
        className={className}
        onPress={() => inputRef.current?.click()}
      >
        {children}
      </Button>
    </>
  );
};
