import type { FormEvent } from 'react';
import { Button } from '@/components/atoms/Button/BaseButton';
import { cx } from '@/utils/cx';
import { TextAreaBase } from '@/components/atoms/TextArea';
import React from 'react';
import { WithDataId } from '@/types/withDataId';

export type MessageSendActionTextAreaProps = WithDataId & {
  textAreaClassName?: string;
  className?: string;
  onSendClick: () => void;
  actionButtons?: React.ReactNode;
  value?: string;
  onValueChange: (value: string) => void;
  sendButtonLabel: string;
  placeholder: string;
};

export const MessageSendActionTextArea = ({
  onSendClick,
  value,
  onValueChange,
  textAreaClassName,
  actionButtons,
  className,
  sendButtonLabel,
  placeholder,
  'data-id': dataId,
}: MessageSendActionTextAreaProps) => {
  return (
    <div
      className={cx('relative flex h-max items-center gap-3', className)}
      data-id={dataId}
    >
      <TextAreaBase
        value={value}
        aria-label={placeholder}
        placeholder={placeholder}
        name="message"
        className={cx('h-32 w-full resize-none', textAreaClassName)}
        onChange={(e: FormEvent<HTMLTextAreaElement>) => {
          onValueChange((e.target as HTMLTextAreaElement).value);
        }}
      />

      <div className="absolute right-3.5 bottom-2 flex items-center gap-2">
        <div className="flex items-center gap-0.5">
          {actionButtons && actionButtons}
        </div>

        <Button
          size="sm"
          color="link-color"
          onClick={onSendClick}
        >
          {sendButtonLabel}
        </Button>
      </div>
    </div>
  );
};
