import { Button } from '@/components/atoms/Button';

import { useRef } from 'react';
import { Avatar } from '@/vendor/untitled-ui/base/avatar/avatar';
import { WithDataId } from '@/types/withDataId';

export type FileInputProps = WithDataId &
  Omit<React.ComponentProps<'div'>, 'onChange'> & {
    onChange?: (e: React.ChangeEvent<HTMLInputElement>) => void;
    size?: 'sm' | 'md' | 'lg';
    radius?: 'sm' | 'md' | 'lg';
    label?: string;
    description?: string;
    button?: string;
    value?: string;
  };

export function FileInput({
  onChange = () => {},
  button = 'Change',
  label = 'Choose File',
  value,
  description,
  'data-id': dataId,
  ...rest
}: FileInputProps) {
  const fileInputRef = useRef<HTMLInputElement>(null);

  return (
    <div
      className="flex-row gap-4 items-center"
      data-id={dataId}
      {...rest}
    >
      <input
        type="file"
        ref={fileInputRef}
        onChange={onChange}
        className="hidden"
        accept="image/*"
        data-id={`${dataId}-input`}
      />
      <Avatar
        size="lg"
        src={value}
      />
      <div className="flex-1">
        <div className="text-md">{label}</div>
        <div className="text-gray-400 text-small">{description}</div>
      </div>
      <Button
        size="sm"
        color="primary"
        onClick={() => fileInputRef?.current?.click()}
        data-id={`${dataId}-button`}
      >
        {button}
      </Button>
    </div>
  );
}
