import type { ComponentPropsWithRef } from 'react';
import { cx } from '@/utils/cx';
import {
  Avatar,
  AvatarProps,
  AvatarAddButton,
} from '@/components/atoms/Avatar';
import { WithDataId } from '@/types/withDataId';

interface AvatarGroupItem extends AvatarProps {
  size: 'xs' | 'sm' | 'md';
}

export interface AvatarGroupProps
  extends ComponentPropsWithRef<'div'>, WithDataId {
  /** List of avatars to display */
  list: AvatarGroupItem[];
  minDisplay?: number;
  buttonSize: 'xs' | 'sm' | 'md';
}

export function AvatarGroup({
  list,
  buttonSize,
  minDisplay = 3,
  className,
  'data-id': dataId,
}: AvatarGroupProps) {
  const shouldDisplayCountAvatar = list.length > minDisplay;
  const displayList = shouldDisplayCountAvatar
    ? list.slice(0, minDisplay)
    : list;
  return (
    <div className={cx('flex -space-x-3', className)}>
      {displayList.map(({ size: avatarSize, ...avatar }, index) => (
        <Avatar
          className="outline-white outline-2"
          key={index}
          size={avatarSize}
          {...avatar}
        />
      ))}
      {shouldDisplayCountAvatar && (
        <Avatar
          className="outline-white outline-2 border border-solid border-secondary shadow-bg-primary outline-offset-0"
          size={displayList?.[0]?.size}
          initials={`+${list.length - minDisplay}`}
        />
      )}
      <AvatarAddButton
        className="ml-5"
        size={buttonSize}
        title="Add team member"
        data-id={dataId}
      />
    </div>
  );
}
