
import { useState } from "react";
import { cx } from "@/utils/cx";
import type { WithDataId } from "@/types/withDataId";
import type { NavItemDividerType, NavItemType } from "../config";
import { NavItemBase } from "./nav-item";

export interface NavListProps extends WithDataId {
    /** URL of the currently active item. */
    activeUrl?: string;
    /** Additional CSS classes to apply to the list. */
    className?: string;
    /** List of items to display. */
    items: (NavItemType | NavItemDividerType)[];
}

export const NavList = ({ activeUrl, items, className, 'data-id': dataId }: NavListProps) => {
    const activeItem = items.find((item) => item.href === activeUrl || item.items?.some((subItem) => subItem.href === activeUrl));
    const [openLabel, setOpenLabel] = useState<string | undefined>(
        activeItem && !activeItem.divider && activeItem.items?.length ? activeItem.label : undefined,
    );

    return (
        <ul data-id={dataId} className={cx("mt-4 flex flex-col px-2 lg:px-4", className)}>
            {items.map((item, index) => {
                if (item.divider) {
                    return (
                        <li key={index} className="w-full px-0.5 py-2">
                            <hr className="h-px w-full border-none bg-border-secondary" />
                        </li>
                    );
                }

                if (item.items?.length) {
                    const isOpen = openLabel === item.label;
                    const targetHref = item.href ?? item.items[0].href;
                    const isCurrent = activeUrl === item.href || item.items.some((subItem) => subItem.href === activeUrl);

                    return (
                        <li key={item.label} className="py-0.5">
                            <NavItemBase
                                data-id={`${dataId}-${item['data-id']}`}
                                href={targetHref}
                                badge={item.badge}
                                icon={item.icon}
                                type="collapsible"
                                open={isOpen}
                                current={isCurrent}
                                onClick={() => setOpenLabel(isOpen ? undefined : item.label)}
                            >
                                {item.label}
                            </NavItemBase>

                            <ul className={cx("py-0.5", !isOpen && "hidden")} hidden={!isOpen}>
                                {item.items.map((childItem) => (
                                    <li key={childItem.label} className="py-0.5">
                                        <NavItemBase
                                            data-id={`${dataId}-${childItem['data-id']}`}
                                            href={childItem.href}
                                            badge={childItem.badge}
                                            type="collapsible-child"
                                            current={activeUrl === childItem.href}
                                        >
                                            {childItem.label}
                                        </NavItemBase>
                                    </li>
                                ))}
                            </ul>
                        </li>
                    );
                }

                return (
                    <li key={item.label} className="py-0.5">
                        <NavItemBase
                            data-id={`${dataId}-${item['data-id']}`}
                            type="link"
                            badge={item.badge}
                            icon={item.icon}
                            href={item.href}
                            current={activeUrl === item.href}
                        >
                            {item.label}
                        </NavItemBase>
                    </li>
                );
            })}
        </ul>
    );
};
