import { cx } from '@/utils/cx';
import type { ComponentProps, ReactNode } from 'react';
import { FileIcon as FileTypeIcon } from '@/icons';
import { Avatar } from '@/vendor/untitled-ui/base/avatar/avatar';
import { WithDataId } from '@/types/withDataId';

export interface FileUploadedProps
  extends WithDataId, Omit<ComponentProps<'div'>, 'onClick' | 'title'> {
  title?: string;
  fileName?: string;
  type?: ComponentProps<typeof FileTypeIcon>['type'];
  className?: string;
  fileIconVariant?: ComponentProps<typeof FileTypeIcon>['variant'];
  actions?: () => ReactNode;
  url?: string;
}

export const FileUploaded = ({
  title = '',
  fileName = '',
  type,
  fileIconVariant,
  actions,
  className,
  'data-id': dataId,
  url = '',
  ...rest
}: FileUploadedProps) => {
  return (
    <div
      className={cx(
        'relative flex gap-3 rounded-xl bg-primary p-4 ring-1 ring-secondary transition-shadow duration-100 ease-linear ring-inset w-full items-center',
        className,
      )}
      data-id={dataId}
      {...rest}
    >
      {url ? (
        <Avatar
          src={url}
          alt={fileName || title}
          size="md"
        />
      ) : (
        <>
          <FileTypeIcon
            className="size-10 shrink-0 dark:hidden"
            type={type ?? 'empty'}
            theme="light"
            variant={fileIconVariant ?? 'default'}
          />
          <FileTypeIcon
            className="size-10 shrink-0 not-dark:hidden"
            type={type ?? 'empty'}
            theme="dark"
            variant={fileIconVariant ?? 'default'}
          />
        </>
      )}

      <div className="flex min-w-0 flex-1 flex-col items-start">
        <div className="flex w-full max-w-full min-w-0 flex-1 gap-3">
          <div className="min-w-0 flex-1 flex items-center">
            {title && (
              <p className="truncate text-sm font-medium text-secondary">
                {title}
              </p>
            )}

            {fileName && (
              <p className="truncate text-sm font-medium text-quaternary">
                {fileName}
              </p>
            )}
          </div>

          {actions && <div>{actions()}</div>}
        </div>
      </div>
    </div>
  );
};
