import { useRef, useState } from 'react';
import { type Key } from 'react-aria-components';
import { Settings01, SearchLg } from '@untitledui/icons';
import { Button } from '@/components/atoms/Button';
import { Dropdown } from '@/components/atoms/Dropdown/base';
import { InputField } from '@/components/atoms/Input';
import { cx } from '@/utils/cx';

import { DEFAULT_TEXTS } from './_consts';
import { isColumnSelected } from './_utils';
import { WithDataId } from '@/types/withDataId';
import { ColumnCheckboxList } from './ColumnCheckboxList';
import { SelectedColumnsPanel } from './SelectedColumnsPanel';

import type { TableRow, TableColumnsSelectorProps } from './_types';

export function TableColumnsSelector<TData extends TableRow>({
  columnDefs,
  columnsSelection,
  onColumnsSelectedChange,
  onColumnsSelectionChange,
  columnsSelectorTabs,
  columnOrder,
  onColumnOrderChange,
  t,
  'data-id': dataId,
}: TableColumnsSelectorProps<TData> & WithDataId) {
  const texts = {
    columnsSelector: {
      ...DEFAULT_TEXTS.columnsSelector,
      ...t?.columnsSelector,
    },
  };
  const [filter, setFilter] = useState('');
  const [activeTab, setActiveTab] = useState<Key>(
    columnsSelectorTabs?.[0]?.id ?? '',
  );
  const tablistRef = useRef<HTMLDivElement>(null);

  const toggleableColumns = columnDefs.filter((c) => !c.alwaysVisible);
  const filteredColumns = filter
    ? toggleableColumns.filter(
        (c) => c.label?.toLowerCase().indexOf(filter.toLowerCase()) !== -1,
      )
    : toggleableColumns;

  const getTabColumns = (tabId: Key) =>
    filteredColumns.filter(
      (c) => (c.category ?? columnsSelectorTabs?.[0]?.id) === tabId,
    );

  const visibleTabs = columnsSelectorTabs?.filter((tab) =>
    toggleableColumns.some(
      (c) => (c.category ?? columnsSelectorTabs?.[0]?.id) === tab.id,
    ),
  );

  const hasTabs = visibleTabs && visibleTabs.length > 0;

  const selectedColumns = columnDefs.filter(
    (c) => c.label && isColumnSelected(c, columnsSelection),
  );

  const getTabSelectedCount = (tabId: Key) =>
    toggleableColumns.filter(
      (c) =>
        (c.category ?? columnsSelectorTabs?.[0]?.id) === tabId &&
        isColumnSelected(c, columnsSelection),
    ).length;

  // Arrow key navigation for tablist
  const handleTabKeyDown = (e: React.KeyboardEvent) => {
    if (!visibleTabs) {
      return;
    }

    const tabIds = visibleTabs.map((t) => t.id);
    const currentIndex = tabIds.indexOf(activeTab as string);

    if (currentIndex === -1) {
      return;
    }

    let nextIndex: number | null = null;

    if (e.key === 'ArrowDown' || e.key === 'ArrowRight') {
      nextIndex = (currentIndex + 1) % tabIds.length;
    } else if (e.key === 'ArrowUp' || e.key === 'ArrowLeft') {
      nextIndex = (currentIndex - 1 + tabIds.length) % tabIds.length;
    }

    if (nextIndex != null) {
      e.preventDefault();

      setActiveTab(tabIds[nextIndex]);

      const buttons =
        tablistRef.current?.querySelectorAll<HTMLButtonElement>('[role="tab"]');

      buttons?.[nextIndex]?.focus();
    }
  };

  // Non-tabbed layout: two panels (checkboxes + selected columns)
  if (!hasTabs) {
    return (
      <Dropdown.Root>
        <Button
          size="sm"
          color="tertiary"
          aria-label={texts.columnsSelector.settingsAriaLabel}
          className="bg-transparent hover:bg-transparent focus:bg-transparent !w-17"
          data-id={`${dataId}-settings`}
        >
          <Settings01 className="size-4 text-quaternary" />
        </Button>
        <Dropdown.Popover className="flex !overflow-hidden w-[480px] max-w-[calc(100vw-1rem)]">
          {/* Left panel — search + checkboxes */}
          <div className="flex min-w-0 flex-1 flex-col border-r border-secondary">
            <div className="border-b border-secondary p-2">
              <InputField
                icon={SearchLg}
                value={filter}
                onChange={(val) => {
                  setFilter(val);
                }}
                placeholder={texts.columnsSelector.findColumnPlaceholder}
                className="text-sm"
                data-id={`${dataId}-filter`}
              />
            </div>
            <div className="flex-1 overflow-y-auto">
              <ColumnCheckboxList
                columns={filteredColumns}
                allColumnDefs={columnDefs}
                columnsSelection={columnsSelection}
                onColumnsSelectedChange={onColumnsSelectedChange}
                onColumnsSelectionChange={onColumnsSelectionChange}
                texts={texts}
                dataId={`${dataId}-checkboxList`}
              />
            </div>
          </div>

          {/* Right panel — selected columns with drag reorder */}
          <div className="flex w-2/5 flex-col">
            <SelectedColumnsPanel
              columns={selectedColumns}
              columnOrder={columnOrder}
              onColumnOrderChange={onColumnOrderChange}
              texts={texts}
              dataId={`${dataId}-selectedColumns`}
            />
          </div>
        </Dropdown.Popover>
      </Dropdown.Root>
    );
  }

  // Tabbed layout: three-panel with vertical tabs
  const resolvedActiveTab = visibleTabs.some((t) => t.id === activeTab)
    ? activeTab
    : (visibleTabs[0]?.id ?? '');
  const activeTabColumns = getTabColumns(resolvedActiveTab);

  return (
    <Dropdown.Root>
      <Button
        size="sm"
        color="tertiary"
        aria-label={texts.columnsSelector.settingsAriaLabel}
        className="bg-transparent hover:bg-transparent focus:bg-transparent !w-17"
        data-id={`${dataId}-tabbed-settings`}
      >
        <Settings01 className="size-4" />
      </Button>
      <Dropdown.Popover className="flex !overflow-hidden w-[775px] max-w-[calc(100vw-1rem)]">
        {/* Left panel — vertical category tabs */}
        <div
          ref={tablistRef}
          className="flex w-[32%] min-w-0 flex-col overflow-hidden border-r border-secondary bg-primary"
          role="tablist"
          aria-orientation="vertical"
          aria-label="Column categories"
        >
          {visibleTabs.map((tab) => (
            <Button
              key={tab.id}
              type="button"
              role="tab"
              color="tertiary"
              size="sm"
              aria-selected={resolvedActiveTab === tab.id}
              tabIndex={0}
              className={cx(
                '!flex w-full items-center !px-3 !py-2 text-left text-sm !rounded-none focus-visible:ring-2 focus-visible:ring-inset focus-visible:ring-brand-solid [&>[data-text]]:flex [&>[data-text]]:w-full [&>[data-text]]:min-w-0 [&>[data-text]]:items-center [&>[data-text]]:justify-between',
                resolvedActiveTab === tab.id
                  ? 'bg-secondary !font-medium !text-secondary_hover'
                  : '!font-normal !text-primary',
              )}
              onPress={() => setActiveTab(tab.id)}
              onKeyDown={handleTabKeyDown}
              data-id={`${dataId}-tab-${tab.id}`}
            >
              <span className="truncate">{tab.label}</span>
              {getTabSelectedCount(tab.id) > 0 && (
                <span className="inline-flex min-w-4 items-center justify-center rounded border border-secondary px-0.5 text-[10px] leading-4 text-tertiary">
                  {getTabSelectedCount(tab.id)}
                </span>
              )}
            </Button>
          ))}
        </div>

        {/* Middle panel — search + checkboxes */}
        <div
          className="flex min-w-0 flex-1 flex-col border-r border-secondary"
          role="tabpanel"
          aria-labelledby={`${dataId}-tab-${resolvedActiveTab}`}
        >
          <div className="border-b border-secondary p-2">
            <InputField
              icon={SearchLg}
              value={filter}
              onChange={(val) => {
                setFilter(val);
              }}
              placeholder={texts.columnsSelector.findColumnPlaceholder}
              className="text-sm"
              data-id={`${dataId}-tabbed-filter`}
            />
          </div>
          <div className="flex-1 overflow-y-auto">
            <ColumnCheckboxList
              columns={activeTabColumns}
              allColumnDefs={columnDefs}
              columnsSelection={columnsSelection}
              onColumnsSelectedChange={onColumnsSelectedChange}
              onColumnsSelectionChange={onColumnsSelectionChange}
              texts={texts}
              dataId={`${dataId}-tabbed-checkboxList`}
            />
          </div>
        </div>

        {/* Right panel — selected columns with drag reorder */}
        <div className="flex w-[32%] min-w-0 flex-col">
          <SelectedColumnsPanel
            columns={selectedColumns}
            columnOrder={columnOrder}
            onColumnOrderChange={onColumnOrderChange}
            texts={texts}
            dataId={`${dataId}-tabbed-selectedColumns`}
          />
        </div>
      </Dropdown.Popover>
    </Dropdown.Root>
  );
}
