import type {
  FocusEventHandler,
  PointerEventHandler,
  RefAttributes,
} from 'react';
import { forwardRef, useCallback, useContext, useRef, useState } from 'react';
import { SearchLg as SearchIcon } from '@/icons';
import type {
  ComboBoxProps as AriaComboBoxProps,
  GroupProps as AriaGroupProps,
  ListBoxProps as AriaListBoxProps,
} from 'react-aria-components';
import {
  ComboBox as AriaComboBox,
  Group as AriaGroup,
  Input as AriaInput,
  ListBox as AriaListBox,
  ComboBoxStateContext,
} from 'react-aria-components';
import { HintText } from '@/components/atoms/Input/base/hint-text';
import { Label } from '@/components/atoms/Input/base/label';
import { Popover } from './BasePopover';
import { type CommonProps, type SelectItemType } from './baseTypes';
import { useResizeObserver } from '@/hooks/use-resize-observer';
import { cx } from '@/utils/cx';

interface ComboBoxProps
  extends
    Omit<AriaComboBoxProps<SelectItemType>, 'children' | 'items'>,
    RefAttributes<HTMLDivElement>,
    CommonProps {
  shortcut?: boolean;
  items?: SelectItemType[];
  popoverClassName?: string;
  shortcutClassName?: string;
  children: AriaListBoxProps<SelectItemType>['children'];
}

interface ComboBoxValueProps extends AriaGroupProps {
  shortcut: boolean;
  placeholder?: string;
  shortcutClassName?: string;
  onFocus?: FocusEventHandler;
  onPointerEnter?: PointerEventHandler;
}

const ComboBoxValue = forwardRef<HTMLDivElement, ComboBoxValueProps>(
  ({ shortcut, placeholder, shortcutClassName, ...otherProps }, ref) => {
    const state = useContext(ComboBoxStateContext);

    const value = state?.selectedItem?.value || null;
    const inputValue = state?.inputValue || null;

    const first = inputValue?.split(value?.supportingText)?.[0] || '';
    const last = inputValue?.split(first)[1];

    return (
      <AriaGroup
        {...otherProps}
        ref={ref}
        className={({ isFocusWithin, isDisabled }) =>
          cx(
            'relative flex w-full items-center gap-2 rounded-lg bg-primary shadow-xs ring-1 ring-primary outline-hidden transition-shadow duration-100 ease-linear ring-inset py-2 px-3',
            isDisabled && 'cursor-not-allowed bg-disabled_subtle',
            isFocusWithin && 'ring-2 ring-brand',
          )
        }
      >
        {({ isDisabled }) => (
          <>
            <SearchIcon className="pointer-events-none size-4 text-fg-quaternary" />

            <div className="relative flex w-full items-center gap-2">
              {inputValue && (
                <span
                  className="absolute top-1/2 z-0 inline-flex w-full -translate-y-1/2 gap-2 truncate"
                  aria-hidden="true"
                >
                  <p
                    className={cx(
                      'text-sm font-medium text-primary',
                      isDisabled && 'text-disabled',
                    )}
                  >
                    {first}
                  </p>
                  {last && (
                    <p
                      className={cx(
                        '-ml-0.75 text-sm text-tertiary',
                        isDisabled && 'text-disabled',
                      )}
                    >
                      {last}
                    </p>
                  )}
                </span>
              )}

              <AriaInput
                placeholder={placeholder}
                className="z-10 w-full appearance-none bg-transparent text-sm text-transparent caret-alpha-black/90 placeholder:text-placeholder focus:outline-hidden disabled:cursor-not-allowed disabled:text-disabled disabled:placeholder:text-disabled"
              />
            </div>

            {shortcut && (
              <div
                className={cx(
                  'absolute inset-y-0.5 right-0.5 z-10 flex items-center rounded-r-[inherit] bg-linear-to-r from-transparent to-bg-primary to-40% pl-8 pr-2.5',
                  isDisabled && 'to-bg-disabled_subtle',
                  shortcutClassName,
                )}
              >
                <span
                  className={cx(
                    'pointer-events-none rounded px-1 py-px text-xs font-medium text-quaternary ring-1 ring-secondary select-none ring-inset',
                    isDisabled && 'bg-transparent text-disabled',
                  )}
                  aria-hidden="true"
                >
                  ⌘K
                </span>
              </div>
            )}
          </>
        )}
      </AriaGroup>
    );
  },
);

export const ComboBox = forwardRef<HTMLDivElement, ComboBoxProps>(
  (
    {
      placeholder = 'Search',
      shortcut = true,
      children,
      items,
      shortcutClassName,
      ...otherProps
    },
    ref,
  ) => {
    const placeholderRef = useRef<HTMLDivElement>(null);
    const [popoverWidth, setPopoverWidth] = useState('');

    // Resize observer for popover width
    const onResize = useCallback(() => {
      if (!placeholderRef.current) return;

      const divRect = placeholderRef.current?.getBoundingClientRect();

      setPopoverWidth(divRect.width + 'px');
    }, [placeholderRef, setPopoverWidth]);

    useResizeObserver({
      ref: placeholderRef,
      box: 'border-box',
      onResize,
    });

    return (
      <AriaComboBox
        ref={ref}
        menuTrigger="focus"
        {...otherProps}
      >
        {(state) => (
          <div className="flex flex-col gap-1.5">
            {otherProps.label && (
              <Label
                isRequired={state.isRequired}
                tooltip={otherProps.tooltip}
              >
                {otherProps.label}
              </Label>
            )}

            <ComboBoxValue
              ref={placeholderRef}
              placeholder={placeholder}
              shortcut={shortcut}
              shortcutClassName={shortcutClassName}
              // This is a workaround to correctly calculating the trigger width
              // while using ResizeObserver wasn't 100% reliable.
              onFocus={onResize}
              onPointerEnter={onResize}
            />

            <Popover
              triggerRef={placeholderRef}
              style={{ width: popoverWidth }}
              className={otherProps.popoverClassName}
            >
              <AriaListBox
                items={items}
                className="size-full outline-hidden"
              >
                {children}
              </AriaListBox>
            </Popover>

            {otherProps.hint && (
              <HintText isInvalid={state.isInvalid}>{otherProps.hint}</HintText>
            )}
          </div>
        )}
      </AriaComboBox>
    );
  },
);
