import type { CSSProperties, ReactNode } from 'react';
import { useState } from 'react';
import type { EditorOptions } from '@tiptap/react';
import {
  TextEditor as BaseTextEditor,
  useEditorContext,
} from './base/text-editor';
import { Button } from '@/components/atoms/Button';
import { Type01 } from '@/icons';
import { WithDataId } from '@/types/withDataId';
import { cx } from '@/utils/cx';
import { ROW_HEIGHT_PX } from '@/utils/rowHeight';

export { useEditorContext };

// Each row in the editor is a `<p class="my-2">`. With `p-4` on the
// contenteditable (16 + 16), the first paragraph's top margin and the last
// paragraph's bottom margin together add 16 (margins don't collapse against
// the parent's padding), and every adjacent paragraph pair contributes a
// collapsed 8px gap. So N rows take:
//   24 * N (text) + 8 * (N - 1) (gaps) + 8 + 8 (outer margins) + 32 (padding)
// = 32 * N + 40, valid for N ≥ 1. Non-positive N clamps to `EDITOR_BASE_PX`
// (48px) — just the padding + outer margins, no text content.
const PARAGRAPH_GAP_PX = 8; // collapsed margin between sibling <p>s
const OUTER_MARGIN_PX = 16; // 8 top + 8 bottom on first/last <p>
const CONTAINER_PADDING_PX = 32; // `p-4` on the contenteditable (16 + 16)
const EDITOR_BASE_PX = OUTER_MARGIN_PX + CONTAINER_PADDING_PX;
/**
 * Exported for the colocated spec to assert against the same formula.
 * Not part of the public package API — not re-exported from `index.ts`.
 */
export const editorRowsToPx = (rows: number) => {
  if (rows < 1) return EDITOR_BASE_PX;
  return rows * ROW_HEIGHT_PX + (rows - 1) * PARAGRAPH_GAP_PX + EDITOR_BASE_PX;
};

export interface TextEditorProps extends WithDataId {
  floating?: boolean;
  isInvalid?: boolean;
  size?: 'sm' | 'md';
  /**
   * Controls the editor's horizontal sizing. `'md'` (default) caps the editor
   * at `max-w-lg` (512px). `'full'` removes the cap so the editor fills its
   * container — useful inside flex layouts or full-width composers.
   */
  fieldSize?: 'md' | 'full';
  /**
   * When true, the editor auto-resizes to fit its content. Starting height
   * is one row (or `minRows`) and grows with content. Defaults to `false`
   * — height is fixed at 348px and the user drags the resize handle to grow.
   */
  autoGrow?: boolean;
  /**
   * When combined with `autoGrow`, sets the editor's starting / minimum
   * height in rows. When unset, the editor uses a one-row baseline
   * (`min-h-18`). No-op when `autoGrow` is false.
   */
  minRows?: number;
  /**
   * When combined with `autoGrow`, caps the editor height at `maxRows`
   * worth of text. Content beyond that scrolls within the editor.
   * No-op when `autoGrow` is false.
   */
  maxRows?: number;
  limit?: number;
  content?: string;
  onUpdate: (content: string) => void;
  isTooltipEnabled?: boolean;
  /**
   * When true, renders a Type01 toggle button at the start of the footer
   * that shows / hides the formatting toolbar. The toolbar starts hidden.
   * Designed for chat-style composers.
   */
  toolbarToggle?: boolean;
  hintText?: string;
  toolbarExtras?: ReactNode[];
  extraExtensions?: EditorOptions['extensions'];
  headerSlot?: ReactNode;
  footerSlot?: ReactNode;
}
export function TextEditor({
  onUpdate,
  content,
  size,
  fieldSize = 'md',
  autoGrow = false,
  minRows,
  maxRows,
  floating = false,
  isInvalid = false,
  isTooltipEnabled = false,
  toolbarToggle = false,
  limit = 1812,
  hintText = '',
  toolbarExtras,
  extraExtensions,
  headerSlot,
  footerSlot,
  'data-id': dataId,
  ...rest
}: TextEditorProps) {
  const [hideToolbar, setHideToolbar] = useState(toolbarToggle);

  const toolbar = hideToolbar ? null : isTooltipEnabled ? (
    <BaseTextEditor.Tooltip
      data-id={`${dataId}-tooltip`}
      extras={toolbarExtras}
    />
  ) : (
    <BaseTextEditor.Toolbar
      floating={floating}
      type={size === 'md' ? 'advanced' : 'simple'}
      data-id={`${dataId}-toolbar`}
      extras={toolbarExtras}
    />
  );

  const hasFooter = !!(footerSlot || toolbarToggle);
  const isFramed = !!(headerSlot || hasFooter);

  // autoGrow: `min-h-18` (72px) matches the intrinsic height of an empty
  // editor — one `<p class="my-2">` plus `p-4` padding. Today intrinsic
  // wins on its own, but this guards against future styling that could
  // shrink the natural baseline (custom paragraph margins, alternate node
  // types, etc.). Editor grows with content from that baseline. Default
  // (no autoGrow) keeps the fixed `h-87` height + manual resize handle.
  //
  // minRows / maxRows cap height via CSS variables so the static
  // `min-h-[var(--editor-min-h)]` / `max-h-[var(--editor-max-h)]` classes
  // reach the tiptap contenteditable (which inherits CSS vars from this
  // wrapper). `TextArea` doesn't need this indirection — it applies its
  // height limit directly via inline style on the textarea itself.
  const inputClassName = cx(
    autoGrow ? 'resize-none p-4' : 'h-87 resize-y p-4',
    autoGrow &&
      (minRows !== undefined ? 'min-h-[var(--editor-min-h)]' : 'min-h-18'),
    autoGrow && maxRows !== undefined && 'max-h-[var(--editor-max-h)]',
    isFramed &&
      'resize-none rounded-none shadow-none ring-0 focus:ring-0 focus:ring-offset-0',
  );

  const editorSizeStyle: CSSProperties | undefined =
    autoGrow && (minRows !== undefined || maxRows !== undefined)
      ? ({
          ...(minRows !== undefined && {
            '--editor-min-h': `${editorRowsToPx(minRows)}px`,
          }),
          ...(maxRows !== undefined && {
            '--editor-max-h': `${editorRowsToPx(maxRows)}px`,
          }),
        } as CSSProperties)
      : undefined;

  const frameClassName = cx(
    'overflow-hidden rounded-lg border border-primary bg-primary shadow-xs',
    'focus-within:border-brand focus-within:ring-1 focus-within:ring-brand',
    isInvalid &&
      'border-error_subtle focus-within:border-error focus-within:ring-error',
  );

  return (
    // Wrapper hosts HTML attributes; BaseTextEditor.Root forwards unknown props
    // to useEditor (tiptap), not the DOM.
    <div
      {...rest}
      style={editorSizeStyle}
    >
      <BaseTextEditor.Root
        content={content}
        onUpdate={({ editor }) => onUpdate(editor.getHTML())}
        className={cx('w-full gap-2', fieldSize === 'md' && 'max-w-lg')}
        inputClassName={inputClassName}
        limit={limit}
        data-id={dataId}
        extraExtensions={extraExtensions}
        isInvalid={isInvalid}
      >
        {toolbar}

        <div className="flex flex-col gap-2">
          {isFramed ? (
            <div className={frameClassName}>
              {headerSlot && (
                <BaseTextEditor.Header className="px-4 pt-3">
                  {headerSlot}
                </BaseTextEditor.Header>
              )}
              <BaseTextEditor.Content />
              {hasFooter && (
                <BaseTextEditor.Footer className="gap-3 px-4 pb-3">
                  {toolbarToggle && (
                    <Button
                      data-id={`${dataId}-toolbar-toggle`}
                      color="link-gray"
                      size="sm"
                      iconLeading={Type01}
                      aria-label={
                        hideToolbar ? 'Show formatting' : 'Hide formatting'
                      }
                      aria-pressed={!hideToolbar}
                      onPress={() => setHideToolbar((v) => !v)}
                    />
                  )}
                  {footerSlot}
                </BaseTextEditor.Footer>
              )}
            </div>
          ) : (
            <BaseTextEditor.Content />
          )}
          {hintText && (
            <BaseTextEditor.HintText>{hintText}</BaseTextEditor.HintText>
          )}
        </div>
      </BaseTextEditor.Root>
    </div>
  );
}
