import React from 'react';
import type { Placement } from 'react-aria';
import { AvatarLabelGroup } from '@/vendor/untitled-ui/base/avatar/avatar-label-group';
import { Dropdown as BaseDropdown, DropdownPopoverProps } from './base';
import { AvatarProps } from '@/components/atoms/Avatar';
import { ChevronDown } from '@untitledui/icons';
import { Button as AriaButton } from 'react-aria-components';
import { cx } from '@/utils/cx';
import { Button } from '@/components/atoms/Button';
import { Avatar } from '@/vendor/untitled-ui/base/avatar/avatar';
import {
  Tooltip,
  TooltipTrigger,
} from '@/components/atoms/Tooltip/base/tooltip';
import { ComponentPropsWithoutRef } from 'react';
import { WithDataId } from '@/types/withDataId';

export type DropdownSectionItem = ComponentPropsWithoutRef<
  typeof BaseDropdown.Item
> & { tooltip?: string };

type IconComponent = typeof ChevronDown;

interface AvatarTriggerProps {
  src?: string;
  status?: AvatarProps['status'];
  title?: string;
  subtitle?: string;
}
export interface DropdownProps extends WithDataId {
  label?: string;
  type: 'button' | 'icon' | 'avatar' | 'label';
  /** @default "md" */
  size?: 'sm' | 'md' | 'lg' | 'xl';
  icon?: IconComponent;
  shouldHideChevron?: boolean;
  avatar?: AvatarTriggerProps;
  sections: { items: DropdownSectionItem[] }[];
  placement?: DropdownPopoverProps['placement'];
  /** Whether the dropdown is disabled */
  isDisabled?: boolean;
  /** Tooltip text to display on hover */
  tooltip?: string;
  /** Placement of the tooltip */
  tooltipPlacement?: Placement;
  /** Styles for Dropodown Popover */
  popoverClassNames?: string;
}

const DropdownTrigger = ({
  type,
  label,
  size,
  icon,
  shouldHideChevron,
  avatar,
  isDisabled,
  tooltip,
  tooltipPlacement = 'top',
  'data-id': dataId,
}: {
  type: 'button' | 'icon' | 'avatar' | 'label';
  label?: string;
  size?: 'sm' | 'md' | 'lg' | 'xl';
  icon?: IconComponent;
  shouldHideChevron?: boolean;
  avatar?: AvatarTriggerProps;
  isDisabled?: boolean;
  tooltip?: string;
  tooltipPlacement?: Placement;
} & WithDataId) => {
  if (type === 'icon') {
    if (icon) {
      const Icon = icon;
      const button = (
        <AriaButton
          aria-label={tooltip || label}
          isDisabled={isDisabled}
          className={(state) =>
            cx(
              'cursor-pointer rounded-md p-1.5 text-fg-quaternary outline-focus-ring transition duration-100 ease-linear',
              (state.isPressed || state.isHovered) &&
                'bg-primary_hover text-fg-quaternary_hover',
              (state.isPressed || state.isFocusVisible) &&
                'outline-2 outline-offset-2',
              state.isDisabled && 'cursor-not-allowed opacity-50',
            )
          }
        >
          <Icon className="size-5 transition-inherit-all" />
        </AriaButton>
      );

      if (isDisabled && tooltip) {
        return (
          <Tooltip
            title={tooltip}
            placement={tooltipPlacement}
          >
            <TooltipTrigger className="cursor-not-allowed">
              <span className="pointer-events-none">{button}</span>
            </TooltipTrigger>
          </Tooltip>
        );
      }

      return button;
    }

    const dotsButton = (
      <BaseDropdown.DotsButton
        data-id={dataId}
        isDisabled={isDisabled}
      />
    );

    if (isDisabled && tooltip) {
      return (
        <Tooltip
          title={tooltip}
          placement={tooltipPlacement}
        >
          <TooltipTrigger className="cursor-not-allowed">
            <span className="pointer-events-none">{dotsButton}</span>
          </TooltipTrigger>
        </Tooltip>
      );
    }

    return dotsButton;
  }

  if (type === 'button') {
    return (
      <Button
        className="group"
        color="secondary"
        size={size && ['sm', 'md'].includes(size) ? 'sm' : 'xl'}
        iconLeading={icon}
        iconTrailing={shouldHideChevron ? undefined : ChevronDown}
        data-id={dataId}
        isDisabled={isDisabled}
        tooltip={tooltip}
        tooltipPlacement={tooltipPlacement}
      >
        {label}
      </Button>
    );
  }

  if (type === 'avatar' && avatar) {
    return (
      <Button
        color="tertiary"
        data-id={dataId}
        isDisabled={isDisabled}
        tooltip={tooltip}
        tooltipPlacement={tooltipPlacement}
      >
        <Avatar
          alt={avatar.title}
          src={avatar.src}
          size="md"
        />
      </Button>
    );
  }

  if (type === 'label' && label) {
    return (
      <Button
        className="*:data-text:no-underline hover:*:data-text:no-underline"
        color="link-gray"
        data-id={dataId}
        size={size && ['sm', 'md'].includes(size) ? 'sm' : 'xl'}
        iconLeading={icon}
        iconTrailing={shouldHideChevron ? undefined : ChevronDown}
        isDisabled={isDisabled}
        tooltip={tooltip}
        tooltipPlacement={tooltipPlacement}
      >
        <span className="px-2 py-1">{label}</span>
      </Button>
    );
  }

  return null;
};

export const Dropdown = ({
  avatar,
  sections,
  label,
  type,
  size,
  icon,
  shouldHideChevron,
  'data-id': dataId,
  placement,
  isDisabled,
  tooltip,
  tooltipPlacement,
  popoverClassNames = '',
}: DropdownProps) => {
  const trigger = (
    <DropdownTrigger
      type={type}
      label={label}
      size={size}
      icon={icon}
      shouldHideChevron={shouldHideChevron}
      avatar={avatar}
      isDisabled={isDisabled}
      tooltip={tooltip}
      tooltipPlacement={tooltipPlacement}
      data-id={`${dataId}-trigger`}
    />
  );

  if (isDisabled) {
    return trigger;
  }

  return (
    <BaseDropdown.Root>
      {trigger}
      <BaseDropdown.Popover
        placement={placement}
        className={popoverClassNames}
      >
        {avatar && (
          <div className="flex gap-3 border-b border-secondary p-3">
            <AvatarLabelGroup
              size="md"
              src={avatar.src}
              status={avatar.status}
              title={avatar.title}
              subtitle={avatar.subtitle}
            />
          </div>
        )}

        <BaseDropdown.Menu>
          {sections.map((section, index) => (
            <React.Fragment key={index}>
              <BaseDropdown.Section>
                {section.items.map((item, index) => (
                  <BaseDropdown.Item
                    key={index}
                    {...item}
                    data-id={`${dataId}-item-${item['data-id']}`}
                    label={item.label}
                  />
                ))}
              </BaseDropdown.Section>
              {index < sections.length - 1 && <BaseDropdown.Separator />}
            </React.Fragment>
          ))}
        </BaseDropdown.Menu>
      </BaseDropdown.Popover>
    </BaseDropdown.Root>
  );
};
