import type { ButtonProps as AriaButtonProps } from 'react-aria-components';
import type { Placement } from 'react-aria';
import {
  Button as BaseButton,
  type ButtonProps as BaseButtonProps,
  type Props as BaseProps,
} from './BaseButton';
import {
  Tooltip,
  TooltipTrigger,
} from '@/components/atoms/Tooltip/base/tooltip';
import { WithDataId } from '@/types/withDataId';
import { cx } from '@/utils/cx';

export type ButtonProps = Omit<BaseButtonProps, 'color'> & {
  onPress?: AriaButtonProps['onPress'];
  color?:
    | BaseButtonProps['color']
    | 'primary'
    | 'secondary'
    | 'tertiary'
    | 'link-gray'
    | 'link-color'
    | 'link-destructive'
    | 'primary-destructive'
    | 'secondary-destructive'
    | 'tertiary-destructive';
  loadingLabel?: string;
  showTextWhileLoading?: boolean;
  /** The tooltip to display when hovering over the button */
  tooltip?: string;
  /** The placement of the tooltip */
  tooltipPlacement?: Placement;
} & WithDataId;

type BaseLinkProps = Exclude<BaseProps, BaseButtonProps>;

export type ButtonLinkProps = Omit<BaseLinkProps, 'color'> &
  Pick<
    ButtonProps,
    | 'color'
    | 'loadingLabel'
    | 'showTextWhileLoading'
    | 'tooltip'
    | 'tooltipPlacement'
  > &
  WithDataId;

export function Button({
  children,
  isDisabled = false,
  isLoading = false,
  color = 'primary',
  className = undefined,
  showTextWhileLoading = true,
  size = 'sm',
  loadingLabel = '',
  tooltip,
  tooltipPlacement = 'top',
  ...props
}: ButtonProps | ButtonLinkProps) {
  const content = (
    <BaseButton
      isDisabled={isDisabled}
      isLoading={isLoading}
      size={size}
      color={color}
      className={className}
      showTextWhileLoading={showTextWhileLoading}
      aria-label={tooltip}
      {...props}
    >
      {isLoading ? loadingLabel : children}
    </BaseButton>
  );

  if (tooltip) {
    return (
      <Tooltip
        title={tooltip}
        placement={tooltipPlacement}
        offset={size === 'sm' ? 6 : 8}
      >
        <TooltipTrigger className={cx(isDisabled && 'cursor-not-allowed')}>
          {content}
        </TooltipTrigger>
      </Tooltip>
    );
  }

  return content;
}
