import { Avatar as BaseAvatar } from '@/vendor/untitled-ui/base/avatar/avatar';
import { ComponentPropsWithoutRef } from 'react';
import { ChannelLogoKey, channelLogos } from './ChannelLogos';
import { cx } from '@/utils/cx';
import { Tooltip } from '@/components/atoms/Tooltip';
import { WithDataId } from '@/types';

export interface ChannelAvatarItem extends Omit<
  ComponentPropsWithoutRef<typeof BaseAvatar>,
  'src' | 'initials' | 'placeholder' | 'placeholderIcon'
> {
  /** Channel key from `channelLogos`. Determines the brand logo and background color. */
  channel: ChannelLogoKey;
  /** Tooltip label shown on hover. When omitted, no tooltip is rendered. */
  tooltip?: string;
  /**
   * When `false`, the avatar is dimmed to indicate the channel is not live.
   * @default true
   */
  isActive?: boolean;
  /** Click handler. When provided, the avatar shows a pointer cursor. */
  onClick?: () => void;
}

export type ChannelAvatarProps = ChannelAvatarItem & WithDataId;

export function ChannelAvatar({
  channel,
  tooltip,
  isActive = true,
  onClick,
  className,
  'data-id': dataId,
  ...props
}: ChannelAvatarItem & WithDataId) {
  const Logo = channelLogos[channel];

  const avatar = (
    <BaseAvatar
      {...props}
      className={cx(
        'outline-none',
        channel === 'homeawayical' && 'bg-[#116DB3]',
        !isActive && 'opacity-[30%]',
        onClick && 'cursor-pointer',
        className,
      )}
      placeholderIcon={() => (
        <Logo
          className={cx('w-full', channel === 'homeawayical' && 'w-[50%]')}
        />
      )}
    />
  );

  return tooltip ? (
    <Tooltip
      title={tooltip}
      data-id={`${dataId}-tooltip`}
      triggerProps={{
        className: 'flex leading-none',
        onClick: onClick,
      }}
    >
      <div className="inline-flex">{avatar}</div>
    </Tooltip>
  ) : (
    <div
      onClick={onClick}
      className="inline-flex"
    >
      {avatar}
    </div>
  );
}
