import { ComponentPropsWithoutRef } from 'react';

import { NativeSelect as BaseNativeSelect } from '@/vendor/untitled-ui/base/select/select-native';
import { WithDataId } from '@/types/withDataId';

export type NativeSelectProps = ComponentPropsWithoutRef<
  typeof BaseNativeSelect
> &
  WithDataId;
export function NativeSelect({
  label,
  'data-id': dataId,
  ...props
}: NativeSelectProps) {
  return (
    <BaseNativeSelect
      label={label}
      data-id={dataId}
      {...props}
    />
  );
}
