import {
  isValidElement,
  useCallback,
  useEffect,
  useRef,
  useState,
} from 'react';
import { match } from 'ts-pattern';

import { LoadingIndicator } from '@/components/atoms/LoadingIndicator';
import { WithDataId } from '@/types/withDataId';
import { cx } from '@/utils/cx';

import { Table as BaseTable, TableCard as BaseTableCard } from './base';
import {
  COL_SIZE_CLASS,
  DEFAULT_TEXTS,
  DROP_INDICATOR_CLASSES,
  TABLE_CARD_HEADER_PADDING,
  TABLE_CELL_PADDING,
  TABLE_FOOTER_CELL_PADDING,
  TABLE_HEAD_PADDING,
  TABLE_ROW_HEIGHT,
  TREE_LINE_INDENT,
} from './_consts';
import { useColumns, useStickyColumns, useTableItems } from './_hooks';
import { TableColumnsSelector } from './ColumnsSelector';
import { TableHead } from './Head';
import { TableEmptyState } from './TableEmptyState';
import { TablePagination } from './TablePagination';
import { TreeCell } from './TreeCell';
import { TableProps, TableRow, type SortDirection } from './_types';
import { Menu01 } from '@/icons';
import { ButtonUtility } from '@/components/atoms/ButtonUtility';

const FOOTER_ROW_ID = '__hostaway-table-footer__';

function toAriaDirection(dir: SortDirection): 'ascending' | 'descending' {
  return match(dir)
    .with('asc', () => 'ascending' as const)
    .with('desc', () => 'descending' as const)
    .with('ascending', () => 'ascending' as const)
    .with('descending', () => 'descending' as const)
    .exhaustive();
}

function toConsumerDirection(
  ariaDir: 'ascending' | 'descending',
  inputDir: SortDirection,
): SortDirection {
  return match(inputDir)
    .with('asc', 'desc', () => (ariaDir === 'ascending' ? 'asc' : 'desc'))
    .with('ascending', 'descending', () => ariaDir)
    .exhaustive();
}

export function Table<TData extends TableRow>({
  getRowId,
  columnDefs = [],
  defaultColDef,
  rowData = [],
  tableCardHeader = null,
  pagination = false,
  paginationCurrentPage = 1,
  paginationTotalItems = 0,
  paginationPageSize = 20,
  paginationPageSizeSelector = true,
  onPaginationChanged = undefined,
  onPageNumberChange = undefined,
  onPageLimitChange = undefined,
  rowProps,
  emptyState,
  isLoading = false,
  columnsSelectorEnabled = false,
  columnsSelectorTabs,
  t,
  paginationText,
  onColumnsSelectionChange,
  columnOrder,
  onColumnOrderChange,
  columnsSelection,
  onColumnsSelectedChange,
  'data-id': dataId,
  sortDescriptor,
  onSortChange,
  rounded = true,
  card = true,
  getChildRows,
  collapsible = false,
  showFooter = false,
  size = 'md',
  dragHandleVisible = false,
  ...tableProps
}: TableProps<TData> & WithDataId) {
  const texts = {
    loading: { ...DEFAULT_TEXTS.loading, ...t?.loading },
  };

  const isColumnOrderControlled = columnOrder !== undefined;
  const [internalColumnOrder, setInternalColumnOrder] = useState<
    Record<string | number, number>
  >({});
  const resolvedColumnOrder = isColumnOrderControlled
    ? columnOrder
    : internalColumnOrder;
  const handleColumnOrderChange = (
    newOrder: Record<string | number, number>,
  ) => {
    if (!isColumnOrderControlled) {
      setInternalColumnOrder(newOrder);
    }
    onColumnOrderChange?.(newOrder);
  };

  const { columns, setColumns, visibleColumns } = useColumns(
    columnDefs,
    columnsSelectorEnabled,
    resolvedColumnOrder,
    columnsSelection,
  );

  const hasPinnedColumns = visibleColumns.some((c) => c.pinned);
  const stickyCallback = useStickyColumns(visibleColumns, {
    enabled: hasPinnedColumns,
  });
  const wrapperRef = useRef<HTMLDivElement | null>(null);
  const stickyRef = useCallback(
    (node: HTMLDivElement | null) => {
      stickyCallback(node);
      wrapperRef.current = node;
    },
    [stickyCallback],
  );

  const { items, hasChildRows, collapsedKeys, toggleExpanded } = useTableItems(
    rowData,
    getRowId,
    getChildRows,
    collapsible,
  );

  const itemsWithFooter = showFooter
    ? [
        ...items,
        {
          __row: undefined as unknown as TData,
          __index: items.length,
          __meta: { isParent: false, isChild: false, isLastChild: false },
          id: FOOTER_ROW_ID,
        },
      ]
    : items;

  const isEmpty = !isLoading && (!rowData || rowData.length === 0);

  const rowHeight = TABLE_ROW_HEIGHT[size];

  // Restrict drag to the handle button only. Re-runs on isEmpty toggles
  // because the wrapper unmounts in the empty state, so the ref needs to
  // be re-attached when data arrives.
  useEffect(() => {
    if (!dragHandleVisible) return;
    const el = wrapperRef.current;
    if (!el) return;

    let pointerTarget: HTMLElement | null = null;
    const onPointerDown = (e: PointerEvent) => {
      pointerTarget = e.target as HTMLElement;
    };
    const onDragStart = (e: DragEvent) => {
      if (!pointerTarget?.closest('[data-drag-handle]')) {
        e.preventDefault();
      }
    };
    const onDragOver = (e: DragEvent) => e.preventDefault();

    el.addEventListener('pointerdown', onPointerDown, { capture: true });
    el.addEventListener('dragstart', onDragStart, { capture: true });
    el.addEventListener('dragover', onDragOver);
    return () => {
      el.removeEventListener('pointerdown', onPointerDown, { capture: true });
      el.removeEventListener('dragstart', onDragStart, { capture: true });
      el.removeEventListener('dragover', onDragOver);
    };
  }, [dragHandleVisible, isEmpty]);

  return (
    <BaseTableCard.Root
      size={size}
      className={cx(
        'relative flex flex-col',
        !rounded && 'rounded-none',
        !card && 'shadow-none ring-0',
      )}
    >
      {tableCardHeader ? (
        <div
          className={cx(
            'relative flex flex-col items-start gap-4 border-b border-secondary bg-primary px-4 md:flex-row',
            TABLE_CARD_HEADER_PADDING[size],
          )}
        >
          {tableCardHeader}
        </div>
      ) : null}

      {isEmpty ? (
        <TableEmptyState emptyState={emptyState} />
      ) : (
        <div className="relative flex min-h-0 flex-1 flex-col">
          {columnsSelectorEnabled && (
            <div
              className={cx(
                'absolute right-0 z-51',
                size === 'sm' ? 'top-0.5' : 'top-1.5',
              )}
            >
              <TableColumnsSelector
                columnDefs={columns}
                columnsSelection={columnsSelection}
                onColumnsSelectedChange={onColumnsSelectedChange}
                onColumnsSelectionChange={(cols) => {
                  setColumns(cols);
                  onColumnsSelectionChange?.(cols);
                }}
                columnsSelectorTabs={columnsSelectorTabs}
                columnOrder={resolvedColumnOrder}
                onColumnOrderChange={handleColumnOrderChange}
                t={t}
                data-id={`${dataId}-columnSelector`}
              />
            </div>
          )}
          <div
            ref={stickyRef}
            className={cx(
              'min-h-0 flex-1 [&>div]:h-full [&>div]:overflow-auto! [&_thead]:sticky [&_thead]:top-0 [&_thead]:z-50',
              columnsSelectorEnabled && '[&_thead_th:last-child]:pr-15',
            )}
            style={
              {
                '--row-height': `${rowHeight}px`,
              } as React.CSSProperties
            }
          >
            <BaseTable
              {...tableProps}
              size={size}
              disabledKeys={[FOOTER_ROW_ID]}
              sortDescriptor={
                sortDescriptor
                  ? {
                      ...sortDescriptor,
                      direction: toAriaDirection(sortDescriptor.direction),
                    }
                  : undefined
              }
              onSortChange={
                onSortChange
                  ? (ariaDescriptor) => {
                      onSortChange({
                        column: ariaDescriptor.column as string,
                        direction: sortDescriptor
                          ? toConsumerDirection(
                              ariaDescriptor.direction,
                              sortDescriptor.direction,
                            )
                          : ariaDescriptor.direction,
                      });
                    }
                  : undefined
              }
              className={cx(
                '[&_tbody_tr]:[content-visibility:auto] [&_tbody_tr]:[contain-intrinsic-block-size:var(--row-height)]',
                DROP_INDICATOR_CLASSES,
                !dragHandleVisible &&
                  '[&[data-allows-dragging]_tbody_tr]:cursor-grab',
              )}
            >
              <BaseTable.Header>
                {visibleColumns.map(({ cellRenderer: _, ...col }) => (
                  <TableHead
                    key={col.id}
                    {...defaultColDef}
                    {...col}
                    className={(state) =>
                      cx(
                        TABLE_HEAD_PADDING[size],
                        typeof col.className === 'function'
                          ? col.className(state)
                          : col.className,
                      )
                    }
                    data-id={`${dataId}-head-${col.id}`}
                  />
                ))}
              </BaseTable.Header>
              <BaseTable.Body items={isLoading ? [] : itemsWithFooter}>
                {(item) => {
                  if (item.id === FOOTER_ROW_ID) {
                    return (
                      <BaseTable.Row
                        id={item.id}
                        className="bg-secondary hover:bg-secondary sticky bottom-0 z-20 !h-11 font-semibold uppercase"
                        isFooterRow
                      >
                        {visibleColumns.map((col, colIndex) => {
                          if (!col.id) return <BaseTable.Cell key={colIndex} />;

                          const cellContent = col.footerCell?.() ?? null;

                          return (
                            <BaseTable.Cell
                              key={col.id}
                              data-id={`${dataId}-footer-cell-${col.id}`}
                              className={TABLE_FOOTER_CELL_PADDING[size]}
                            >
                              {cellContent as React.ReactNode}
                            </BaseTable.Cell>
                          );
                        })}
                      </BaseTable.Row>
                    );
                  }

                  const { __meta: meta } = item;
                  const isCollapsed =
                    collapsible && !!collapsedKeys?.has(item.id);

                  const isLastDataRow = item.__index === items.length - 1;

                  return (
                    <BaseTable.Row
                      {...rowProps}
                      data-child-row={meta.isChild || undefined}
                      data-last-child={meta.isLastChild || undefined}
                      className={(state) =>
                        cx(
                          typeof rowProps?.className === 'function'
                            ? rowProps.className(state)
                            : rowProps?.className,
                          tableProps.onRowAction && 'cursor-pointer',
                          meta.isParent &&
                            !isCollapsed &&
                            '[&>td]:after:bg-transparent',
                          meta.isChild &&
                            !meta.isLastChild &&
                            '[&>td]:after:bg-transparent',
                          showFooter &&
                            isLastDataRow &&
                            '[&>td]:after:bg-transparent',
                        )
                      }
                      id={item.id}
                    >
                      {visibleColumns.map((col, colIndex) => {
                        if (!col.id) return <BaseTable.Cell key={colIndex} />;

                        let cellContent: React.ReactNode;

                        if (typeof col.cellRenderer === 'function') {
                          cellContent = col.cellRenderer(item.__row);
                        } else {
                          const value =
                            typeof item.__row === 'object'
                              ? item.__row[col.id]
                              : item.__row;
                          cellContent = isValidElement(value)
                            ? value
                            : String(value);
                        }

                        const isSelectionMode =
                          tableProps.selectionMode !== undefined &&
                          tableProps.selectionMode !== 'none';

                        if (colIndex === 0 && hasChildRows) {
                          cellContent = (
                            <TreeCell
                              meta={meta}
                              itemId={item.id}
                              collapsible={collapsible}
                              isCollapsed={isCollapsed}
                              toggleExpanded={toggleExpanded}
                              treeLineLeft={TREE_LINE_INDENT(
                                size,
                                isSelectionMode,
                                dragHandleVisible,
                              )}
                              data-id={`${dataId}-tree-cell-${item.id}`}
                            >
                              {cellContent}
                            </TreeCell>
                          );
                        }

                        const showDragHandle =
                          dragHandleVisible && colIndex === 0;

                        if (showDragHandle) {
                          return (
                            <BaseTable.Cell
                              key={col.id}
                              className={TABLE_CELL_PADDING[size]}
                            >
                              <div
                                className={cx(
                                  'flex items-center',
                                  col.size && COL_SIZE_CLASS[col.size],
                                  meta.isChild && 'pl-6',
                                )}
                              >
                                {!meta.isChild && (
                                  <ButtonUtility
                                    data-id={`${dataId}-drag-${item.id}`}
                                    icon={Menu01}
                                    size="xs"
                                    slot="drag"
                                    color="tertiary"
                                    data-drag-handle
                                    style={{ pointerEvents: 'auto' }}
                                    className="p-0 pr-2 cursor-grab data-pressed:cursor-grabbing"
                                  />
                                )}
                                {cellContent}
                              </div>
                            </BaseTable.Cell>
                          );
                        }

                        return (
                          <BaseTable.Cell
                            key={col.id}
                            className={TABLE_CELL_PADDING[size]}
                          >
                            <div
                              className={cx(
                                'break-words',
                                col.size && COL_SIZE_CLASS[col.size],
                              )}
                            >
                              {cellContent}
                            </div>
                          </BaseTable.Cell>
                        );
                      })}
                    </BaseTable.Row>
                  );
                }}
              </BaseTable.Body>
            </BaseTable>
          </div>

          {isLoading ? (
            <div className="flex items-center justify-center py-10">
              <LoadingIndicator
                data-id={`${dataId}-loading`}
                size="sm"
                label={texts.loading.labelLoading}
              />
            </div>
          ) : null}
        </div>
      )}

      {pagination ? (
        <TablePagination
          paginationCurrentPage={paginationCurrentPage}
          paginationTotalItems={paginationTotalItems}
          paginationPageSize={paginationPageSize}
          paginationPageSizeSelector={paginationPageSizeSelector}
          paginationText={paginationText}
          onPaginationChanged={onPaginationChanged}
          onPageNumberChange={onPageNumberChange}
          onPageLimitChange={onPageLimitChange}
          t={t}
        />
      ) : null}
    </BaseTableCard.Root>
  );
}
