import {
  MenuTrigger as AriaMenuTrigger,
  Menu as AriaMenu,
  MenuItem as AriaMenuItem,
  Popover as AriaPopover,
} from 'react-aria-components';
import type {
  MenuTriggerProps as AriaMenuTriggerProps,
  MenuProps as AriaMenuProps,
  MenuItemProps as AriaMenuItemProps,
  PopoverProps as AriaPopoverProps,
} from 'react-aria-components';
import { Check } from '@/icons';
import { CheckboxBase } from '@/vendor/untitled-ui/base/checkbox/checkbox';
import { cx } from '@/utils/cx';

export function MenuTrigger(props: AriaMenuTriggerProps) {
  return <AriaMenuTrigger {...props} />;
}

export function MenuPopover({
  className,
  ...props
}: Omit<AriaPopoverProps, 'className'> & { className?: string }) {
  return (
    <AriaPopover
      containerPadding={0}
      className={cx(
        'max-w-[min(32rem,90vw)] rounded-lg bg-primary shadow-lg ring ring-secondary_alt',
        className,
      )}
      {...props}
    />
  );
}

export function MenuList<T extends object>({
  className,
  ...props
}: Omit<AriaMenuProps<T>, 'className'> & { className?: string }) {
  return (
    <AriaMenu
      className={cx(
        'flex flex-col gap-0.5 px-1.5 py-1 outline-hidden select-none overflow-y-auto',
        className,
      )}
      {...props}
    />
  );
}

export type MenuItemProps = Omit<
  AriaMenuItemProps,
  'className' | 'children' | 'isSelected'
> & {
  className?: string;
  children?: React.ReactNode;
  leading?: React.ReactNode;
  trailing?: React.ReactNode;
  withCheckbox?: boolean;
  isSelected?: boolean;
  withCheck?: boolean;
};

export function MenuItem({
  className,
  leading,
  trailing,
  withCheckbox,
  isSelected,
  withCheck,
  children,
  ...props
}: MenuItemProps) {
  return (
    <AriaMenuItem
      className={cx(
        'cursor-pointer rounded-md px-2.5 py-2 hover:bg-primary_hover text-secondary text-sm outline-hidden',
        (leading || trailing || withCheckbox || withCheck) &&
          'flex items-center gap-2',
        isSelected && 'bg-primary_hover',
        className,
      )}
      aria-selected={isSelected || undefined}
      {...props}
    >
      {withCheckbox && (
        <CheckboxBase
          isSelected={isSelected}
          size="sm"
        />
      )}
      {leading}
      <span className="flex-1 truncate">{children}</span>
      {trailing}
      {withCheck && isSelected && <Check className="size-3.5 shrink-0" />}
    </AriaMenuItem>
  );
}
