import React from 'react';

export interface FieldGroupProps extends React.ComponentProps<'div'> {
  children: React.ReactNode;
  className?: string;
}

export function FieldGroup({
  children,
  className = '',
  ...rest
}: FieldGroupProps) {
  const childrenArray = React.Children.toArray(children);
  const childCount = childrenArray.length;

  const baseClasses = 'flex w-full gap-4';

  // Auto-determine width based on number of children
  const getWidthClass = (count: number) => {
    switch (count) {
      case 1:
        return '[&>*]:w-full';
      case 2:
        return '[&>*]:w-1/2';
      case 3:
        return '[&>*]:w-1/3';
      case 4:
        return '[&>*]:w-1/4';
      default:
        // For 5+ children, use flex-1 for equal distribution
        return '[&>*]:flex-1';
    }
  };

  const widthClass = getWidthClass(childCount);
  const combinedClasses = `${baseClasses} ${widthClass} ${className}`.trim();

  return (
    <div
      className={combinedClasses}
      {...rest}
    >
      {children}
    </div>
  );
}
