import { useMemo, useState } from 'react';
import { InputSearchField } from '@/components/atoms/Input';
import { cx } from '@/utils/cx';
import { WithDataId } from '@/types/withDataId';
import {
  MenuTrigger,
  MenuPopover,
  MenuList,
  MenuItem as MenuItemPrimitive,
} from './MenuPrimitives';

export type MenuOption = {
  label: string;
  value: string;
};

export type MenuGroup = {
  label: string;
  items: MenuOption[];
};

export type MenuProps = {
  groups: MenuGroup[];
  onSelect: (item: MenuOption, groupLabel: string) => void;
  selectedValues?: Set<string>;
  isOpen?: boolean;
  onOpenChange?: (isOpen: boolean) => void;
  withSearch?: boolean;
  searchPlaceholder?: string;
  children: React.ReactNode;
  className?: string;
  placement?:
    | 'bottom'
    | 'bottom start'
    | 'bottom end'
    | 'top'
    | 'top start'
    | 'top end';
  closeOnSelect?: boolean;
} & WithDataId;

export function Menu({
  groups,
  onSelect,
  selectedValues,
  isOpen: controlledIsOpen,
  onOpenChange,
  withSearch = true,
  searchPlaceholder = 'Search',
  children,
  className,
  placement = 'bottom start',
  closeOnSelect = false,
  'data-id': dataId,
}: MenuProps) {
  const isControlled = controlledIsOpen !== undefined;
  const [internalIsOpen, setInternalIsOpen] = useState(false);
  const isOpen = isControlled ? controlledIsOpen : internalIsOpen;
  const [selectedGroupIndex, setSelectedGroupIndex] = useState(0);
  const [searchTerm, setSearchTerm] = useState('');

  const selectedGroup = groups[selectedGroupIndex];

  const filteredItems = useMemo(
    () =>
      selectedGroup?.items.filter((item) =>
        item.label.toLowerCase().includes(searchTerm.trim().toLowerCase()),
      ) ?? [],
    [selectedGroup, searchTerm],
  );

  const handleOpenChange = (open: boolean) => {
    if (!isControlled) setInternalIsOpen(open);
    onOpenChange?.(open);
    if (!open) setSearchTerm('');
  };

  return (
    <MenuTrigger
      isOpen={isOpen}
      onOpenChange={handleOpenChange}
    >
      {children}

      <MenuPopover
        placement={placement}
        className={className}
      >
        <div className="grid grid-cols-[250px_250px] divide-x divide-secondary_alt">
          <MenuList selectionMode="multiple">
            {groups.map((group, index) => (
              <MenuItemPrimitive
                key={group.label}
                id={group.label}
                className={cx(
                  'font-semibold w-full text-left',
                  selectedGroupIndex === index
                    ? 'bg-primary_hover text-secondary_hover'
                    : '',
                )}
                onAction={() => {
                  setSelectedGroupIndex(index);
                  setSearchTerm('');
                }}
                data-id={`${dataId}-group-${index}`}
              >
                {group.label}
              </MenuItemPrimitive>
            ))}
          </MenuList>

          <div className="px-1.5 py-1 flex flex-col gap-1 max-h-80">
            {withSearch && (
              <InputSearchField
                placeholder={searchPlaceholder}
                value={searchTerm}
                onChange={setSearchTerm}
                data-id={`${dataId}-search`}
                className={cx('text-sm mt-[5px]')}
                iconClassName="size-4"
              />
            )}
            <MenuList
              className="h-min"
              selectionMode="multiple"
            >
              {filteredItems.map((item) => (
                <MenuItemPrimitive
                  key={item.value}
                  id={item.value}
                  isSelected={selectedValues?.has(item.value)}
                  withCheck={!!selectedValues}
                  onAction={() => {
                    onSelect(item, selectedGroup.label);
                    if (closeOnSelect) {
                      handleOpenChange(false);
                    }
                  }}
                  data-id={`${dataId}-item-${item.value}`}
                >
                  <span className="text-sm">{item.label}</span>
                </MenuItemPrimitive>
              ))}
            </MenuList>
          </div>
        </div>
      </MenuPopover>
    </MenuTrigger>
  );
}
