import { useRef, type FormEvent } from 'react';
import { Send01 } from '@untitledui/icons';
import { Button } from '@/components/atoms/Button/BaseButton';
import { InputBase } from '@/components/atoms/Input/base/input';
import { cx } from '@/utils/cx';
import { WithDataId } from '@/types/withDataId';

type MessageSendActionProps = Omit<
  React.ComponentPropsWithoutRef<'form'>,
  'onSubmit'
> &
  WithDataId & {
    onSubmit: (message: string) => void;
    placeholder: string;
  };

export type MessageSendActionInputProps = MessageSendActionProps;

export const MessageSendActionInput = ({
  onSubmit,
  className,
  placeholder,
  ...props
}: MessageSendActionInputProps) => {
  const formRef = useRef<HTMLFormElement>(null);

  const handleSubmit = (e: FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.target as HTMLFormElement);
    const message = formData.get('message') as string;
    onSubmit(message);
    handleClear();
  };

  const handleClear = () => {
    const form = formRef.current;
    if (form) {
      form.reset();
    }
  };
  //TODO replace InputBase and Button with atom components (the wrappers)
  return (
    <form
      ref={formRef}
      className={cx('flex h-max w-90 items-center gap-3', className)}
      onSubmit={handleSubmit}
      {...props}
    >
      <InputBase
        aria-label={placeholder}
        size="md"
        placeholder={placeholder}
        name="message"
      />

      <Button
        type="submit"
        size="sm"
        color="secondary"
        iconLeading={Send01}
      />
    </form>
  );
};
