import { cx } from '@/utils/cx';
import { ReactNode, Ref } from 'react';
import { Radio as AriaRadio } from 'react-aria-components';
import { RadioButtonBase } from '@/vendor/untitled-ui/base/radio-buttons/radio-buttons';
import { ComponentPropsWithoutRef } from 'react';
import { WithDataId } from '@/types/withDataId';

export type AriaRadioProps = ComponentPropsWithoutRef<typeof AriaRadio>;
export interface RadioButtonProps extends AriaRadioProps, WithDataId {
  label?: string | ReactNode;
  hint?: string | ReactNode;
  ref?: Ref<HTMLLabelElement>;
  /** @deprecated No longer affects rendering. Accepted for backwards compatibility with consumers still passing it. */
  size?: 'sm' | 'md';
}

// NOTE: This is a low-level visual wrapper around `AriaRadio`, intended primarily for Storybook/demo composition.
// In application code, prefer using the higher-level radio field components from this library instead of `RadioButton` directly.
export const RadioButton = ({
  label,
  hint,
  className,
  size: _size,
  ...props
}: RadioButtonProps) => {
  return (
    <AriaRadio
      {...props}
      className={(renderProps) =>
        cx(
          'flex items-start gap-2',
          renderProps.isDisabled && 'cursor-not-allowed',
          typeof className === 'function' ? className(renderProps) : className,
        )
      }
    >
      {({ isSelected, isDisabled, isFocusVisible }) => (
        <>
          <RadioButtonBase
            isSelected={isSelected}
            isDisabled={isDisabled}
            isFocusVisible={isFocusVisible}
            className={label || hint ? 'mt-0.5' : ''}
          />
          {(label || hint) && (
            <div className="inline-flex flex-col">
              {label && (
                <p className="text-sm font-medium text-secondary select-none">
                  {label}
                </p>
              )}
              {hint && (
                <span
                  className="text-sm text-tertiary"
                  onClick={(event) => event.stopPropagation()}
                >
                  {hint}
                </span>
              )}
            </div>
          )}
        </>
      )}
    </AriaRadio>
  );
};
