import { Toggle as BaseToggle } from './BaseToggle';
import { ComponentPropsWithoutRef } from 'react';
import { WithDataId } from '@/types/withDataId';

export type ToggleProps = ComponentPropsWithoutRef<typeof BaseToggle> &
  WithDataId & {
    /** @deprecated No longer affects rendering. Accepted for backwards compatibility with consumers still passing it. */
    slim?: boolean;
    /** @deprecated No longer affects rendering. Accepted for backwards compatibility with consumers still passing it. */
    size?: 'sm' | 'md';
  };

export function Toggle({ slim: _slim, size: _size, ...props }: ToggleProps) {
  return <BaseToggle {...props} />;
}
