import { PaymentInput } from '@/components/atoms/Input/base/input-payment';
import { WithDataId } from '@/types/withDataId';
import {
  FieldWrapper,
  FieldWrapperProps,
} from '@/components/molecules/FieldWrapper/FieldWrapper';

export type InputCardNumberFieldProps = React.ComponentPropsWithoutRef<
  typeof PaymentInput
> &
  WithDataId &
  Omit<FieldWrapperProps, 'children'>;

export function InputCardNumberField({
  label,
  hint,
  isInvalid,
  isRequired,
  tooltip,
  description,
  id = '',
  fieldSize = 'md',
  labelPosition = 'left',
  ...props
}: InputCardNumberFieldProps) {
  return (
    <FieldWrapper
      id={id}
      label={label}
      hint={hint}
      isInvalid={isInvalid}
      isRequired={isRequired}
      tooltip={tooltip}
      description={description}
      fieldSize={fieldSize}
      labelPosition={labelPosition}
    >
      <PaymentInput
        isInvalid={isInvalid}
        {...props}
      />
    </FieldWrapper>
  );
}
