import { match } from 'ts-pattern';

import { sortCx } from '@/utils/cx';

import type { ColDef, TableProps, TableRow } from '../_types';

type TableSize = NonNullable<TableProps<TableRow>['size']>;
type ColSize = NonNullable<ColDef<TableRow>['size']>;

/**
 * Width constraints applied to each column-size tier. The `<th>` and the
 * cell-content wrapper both consume this so the rendered widths stay aligned.
 */
export const COL_SIZE_CLASS: Record<ColSize, string> = sortCx({
  fill: '',
  xs: 'w-[24px]',
  sm: 'min-w-[64px] max-w-[120px]',
  md: 'min-w-[120px] max-w-[200px]',
  lg: 'min-w-[200px] max-w-[360px]',
});

/**
 * Pixel row-height per table size. Exposed as the `--row-height` CSS variable
 * so `content-visibility` reservations match the actual rendered row.
 */
export const TABLE_ROW_HEIGHT: Record<TableSize, number> = {
  sm: 56,
  md: 72,
};

/** Inline padding applied to each `<th>` based on the table size. */
export const TABLE_HEAD_PADDING: Record<TableSize, string> = {
  sm: 'pr-4 first:pl-3 last:pr-3',
  md: 'pr-6 first:pl-4 last:pr-4',
};

/**
 * Margin/padding applied to the inner `<div>` of every body cell. Implemented
 * via child selectors because the cell itself has no padding (the inner div
 * carries the size-constrained min/max widths).
 */
export const TABLE_CELL_PADDING: Record<TableSize, string> = {
  sm: '[&>div]:my-2 [&>div]:mr-4 first:[&>div]:ml-3 last:[&>div]:mr-3',
  md: '[&>div]:my-4 [&>div]:mr-6 first:[&>div]:ml-4 last:[&>div]:mr-4',
};

/** Padding applied to footer cells. Mirrors the body-cell horizontal rhythm. */
export const TABLE_FOOTER_CELL_PADDING: Record<TableSize, string> = {
  sm: 'px-4 py-2',
  md: 'px-6 py-2',
};

/** Padding for the `tableCardHeader` slot wrapper. */
export const TABLE_CARD_HEADER_PADDING: Record<TableSize, string> = {
  sm: 'py-4 md:px-5',
  md: 'py-5 md:px-6',
};

/**
 * Horizontal indent of the vertical connector line in collapsible-tree rows.
 * Must land directly under the parent row's expand chevron, whose position
 * shifts with selection-checkbox and drag-handle presence.
 */
export const TREE_LINE_INDENT = (
  size: TableSize,
  hasSelection: boolean,
  hasDragHandle: boolean,
) =>
  match({ size, hasSelection, hasDragHandle })
    .with({ hasSelection: true, hasDragHandle: true }, () => 'left-11')
    .with({ hasSelection: true }, () => 'left-5')
    .with({ hasDragHandle: true, size: 'sm' }, () => 'left-11')
    .with({ hasDragHandle: true, size: 'md' }, () => 'left-12')
    .with({ size: 'sm' }, () => 'left-5')
    .with({ size: 'md' }, () => 'left-6')
    .exhaustive();
