import { ButtonUtility } from '@/components/atoms/ButtonUtility';
import { cx } from '@/utils/cx';
import { ChevronDown, ChevronRight } from '@/icons';
import type { WithDataId } from '@/types/withDataId';

import type { TableItemMeta } from './_hooks/useTableItems';
import type { TableRowIdentifier } from './_types';

interface TreeCellProps extends WithDataId {
  meta: TableItemMeta;
  itemId: TableRowIdentifier;
  collapsible: boolean;
  isCollapsed: boolean;
  toggleExpanded?: (key: TableRowIdentifier) => void;
  children: React.ReactNode;
  treeLineLeft?: string;
}

export function TreeCell({
  meta,
  itemId,
  collapsible,
  isCollapsed,
  toggleExpanded,
  children,
  treeLineLeft,
  'data-id': dataId,
}: TreeCellProps) {
  const { isChild, isLastChild, isParent } = meta;

  const showToggle = collapsible && isParent;
  const showTreeLines = (isParent && !isCollapsed) || isChild;

  const handleToggleClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    toggleExpanded?.(itemId);
  };

  return (
    <div className="flex items-center min-w-0">
      <div className={cx('w-4 aspect-square flex', isChild ? 'mr-8' : 'mr-2')}>
        {showToggle && (
          <ButtonUtility
            data-id={`${dataId}-toggle`}
            size="xs"
            color="tertiary"
            icon={isCollapsed ? ChevronRight : ChevronDown}
            className="p-0"
            onClick={handleToggleClick}
          />
        )}

        {showTreeLines && (
          <>
            <div
              className={cx(
                'absolute w-4 -translate-x-[0.5px] translate-y-[0.5px] bottom-0 border-l border-primary',
                showToggle && 'mt-2',
                isChild ? 'top-0' : 'top-1/2',
                isLastChild && 'bottom-1/2 border-b rounded-bl',
                treeLineLeft,
              )}
            />
            {isChild && !isLastChild && (
              <div
                className={cx(
                  'absolute top-1/2 -translate-y-1/2 w-4 h-px bg-border-primary',
                  treeLineLeft,
                )}
              />
            )}
          </>
        )}
      </div>
      <div className="min-w-0 flex-1">{children}</div>
    </div>
  );
}
