const TEMPLATE_VAR_REGEX = /\{\{([^{}]*)\}\}/g;

const ESCAPE_MAP: Record<string, string> = {
  '&': '&amp;',
  '<': '&lt;',
  '>': '&gt;',
  '"': '&quot;',
  "'": '&#39;',
};

const ESCAPE_REGEX = /[&<>"']/g;

const ZERO_WIDTH_SPACE = String.fromCharCode(0x200b);

export const TEMPLATE_VAR_HIGHLIGHT_CLASS =
  'rounded-sm outline outline-1 outline-primary font-medium text-primary';
export const TEMPLATE_VAR_BRACE_CLASS = 'text-placeholder_subtle';

export function highlightTemplateVars(
  text: string,
  validKeywords: Set<string>,
) {
  const escaped = text.replace(ESCAPE_REGEX, (ch) => ESCAPE_MAP[ch]);

  const highlighted = escaped.replace(TEMPLATE_VAR_REGEX, (match, inner) => {
    if (!validKeywords.has(match)) {
      return match;
    }

    return `<span class="${TEMPLATE_VAR_HIGHLIGHT_CLASS}"><span class="${TEMPLATE_VAR_BRACE_CLASS}">{{</span>${inner}<span class="${TEMPLATE_VAR_BRACE_CLASS}">}}</span></span>`;
  });

  // A trailing "\n" in white-space:pre-wrap doesn't produce a visible empty
  // line-box, but a <textarea> does — so the caret sits on a line the backdrop
  // hasn't rendered. A zero-width space gives the final line something to
  // render around.
  return text.endsWith('\n')
    ? `${highlighted}${ZERO_WIDTH_SPACE}`
    : highlighted;
}
