import { useMemo } from 'react';
import { FieldWrapper } from '@/components/molecules/FieldWrapper';
import {
  TextEditor,
  useEditorContext,
} from '@/components/molecules/TextEditor/TextEditor';
import { TemplateVarsHighlight } from './_extensions';
import type { FieldTemplaterProps } from './_types';
import { formatTemplate } from './_utils';
import { TemplaterMenu } from './TemplaterMenu';

type FieldTextEditorTemplaterProps = Omit<
  FieldTemplaterProps<typeof TextEditor>,
  'component' | 'menuTopPos' | 'menuRightPos'
>;

function FieldTextEditorTemplaterMenu({
  templateItems,
  isFormatTemplateItems,
  'data-id': dataId,
}: {
  templateItems: string[];
  isFormatTemplateItems: boolean;
  'data-id': string;
}) {
  const { editor, isDisabled } = useEditorContext();

  if (isDisabled) return null;

  const handleSelect = (item: string) => {
    const inserted = isFormatTemplateItems ? formatTemplate(item) : item;
    editor.chain().focus().insertContent(inserted).run();
  };

  return (
    <TemplaterMenu
      data-id={dataId}
      templateItems={templateItems}
      onSelect={handleSelect}
      isFormatTemplateItems={isFormatTemplateItems}
    />
  );
}

export function FieldTextEditorTemplater({
  label,
  hint,
  isInvalid,
  isRequired,
  tooltip,
  description,
  id = '',
  fieldSize = 'md',
  labelPosition = 'left',

  templateItems,
  isFormatTemplateItems = true,
  'data-id': dataId,
  extraExtensions,
  ...textEditorProps
}: FieldTextEditorTemplaterProps) {
  // Highlight whatever string actually gets inserted: when isFormatTemplateItems
  // is true items are wrapped as {{item}}, otherwise they're already pre-wrapped
  // (e.g. callers pass `{{name}}` directly), so we use them as-is for matching.
  const validKeywords = useMemo(
    () =>
      new Set(
        isFormatTemplateItems
          ? templateItems.map((item) => formatTemplate(item))
          : templateItems,
      ),
    [templateItems, isFormatTemplateItems],
  );

  const highlightExtensions = useMemo(
    () => [
      TemplateVarsHighlight.configure({ validKeywords }),
      ...(extraExtensions ?? []),
    ],
    [validKeywords, extraExtensions],
  );

  return (
    <FieldWrapper
      id={id}
      label={label}
      hint={hint}
      isInvalid={isInvalid}
      isRequired={isRequired}
      tooltip={tooltip}
      description={description}
      fieldSize={fieldSize}
      labelPosition={labelPosition}
    >
      <TextEditor
        {...textEditorProps}
        isInvalid={isInvalid}
        data-id={dataId}
        extraExtensions={highlightExtensions}
        toolbarExtras={[
          <FieldTextEditorTemplaterMenu
            key="templates-menu"
            templateItems={templateItems}
            isFormatTemplateItems={isFormatTemplateItems}
            data-id={`${dataId}-templater`}
          />,
        ]}
      />
    </FieldWrapper>
  );
}
