import { SlideoutMenu as SlideoutMenuBase } from '@/vendor/untitled-ui/application/slideout-menus/slideout-menu';
import { cx } from '@/utils/cx';
import { ComponentPropsWithRef } from 'react';
import { WithDataId } from '@/types/withDataId';

export type HeaderProps = ComponentPropsWithRef<
  typeof SlideoutMenuBase.Header
> &
  WithDataId;

const Header = ({ children, onClose, className, ...props }: HeaderProps) => {
  return (
    <SlideoutMenuBase.Header
      onClose={() => onClose?.()}
      className={cx(
        'flex w-full items-start gap-4 px-4 pt-4 md:px-6',
        className,
      )}
      {...props}
    >
      {children}
    </SlideoutMenuBase.Header>
  );
};

export type FooterProps = ComponentPropsWithRef<typeof SlideoutMenuBase.Footer>;

const Footer = ({ children, className, ...props }: FooterProps) => {
  return (
    <SlideoutMenuBase.Footer
      className={cx('flex w-full items-start gap-4 px-4 md:px-6', className)}
      {...props}
    >
      {children}
    </SlideoutMenuBase.Footer>
  );
};

export type ContentProps = ComponentPropsWithRef<
  typeof SlideoutMenuBase.Content
>;

const Content = ({ children, ...props }: ContentProps) => {
  return (
    <SlideoutMenuBase.Content {...props}>{children}</SlideoutMenuBase.Content>
  );
};

export type MenuProps = ComponentPropsWithRef<typeof SlideoutMenuBase>;

const Menu = ({ isDismissable = true, children, ...props }: MenuProps) => {
  return (
    <SlideoutMenuBase
      isDismissable={isDismissable}
      {...props}
      className={(state) =>
        cx(
          'z-50',
          typeof props.className === 'function'
            ? props.className(state)
            : props.className,
        )
      }
      dialogClassName={cx('rounded-lg', props.dialogClassName)}
    >
      {children}
    </SlideoutMenuBase>
  );
};
export type TriggerProps = Omit<
  ComponentPropsWithRef<typeof SlideoutMenuBase.Trigger>,
  'onOpenChange'
> & { onClose: () => void } & WithDataId;

const Trigger = ({
  children,
  isOpen,
  onClose,
  'data-id': dataId,
}: TriggerProps) => {
  return (
    <SlideoutMenuBase.Trigger
      isOpen={isOpen}
      onOpenChange={(isOpen) => {
        if (!isOpen) {
          onClose();
        }
      }}
      data-id={`${dataId}-trigger`}
    >
      {children}
    </SlideoutMenuBase.Trigger>
  );
};

const SlideoutMenu = Menu as typeof Menu & {
  Trigger: typeof Trigger;
  Content: typeof Content;
  Header: typeof Header;
  Footer: typeof Footer;
};

SlideoutMenu.Trigger = Trigger;
SlideoutMenu.Content = Content;
SlideoutMenu.Header = Header;
SlideoutMenu.Footer = Footer;

export { SlideoutMenu };
