import type { ReactNode } from 'react';
import type { SwitchProps as AriaSwitchProps } from 'react-aria-components';
import { Switch as AriaSwitch } from 'react-aria-components';
import { cx } from '@/utils/cx';

interface ToggleBaseProps {
  className?: string;
  isHovered?: boolean;
  isFocusVisible?: boolean;
  isSelected?: boolean;
  isDisabled?: boolean;
}

export const ToggleBase = ({
  className,
  isHovered,
  isDisabled,
  isFocusVisible,
  isSelected,
}: ToggleBaseProps) => {
  return (
    <div
      className={cx(
        'h-5 w-9 cursor-pointer rounded-full bg-tertiary p-0.5 outline-focus-ring transition duration-150 ease-linear',
        isSelected && 'bg-brand-solid',
        isSelected && isHovered && 'bg-brand-solid_hover',
        isDisabled && 'cursor-not-allowed bg-disabled',
        isFocusVisible && 'outline-2 outline-offset-2',
        className,
      )}
    >
      <div
        style={{
          transition:
            'transform 0.15s ease-in-out, translate 0.15s ease-in-out, border-color 0.1s linear, background-color 0.1s linear',
        }}
        className={cx(
          'size-4 rounded-full bg-fg-white shadow-sm',
          isSelected && 'translate-x-4',
          isDisabled && 'bg-toggle-button-fg_disabled',
        )}
      />
    </div>
  );
};

export interface ToggleProps extends AriaSwitchProps {
  label?: string;
  hint?: ReactNode;
}

export const Toggle = ({
  label,
  hint,
  className,
  ...ariaSwitchProps
}: ToggleProps) => {
  return (
    <AriaSwitch
      {...ariaSwitchProps}
      className={(renderProps) =>
        cx(
          'flex w-max items-start gap-2',
          renderProps.isDisabled && 'cursor-not-allowed',
          typeof className === 'function' ? className(renderProps) : className,
        )
      }
    >
      {({ isSelected, isDisabled, isFocusVisible, isHovered }) => (
        <>
          <ToggleBase
            isHovered={isHovered}
            isDisabled={isDisabled}
            isFocusVisible={isFocusVisible}
            isSelected={isSelected}
          />

          {(label || hint) && (
            <div className="flex flex-col">
              {label && (
                <p
                  className={cx(
                    'text-sm font-medium text-secondary select-none',
                    !isDisabled && 'cursor-pointer',
                  )}
                >
                  {label}
                </p>
              )}
              {hint && (
                <span
                  className="text-sm text-tertiary"
                  onClick={(event) => event.stopPropagation()}
                >
                  {hint}
                </span>
              )}
            </div>
          )}
        </>
      )}
    </AriaSwitch>
  );
};
