import { useEffect, useMemo, useState } from 'react';

import { isColumnSelected } from '../_utils';

import type { ColDef, TableRow } from '../_types';

export function useColumns<TData extends TableRow>(
  columnDefs: ColDef<TData>[],
  columnsSelectorEnabled: boolean,
  columnOrder?: Record<string | number, number>,
  columnsSelection?: Record<string, boolean>,
) {
  const [columns, setColumns] = useState<ColDef<TData>[]>(columnDefs);

  useEffect(() => {
    setColumns((prev) => {
      if (prev.length !== columnDefs.length) {
        return columnDefs;
      }

      const changed = columnDefs.some(
        (col, i) =>
          col.id !== prev[i].id || col.isSelected !== prev[i].isSelected,
      );

      return changed ? columnDefs : prev;
    });
  }, [columnDefs]);

  const visibleColumns = useMemo(() => {
    const cols = columnsSelectorEnabled
      ? columns.filter((c) => isColumnSelected(c, columnsSelection))
      : columns;

    const left = cols.filter((c) => c.pinned === 'left');
    const right = cols.filter((c) => c.pinned === 'right');

    let center = cols.filter((c) => !c.pinned);

    // Apply column ordering to non-pinned columns
    if (columnOrder && Object.keys(columnOrder).length > 0) {
      const maxExplicit = Math.max(...Object.values(columnOrder), -1);

      center = [...center]
        .map((col, i) => ({
          col,
          sortKey:
            col.id != null && col.id in columnOrder
              ? columnOrder[col.id]
              : maxExplicit + 1 + i,
        }))
        .sort((a, b) => a.sortKey - b.sortKey)
        .map((item) => item.col);
    }

    if (left.length === 0 && right.length === 0) {
      return center;
    }

    return [...left, ...center, ...right];
  }, [columns, columnsSelectorEnabled, columnOrder, columnsSelection]);

  return { columns, setColumns, visibleColumns };
}
