import { WithDataId } from '@/types/withDataId';
import { cx } from '@/utils/cx';
import { ChevronDown } from '@untitledui/icons/ChevronDown';

export interface AccordionProps
  extends
    React.PropsWithChildren,
    Omit<React.HTMLAttributes<HTMLDetailsElement>, 'onChange'>,
    WithDataId {
  className?: string;
  defaultExpanded?: boolean;
  expanded?: boolean;
  disabled?: boolean;
  name?: string;
  onChange?: (
    event: React.SyntheticEvent<HTMLDetailsElement, Event>,
    expanded: boolean,
  ) => void;
}

export function Accordion({
  children,
  className,
  defaultExpanded = false,
  expanded,
  disabled = false,
  name,
  onChange,
  ...otherProps
}: AccordionProps) {
  return (
    <details
      {...otherProps}
      className={cx(
        'appearance-none border-y border-secondary last:not-first:border-t-0',
        disabled && 'pointer-events-none',
        className,
      )}
      name={name}
      open={expanded ?? defaultExpanded}
      data-accordion-controlled={expanded !== undefined}
      onToggle={(e) => {
        if (typeof onChange === 'function') {
          onChange(e, e.currentTarget.open);
        }
      }}
    >
      {children}
    </details>
  );
}

Accordion.Summary = AccordionSummary;
Accordion.Details = AccordionDetails;

export interface AccordionSummaryProps
  extends
    React.PropsWithChildren,
    React.HTMLAttributes<HTMLElement>,
    WithDataId {
  /** Additional CSS classes to apply to the summary element. */
  className?: string;
  /** Icon to display for expanding/collapsing the accordion. */
  expandIcon?: React.ReactNode;
}

export function AccordionSummary({
  children,
  className,
  expandIcon,
  ...otherProps
}: AccordionSummaryProps) {
  return (
    <summary
      {...otherProps}
      className={cx(
        'py-4 group relative flex w-full cursor-pointer items-center outline-focus-ring transition duration-100 ease-linear select-none focus-visible:z-10 focus-visible:outline-2 focus-visible:outline-offset-2',
        className,
      )}
      onClick={(e) => {
        const target = e.target as HTMLElement;
        const details = target.closest('details');
        if (details?.getAttribute('data-accordion-controlled') === 'true') {
          e.preventDefault();
        }
      }}
    >
      <span className="flex text-start flex-1 transition-inherit-all text-sm text-tertiary group-hover:text-secondary_hover truncate">
        {children}
      </span>
      <span className="ml-3 shrink-0 in-open:-scale-y-100 text-fg-tertiary">
        {expandIcon ?? (
          <ChevronDown
            width={12}
            height={12}
          />
        )}
      </span>
    </summary>
  );
}

export interface AccordionDetailsProps
  extends React.PropsWithChildren, React.HTMLAttributes<HTMLElement> {
  /** Additional CSS classes to apply to the details element. */
  className?: string;
}

export function AccordionDetails({
  children,
  className,
  ...otherProps
}: AccordionDetailsProps) {
  return (
    <dd
      {...otherProps}
      className={cx('pb-4 text-sm', className)}
    >
      {children}
    </dd>
  );
}
